--
-- Name: aggregate_errors_hourly(timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aggregate_errors_hourly(p_start_time timestamp with time zone DEFAULT (now() - '01:00:00'::interval), p_end_time timestamp with time zone DEFAULT now()) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_inserted INTEGER := 0;
BEGIN
    INSERT INTO error_analytics_hourly (
        hour_start,
        tenant_id,
        category,
        severity,
        error_count,
        unique_errors,
        affected_users,
        top_error_codes
    )
    SELECT
        date_trunc('hour', created_at) AS hour_start,
        tenant_id,
        category,
        severity,
        COUNT(*) AS error_count,
        COUNT(DISTINCT code) AS unique_errors,
        COUNT(DISTINCT user_id) AS affected_users,
        (SELECT ARRAY_AGG(code ORDER BY cnt DESC)
         FROM (
             SELECT code, COUNT(*) as cnt
             FROM error_logs el2
             WHERE el2.tenant_id IS NOT DISTINCT FROM el.tenant_id
               AND el2.category = el.category
               AND el2.severity = el.severity
               AND date_trunc('hour', el2.created_at) = date_trunc('hour', el.created_at)
             GROUP BY code
             ORDER BY cnt DESC
             LIMIT 5
         ) top_codes
        ) AS top_error_codes
    FROM error_logs el
    WHERE created_at >= p_start_time
      AND created_at < p_end_time
    GROUP BY
        date_trunc('hour', created_at),
        tenant_id,
        category,
        severity
    ON CONFLICT (hour_start, tenant_id, category, severity)
    DO UPDATE SET
        error_count = EXCLUDED.error_count,
        unique_errors = EXCLUDED.unique_errors,
        affected_users = EXCLUDED.affected_users,
        top_error_codes = EXCLUDED.top_error_codes;

    GET DIAGNOSTICS v_inserted = ROW_COUNT;
    RETURN v_inserted;
END;
$$;


