--
-- Name: calculate_composite_score(smallint, smallint, smallint, smallint, smallint, numeric[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_composite_score(p_knowledge smallint, p_skill smallint, p_ability smallint, p_behavior smallint, p_attitude smallint, p_weights numeric[] DEFAULT ARRAY[0.20, 0.30, 0.25, 0.15, 0.10]) RETURNS numeric
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_score NUMERIC;
BEGIN
    -- Calculate weighted average
    v_score := (
        COALESCE(p_knowledge, 0) * p_weights[1] +
        COALESCE(p_skill, 0) * p_weights[2] +
        COALESCE(p_ability, 0) * p_weights[3] +
        COALESCE(p_behavior, 0) * p_weights[4] +
        COALESCE(p_attitude, 0) * p_weights[5]
    );

    RETURN ROUND(v_score, 2);
END;
$$;


--
-- Name: calculate_confidence_score(integer, numeric, integer, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_confidence_score(p_sources_count integer, p_retrieval_score numeric, p_response_length integer, p_has_citations boolean) RETURNS numeric
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
  v_score DECIMAL;
BEGIN
  -- Base score from retrieval
  v_score := COALESCE(p_retrieval_score, 0.5) * 0.4;

  -- Sources boost (more sources = higher confidence)
  v_score := v_score + LEAST(p_sources_count * 0.1, 0.3);

  -- Citation boost
  IF p_has_citations THEN
    v_score := v_score + 0.15;
  END IF;

  -- Response length penalty (too short might be incomplete)
  IF p_response_length < 50 THEN
    v_score := v_score - 0.1;
  END IF;

  RETURN GREATEST(LEAST(v_score, 1.0), 0.0);
END;
$$;


--
-- Name: calculate_expected_retirement_date(date, date, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_expected_retirement_date(p_birth_date date, p_hire_date date, p_tenant_id uuid) RETURNS date
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_old_age_years   INTEGER;
    v_early_years     NUMERIC;
    v_old_age_date    DATE;
    v_early_date      DATE;
BEGIN
    IF p_birth_date IS NULL THEN
        RETURN NULL;
    END IF;

    SELECT old_age_retirement_years,
           early_retirement_contribution_years
      INTO v_old_age_years, v_early_years
      FROM tenant_retirement_rules
     WHERE tenant_id = p_tenant_id
       AND effective_from <= CURRENT_DATE
     ORDER BY effective_from DESC
     LIMIT 1;

    v_old_age_years := COALESCE(v_old_age_years, 67);
    v_early_years   := COALESCE(v_early_years, 42.83);

    v_old_age_date := p_birth_date + (v_old_age_years || ' years')::INTERVAL;

    IF p_hire_date IS NOT NULL THEN
        v_early_date := p_hire_date + (v_early_years || ' years')::INTERVAL;
        RETURN LEAST(v_old_age_date, v_early_date);
    END IF;

    RETURN v_old_age_date;
END;
$$;


