--
-- Name: calculate_goal_progress_from_milestones(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_goal_progress_from_milestones(p_goal_id uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_progress NUMERIC;
BEGIN
    SELECT
        CASE
            WHEN COUNT(*) > 0 THEN
                (COUNT(*) FILTER (WHERE status = 'completed') * 100.0 / COUNT(*))
            ELSE 0
        END
    INTO v_progress
    FROM goal_milestones
    WHERE goal_id = p_goal_id AND status != 'cancelled';

    RETURN COALESCE(v_progress, 0);
END;
$$;


--
-- Name: calculate_okr_progress(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_okr_progress(p_okr_id uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_progress NUMERIC;
BEGIN
    SELECT
        CASE
            WHEN SUM(weight) > 0 THEN
                SUM(progress_percent * weight) / SUM(weight)
            ELSE 0
        END
    INTO v_progress
    FROM key_results
    WHERE okr_id = p_okr_id AND status != 'cancelled';

    RETURN COALESCE(v_progress, 0);
END;
$$;


--
-- Name: calculate_role_requirement_composite(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_role_requirement_composite() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Only calculate if not explicitly set
    IF NEW.min_composite_score IS NULL THEN
        -- Calculate from individual dimensions if provided
        IF NEW.required_knowledge_level IS NOT NULL OR
           NEW.required_skill_level IS NOT NULL OR
           NEW.required_ability_level IS NOT NULL OR
           NEW.required_behavior_level IS NOT NULL OR
           NEW.required_attitude_level IS NOT NULL THEN

            NEW.min_composite_score := calculate_composite_score(
                COALESCE(NEW.required_knowledge_level, 0)::SMALLINT,
                COALESCE(NEW.required_skill_level, 0)::SMALLINT,
                COALESCE(NEW.required_ability_level, 0)::SMALLINT,
                COALESCE(NEW.required_behavior_level, 0)::SMALLINT,
                COALESCE(NEW.required_attitude_level, 0)::SMALLINT
            );
        END IF;
    END IF;

    NEW.updated_at := NOW();
    RETURN NEW;
END;
$$;


