CREATE FUNCTION public.calculate_skill_match_score(p_employee_id uuid, p_position_id uuid, p_tenant_id uuid) RETURNS TABLE(overall_score numeric, coverage_score numeric, proficiency_score numeric, matched_skills jsonb, gap_skills jsonb)
    LANGUAGE plpgsql
