--
-- Name: copy_jobs_to_tenant_unit(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.copy_jobs_to_tenant_unit(p_tenant_org_unit_id uuid, p_source_unit_template_id uuid DEFAULT NULL::uuid) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_tenant_id UUID;
    v_job_count INT := 0;
    r_job RECORD;
    v_new_job_id UUID;
BEGIN
    -- Get tenant ID
    SELECT toc.tenant_id INTO v_tenant_id
    FROM tenant_org_units tou
    JOIN tenant_org_charts toc ON tou.chart_id = toc.id
    WHERE tou.id = p_tenant_org_unit_id;

    IF v_tenant_id IS NULL THEN
        RAISE EXCEPTION 'Tenant org unit not found: %', p_tenant_org_unit_id;
    END IF;

    -- Determine source template unit
    IF p_source_unit_template_id IS NULL THEN
        SELECT source_unit_id INTO p_source_unit_template_id
        FROM tenant_org_units WHERE id = p_tenant_org_unit_id;
    END IF;

    IF p_source_unit_template_id IS NULL THEN
        RAISE NOTICE 'No source template unit for: %', p_tenant_org_unit_id;
        RETURN 0;
    END IF;

    -- Copy each job template
    FOR r_job IN
        SELECT * FROM job_templates
        WHERE org_unit_template_id = p_source_unit_template_id
        AND is_active = TRUE
    LOOP
        -- Insert tenant job
        INSERT INTO tenant_jobs (
            tenant_id, source_template_id, tenant_org_unit_id,
            job_code, title_it, title_en, description, summary,
            org_level, is_management, employment_type,
            esco_occupation_uri, esco_occupation_code,
            salary_band_code, salary_min, salary_max, currency
        )
        VALUES (
            v_tenant_id, r_job.id, p_tenant_org_unit_id,
            r_job.job_code, r_job.title_it, r_job.title_en, r_job.description, r_job.summary,
            r_job.org_level, r_job.is_management, r_job.employment_type,
            r_job.esco_occupation_uri, r_job.esco_occupation_code,
            r_job.salary_band_code, r_job.salary_min, r_job.salary_max, r_job.currency
        )
        RETURNING id INTO v_new_job_id;

        -- Copy tasks
        INSERT INTO tenant_job_tasks (
            tenant_job_id, source_task_id, task_order,
            description_it, description_en, frequency, importance, time_allocation_percent
        )
        SELECT
            v_new_job_id, id, task_order,
            description_it, description_en, frequency, importance, time_allocation_percent
        FROM job_tasks
        WHERE job_template_id = r_job.id;

        -- Copy skills
        INSERT INTO tenant_job_skills (
            tenant_job_id, source_skill_id, skill_name_it, skill_name_en,
            esco_skill_uri, esco_skill_code, required_level, is_required, importance, skill_category
        )
        SELECT
            v_new_job_id, id, skill_name_it, skill_name_en,
            esco_skill_uri, esco_skill_code, required_level, is_required, importance, skill_category
        FROM job_skills
        WHERE job_template_id = r_job.id;

        -- Copy KPIs
        INSERT INTO tenant_job_kpis (
            tenant_job_id, source_kpi_id, kpi_code, name_it, name_en, description,
            measurement_type, unit, target_value, min_acceptable, stretch_target,
            kpi_category, frequency, weight
        )
        SELECT
            v_new_job_id, id, kpi_code, name_it, name_en, description,
            measurement_type, unit, target_value, min_acceptable, stretch_target,
            kpi_category, frequency, weight
        FROM job_kpis
        WHERE job_template_id = r_job.id;

        v_job_count := v_job_count + 1;
    END LOOP;

    RETURN v_job_count;
END;
$$;


