--
-- Name: copy_org_chart_to_tenant(uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.copy_org_chart_to_tenant(p_template_id uuid, p_tenant_id uuid, p_chart_name character varying DEFAULT NULL::character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_chart_id UUID;
    v_unit_mapping JSONB := '{}';
    r_unit RECORD;
    v_new_unit_id UUID;
    v_new_parent_id UUID;
    v_template_name VARCHAR;
BEGIN
    -- Get template name
    SELECT name INTO v_template_name
    FROM org_chart_templates
    WHERE id = p_template_id;

    IF v_template_name IS NULL THEN
        RAISE EXCEPTION 'Template not found: %', p_template_id;
    END IF;

    -- Create tenant chart
    INSERT INTO tenant_org_charts (tenant_id, source_template_id, name, status)
    VALUES (
        p_tenant_id,
        p_template_id,
        COALESCE(p_chart_name, v_template_name),
        'draft'
    )
    RETURNING id INTO v_chart_id;

    -- Copy units in hierarchical order (parents first)
    FOR r_unit IN
        SELECT * FROM org_unit_templates
        WHERE template_id = p_template_id
        ORDER BY depth, sort_order
    LOOP
        -- Get mapped parent ID
        v_new_parent_id := NULL;
        IF r_unit.parent_id IS NOT NULL THEN
            v_new_parent_id := (v_unit_mapping->>(r_unit.parent_id::text))::UUID;
        END IF;

        -- Insert unit
        INSERT INTO tenant_org_units (
            chart_id, source_unit_id, parent_id, depth, sort_order,
            code, cost_center, name_it, name_en, short_name,
            area_code, level, is_line, is_management, headcount_budget
        )
        VALUES (
            v_chart_id, r_unit.id, v_new_parent_id, r_unit.depth, r_unit.sort_order,
            r_unit.code, r_unit.cost_center, r_unit.name_it, r_unit.name_en, r_unit.short_name,
            r_unit.area_code, r_unit.level, r_unit.is_line, r_unit.is_management,
            COALESCE(r_unit.headcount_max, r_unit.headcount_min)
        )
        RETURNING id INTO v_new_unit_id;

        -- Store mapping
        v_unit_mapping := v_unit_mapping || jsonb_build_object(r_unit.id::text, v_new_unit_id);
    END LOOP;

    -- Update paths after all units created
    PERFORM update_tenant_org_paths(v_chart_id);

    RETURN v_chart_id;
END;
$$;


