--
-- Name: detect_error_spike(numeric, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.detect_error_spike(p_threshold_multiplier numeric DEFAULT 2.0, p_min_errors integer DEFAULT 10) RETURNS TABLE(category character varying, severity character varying, tenant_id uuid, current_hour_count bigint, avg_hourly_count numeric, spike_ratio numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH current_hour AS (
        SELECT
            el.category,
            el.severity,
            el.tenant_id,
            COUNT(*) AS error_count
        FROM error_logs el
        WHERE el.created_at >= date_trunc('hour', NOW())
        GROUP BY el.category, el.severity, el.tenant_id
        HAVING COUNT(*) >= p_min_errors
    ),
    historical_avg AS (
        SELECT
            eah.category,
            eah.severity,
            eah.tenant_id,
            AVG(eah.error_count) AS avg_count
        FROM error_analytics_hourly eah
        WHERE eah.hour_start >= NOW() - INTERVAL '7 days'
          AND eah.hour_start < date_trunc('hour', NOW())
        GROUP BY eah.category, eah.severity, eah.tenant_id
    )
    SELECT
        c.category,
        c.severity,
        c.tenant_id,
        c.error_count AS current_hour_count,
        COALESCE(h.avg_count, 1) AS avg_hourly_count,
        (c.error_count::DECIMAL / GREATEST(COALESCE(h.avg_count, 1), 1)) AS spike_ratio
    FROM current_hour c
    LEFT JOIN historical_avg h
        ON c.category = h.category
        AND c.severity = h.severity
        AND c.tenant_id IS NOT DISTINCT FROM h.tenant_id
    WHERE (c.error_count::DECIMAL / GREATEST(COALESCE(h.avg_count, 1), 1)) >= p_threshold_multiplier;
END;
$$;


--
-- Name: FUNCTION detect_error_spike(p_threshold_multiplier numeric, p_min_errors integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.detect_error_spike(p_threshold_multiplier numeric, p_min_errors integer) IS 'Detects unusual error spikes compared to historical average';


--
-- Name: employee_has_permission(uuid, character varying, public.permission_scope); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.employee_has_permission(p_employee_id uuid, p_permission_code character varying, p_required_scope public.permission_scope DEFAULT 'own'::public.permission_scope) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_has_permission BOOLEAN := false;
    v_scope permission_scope;
    v_scope_order INTEGER;
    v_required_order INTEGER;
BEGIN
    -- Scope hierarchy: own < team < department < tenant < platform
    v_required_order := CASE p_required_scope
        WHEN 'own' THEN 1
        WHEN 'team' THEN 2
        WHEN 'department' THEN 3
        WHEN 'tenant' THEN 4
        WHEN 'platform' THEN 5
    END;

    -- Check if employee has the permission with sufficient scope
    SELECT scope INTO v_scope
    FROM get_employee_permissions(p_employee_id)
    WHERE permission_code = p_permission_code
    LIMIT 1;

    IF v_scope IS NOT NULL THEN
        v_scope_order := CASE v_scope
            WHEN 'own' THEN 1
            WHEN 'team' THEN 2
            WHEN 'department' THEN 3
            WHEN 'tenant' THEN 4
            WHEN 'platform' THEN 5
        END;

        v_has_permission := v_scope_order >= v_required_order;
    END IF;

    RETURN v_has_permission;
END;
$$;


