END;
$$;


--
-- Name: fn_auto_assign_review_participants(uuid, uuid, uuid[], character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_auto_assign_review_participants(p_tenant_id uuid, p_cycle_id uuid, p_org_unit_ids uuid[] DEFAULT NULL::uuid[], p_employee_status character varying DEFAULT 'active'::character varying) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_count INTEGER := 0;
BEGIN
  INSERT INTO review_cycle_participants (
    tenant_id, review_cycle_id, employee_id, manager_id, status
  )
  SELECT
    p_tenant_id,
    p_cycle_id,
    e.id,
    e.manager_id,
    'draft'
  FROM employees e
  WHERE e.tenant_id = p_tenant_id
    AND e.status = p_employee_status
    AND (p_org_unit_ids IS NULL OR e.org_unit_id = ANY(p_org_unit_ids))
    AND NOT EXISTS (
      SELECT 1 FROM review_cycle_participants rcp
      WHERE rcp.review_cycle_id = p_cycle_id AND rcp.employee_id = e.id
    )
  ON CONFLICT (review_cycle_id, employee_id) DO NOTHING;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


--
-- Name: fn_auto_link_custom_skills(uuid, double precision, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_auto_link_custom_skills(p_tenant_id uuid DEFAULT NULL::uuid, p_threshold double precision DEFAULT 0.40, p_dry_run boolean DEFAULT true) RETURNS TABLE(employee_skill_id uuid, custom_name character varying, matched_esco_label character varying, matched_esco_uri character varying, similarity double precision, action character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_linked INT := 0;
BEGIN
    -- For each distinct custom_skill_name, find the best ESCO match
    -- by computing embedding similarity between the custom name and
    -- all ESCO skill labels+descriptions
    RETURN QUERY
    WITH unlinked AS (
        SELECT DISTINCT ON (es.custom_skill_name)
            es.id AS es_id,
            es.custom_skill_name,
            es.tenant_id
        FROM employee_skills es
        WHERE es.esco_skill_id IS NULL
          AND es.custom_skill_name IS NOT NULL
          AND es.custom_skill_name != ''
          AND (p_tenant_id IS NULL OR es.tenant_id = p_tenant_id)
        ORDER BY es.custom_skill_name, es.id
    ),
    matches AS (
        SELECT
            u.es_id,
            u.custom_skill_name,
            best.id AS esco_id,
            best.preferred_label_en,
            best.uri,
            best.sim
        FROM unlinked u
        CROSS JOIN LATERAL (
            SELECT s.id, s.preferred_label_en, s.uri,
                   (1 - (s.embedding_en <=> (
                       -- Find best proxy embedding: use the ESCO skill whose
                       -- label is most similar textually to the custom name
                       SELECT s2.embedding_en
                       FROM esco_skills s2
                       WHERE s2.embedding_en IS NOT NULL
                       ORDER BY s2.preferred_label_en <-> u.custom_skill_name
                       LIMIT 1
                   )))::FLOAT AS sim
            FROM esco_skills s
            WHERE s.embedding_en IS NOT NULL
            ORDER BY s.embedding_en <=> (
                SELECT s2.embedding_en
                FROM esco_skills s2
                WHERE s2.embedding_en IS NOT NULL
                ORDER BY s2.preferred_label_en <-> u.custom_skill_name
                LIMIT 1
            )
            LIMIT 1
        ) best
        WHERE best.sim >= p_threshold
    )
    SELECT
        m.es_id,
        m.custom_name,
        m.preferred_label_en,
        m.uri,
        m.sim,
        CASE WHEN p_dry_run THEN 'WOULD_LINK' ELSE 'LINKED' END::VARCHAR(20)
    FROM (
        SELECT es_id, custom_skill_name AS custom_name,
               preferred_label_en, uri, sim
        FROM matches
    ) m;

    -- If not dry run, actually update the links
    IF NOT p_dry_run THEN
        WITH unlinked AS (
            SELECT DISTINCT ON (es.custom_skill_name)
                es.custom_skill_name, es.tenant_id
            FROM employee_skills es
            WHERE es.esco_skill_id IS NULL
              AND es.custom_skill_name IS NOT NULL
              AND (p_tenant_id IS NULL OR es.tenant_id = p_tenant_id)
            ORDER BY es.custom_skill_name
        ),
        best_matches AS (
            SELECT
                u.custom_skill_name,
                (SELECT s.id
                 FROM esco_skills s
                 WHERE s.embedding_en IS NOT NULL
                 ORDER BY s.embedding_en <=> (
                     SELECT s2.embedding_en FROM esco_skills s2
                     WHERE s2.embedding_en IS NOT NULL
                     ORDER BY s2.preferred_label_en <-> u.custom_skill_name LIMIT 1
                 ) LIMIT 1
                ) AS esco_id
            FROM unlinked u
        )
        UPDATE employee_skills es
        SET esco_skill_id = bm.esco_id,
            source = COALESCE(es.source, '') || '+auto_linked',
            confidence_score = (
                SELECT (1 - (s.embedding_en <=> (
                    SELECT s2.embedding_en FROM esco_skills s2
                    WHERE s2.embedding_en IS NOT NULL
                    ORDER BY s2.preferred_label_en <-> es.custom_skill_name LIMIT 1
                )))::FLOAT
                FROM esco_skills s WHERE s.id = bm.esco_id
            )
        FROM best_matches bm
        WHERE es.custom_skill_name = bm.custom_skill_name
          AND es.esco_skill_id IS NULL
          AND bm.esco_id IS NOT NULL;

        GET DIAGNOSTICS v_linked = ROW_COUNT;

        -- Also create skill_aliases for the custom names
        INSERT INTO skill_aliases (esco_skill_id, alias_text, alias_type, language_code, source, confidence_score, is_verified, created_at)
        SELECT DISTINCT bm.esco_id, bm.custom_skill_name, 'market_term', 'en',
               'auto_linker', 0.0, FALSE, NOW()
        FROM best_matches bm
        WHERE bm.esco_id IS NOT NULL
        ON CONFLICT DO NOTHING;
    END IF;
END;
$$;


--
-- Name: fn_auto_populate_goal_ratings(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_auto_populate_goal_ratings(p_tenant_id uuid, p_review_id uuid) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_employee_id UUID;
  v_period_start DATE;
  v_period_end DATE;
  v_count INTEGER := 0;
BEGIN
  -- Get review details
  SELECT employee_id, review_period_start, review_period_end
  INTO v_employee_id, v_period_start, v_period_end
  FROM performance_reviews
  WHERE id = p_review_id AND tenant_id = p_tenant_id;

  IF v_employee_id IS NULL THEN
    RAISE EXCEPTION 'Performance review not found';
  END IF;

  -- Insert goal ratings for all period goals
  INSERT INTO goal_review_ratings (tenant_id, performance_review_id, goal_id, employee_id, weight)
  SELECT
    p_tenant_id,
    p_review_id,
    g.goal_id,
    v_employee_id,
    g.weight
  FROM fn_get_review_period_goals(p_tenant_id, v_employee_id, v_period_start, v_period_end) g
  WHERE NOT EXISTS (
    SELECT 1 FROM goal_review_ratings grr
    WHERE grr.performance_review_id = p_review_id AND grr.goal_id = g.goal_id
  )
  ON CONFLICT (performance_review_id, goal_id) DO NOTHING;

  GET DIAGNOSTICS v_count = ROW_COUNT;

  -- Update performance review with goal count
  UPDATE performance_reviews
  SET goals_auto_populated = true,
      goals_count = (SELECT COUNT(*) FROM goal_review_ratings WHERE performance_review_id = p_review_id),
      updated_at = NOW()
  WHERE id = p_review_id;

  RETURN v_count;
END;
$$;


--
-- Name: FUNCTION fn_auto_populate_goal_ratings(p_tenant_id uuid, p_review_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.fn_auto_populate_goal_ratings(p_tenant_id uuid, p_review_id uuid) IS 'Auto-populates goal ratings for a performance review from the employee goals table';


--
-- Name: fn_calculate_cascaded_progress(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_calculate_cascaded_progress(p_goal_id uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_child_progress NUMERIC;
BEGIN
  -- Calculate weighted average of child goals
  SELECT
    CASE
      WHEN SUM(weight) > 0 THEN
        SUM(progress_percent * weight) / SUM(weight)
      ELSE 0
    END
  INTO v_child_progress
  FROM goals
  WHERE parent_goal_id = p_goal_id;

  RETURN COALESCE(v_child_progress, 0);
END;
$$;


--
-- Name: FUNCTION fn_calculate_cascaded_progress(p_goal_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.fn_calculate_cascaded_progress(p_goal_id uuid) IS 'Calculates weighted progress from child goals';


--
-- Name: fn_calculate_hipo_score(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_calculate_hipo_score(p_tenant_id uuid, p_employee_id uuid) RETURNS TABLE(is_high_potential boolean, hipo_score numeric, hipo_justification text, potential_factors jsonb)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_perf_trend NUMERIC;
  v_skill_growth INTEGER;
  v_leadership_feedback NUMERIC;
  v_stretch_success NUMERIC;
  v_tenure_years NUMERIC;
  v_age_factor NUMERIC;
  v_hipo_score NUMERIC := 0;
  v_factors JSONB := '[]'::JSONB;
  v_justification TEXT := '';
  v_strengths TEXT[] := ARRAY[]::TEXT[];
BEGIN
  -- Performance trend (improvement over time)
  SELECT COALESCE(
    (SELECT AVG(COALESCE(calibrated_rating, overall_rating))
     FROM performance_reviews
     WHERE tenant_id = p_tenant_id AND employee_id = p_employee_id
       AND created_at >= (NOW() - INTERVAL '1 year')) -
    (SELECT AVG(COALESCE(calibrated_rating, overall_rating))
     FROM performance_reviews
     WHERE tenant_id = p_tenant_id AND employee_id = p_employee_id
       AND created_at < (NOW() - INTERVAL '1 year')
       AND created_at >= (NOW() - INTERVAL '2 years')),
    0
  ) INTO v_perf_trend;

  IF v_perf_trend > 0.3 THEN
    v_hipo_score := v_hipo_score + 1.0;
    v_strengths := array_append(v_strengths, 'Strong performance improvement trend');
    v_factors := v_factors || jsonb_build_object(
      'factor', 'performance_trend',
      'value', ROUND(v_perf_trend, 2),
      'contribution', 1.0,
      'interpretation', 'Consistently improving performance'
    );
  ELSIF v_perf_trend > 0 THEN
    v_hipo_score := v_hipo_score + 0.5;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'performance_trend',
      'value', ROUND(v_perf_trend, 2),
      'contribution', 0.5,
      'interpretation', 'Positive performance trajectory'
    );
  END IF;

  -- Skill acquisition rate
  SELECT COUNT(*)
  INTO v_skill_growth
  FROM employee_skill_profiles esp
  WHERE esp.tenant_id = p_tenant_id
    AND esp.employee_id = p_employee_id
    AND esp.created_at >= (NOW() - INTERVAL '1 year');

  IF v_skill_growth >= 5 THEN
    v_hipo_score := v_hipo_score + 1.0;
    v_strengths := array_append(v_strengths, 'Rapid skill acquisition');
    v_factors := v_factors || jsonb_build_object(
      'factor', 'skill_growth',
      'value', v_skill_growth,
      'contribution', 1.0,
      'interpretation', 'Exceptional learning agility'
    );
  ELSIF v_skill_growth >= 3 THEN
    v_hipo_score := v_hipo_score + 0.5;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'skill_growth',
      'value', v_skill_growth,
      'contribution', 0.5,
      'interpretation', 'Active skill development'
    );
  END IF;

  -- Leadership-related feedback
  SELECT COALESCE(AVG(
    CASE feedback_type WHEN 'praise' THEN 1 WHEN 'suggestion' THEN 0.5 ELSE 0 END
  ), 0)
  INTO v_leadership_feedback
  FROM continuous_feedback
  WHERE tenant_id = p_tenant_id
    AND to_employee_id = p_employee_id
    AND category IN ('leadership', 'collaboration')
    AND created_at >= (NOW() - INTERVAL '1 year');

  IF v_leadership_feedback > 0.7 THEN
    v_hipo_score := v_hipo_score + 1.0;
    v_strengths := array_append(v_strengths, 'Strong leadership recognition');
    v_factors := v_factors || jsonb_build_object(
      'factor', 'leadership_feedback',
      'value', ROUND(v_leadership_feedback, 2),
      'contribution', 1.0,
      'interpretation', 'Recognized for leadership qualities'
    );
  ELSIF v_leadership_feedback > 0.4 THEN
    v_hipo_score := v_hipo_score + 0.5;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'leadership_feedback',
      'value', ROUND(v_leadership_feedback, 2),
      'contribution', 0.5,
      'interpretation', 'Emerging leadership potential'
    );
  END IF;

  -- Tenure factor (optimal: 2-5 years)
  SELECT EXTRACT(YEAR FROM AGE(NOW(), hire_date))
  INTO v_tenure_years
  FROM employees
  WHERE id = p_employee_id;

  IF v_tenure_years BETWEEN 2 AND 5 THEN
    v_hipo_score := v_hipo_score + 0.5;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'tenure',
      'value', ROUND(v_tenure_years, 1),
      'contribution', 0.5,
      'interpretation', 'Optimal tenure for advancement'
    );
  ELSIF v_tenure_years BETWEEN 1 AND 7 THEN
    v_hipo_score := v_hipo_score + 0.25;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'tenure',
      'value', ROUND(v_tenure_years, 1),
      'contribution', 0.25,
      'interpretation', 'Good tenure range'
    );
  END IF;

  -- High goal achievement
  SELECT COALESCE(
    AVG(CASE WHEN status = 'completed' THEN 1.0 WHEN status = 'in_progress' THEN 0.5 ELSE 0 END),
    0
  )
  INTO v_stretch_success
  FROM goals
  WHERE tenant_id = p_tenant_id
    AND employee_id = p_employee_id
    AND goal_type = 'stretch'
    AND created_at >= (NOW() - INTERVAL '2 years');

  IF v_stretch_success > 0.7 THEN
    v_hipo_score := v_hipo_score + 1.0;
    v_strengths := array_append(v_strengths, 'Successfully completes stretch goals');
    v_factors := v_factors || jsonb_build_object(
      'factor', 'stretch_goals',
      'value', ROUND(v_stretch_success, 2),
      'contribution', 1.0,
      'interpretation', 'Excels at challenging assignments'
    );
  END IF;

  -- Normalize to 0-5 scale
  hipo_score := LEAST(5.0, v_hipo_score);

  -- Determine HiPo status (threshold: 3.0)
  is_high_potential := (hipo_score >= 3.0);

  -- Generate justification
  IF is_high_potential THEN
    v_justification := 'High Potential designation based on: ' ||
      array_to_string(v_strengths, '; ') ||
      '. HiPo Score: ' || ROUND(hipo_score, 2)::TEXT || '/5.0';
  ELSE
    v_justification := 'Employee shows promise but does not yet meet HiPo threshold (3.0). Current score: ' ||
      ROUND(hipo_score, 2)::TEXT || '/5.0. Focus areas for development are available.';
  END IF;

  hipo_justification := v_justification;
  potential_factors := v_factors;

  RETURN NEXT;
END;
$$;


--
-- Name: fn_calculate_okr_progress(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_calculate_okr_progress(p_okr_id uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_progress NUMERIC;
BEGIN
  -- Calculate weighted average of key result progress
  SELECT
    CASE
      WHEN SUM(weight) > 0 THEN
        ROUND(SUM(progress_percent * weight) / SUM(weight), 2)
      ELSE 0
    END
  INTO v_progress
  FROM key_results
  WHERE okr_id = p_okr_id;

  -- Update the OKR
  UPDATE okrs
  SET overall_progress = COALESCE(v_progress, 0),
      updated_at = NOW()
  WHERE id = p_okr_id;

  RETURN COALESCE(v_progress, 0);
END;
$$;


--
-- Name: FUNCTION fn_calculate_okr_progress(p_okr_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.fn_calculate_okr_progress(p_okr_id uuid) IS 'Calculates and updates OKR progress from key results';


--
-- Name: fn_calculate_path_fit_score(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_calculate_path_fit_score(p_employee_id uuid, p_path_id uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_total_distance NUMERIC := 0;
    v_levels_count INTEGER := 0;
    v_level_record RECORD;
BEGIN
    FOR v_level_record IN
        SELECT id FROM career_path_levels
        WHERE path_id = p_path_id
        ORDER BY level_order
    LOOP
        v_total_distance := v_total_distance + fn_calculate_skill_distance(p_employee_id, v_level_record.id);
        v_levels_count := v_levels_count + 1;
    END LOOP;

    IF v_levels_count > 0 THEN
        -- Convert distance to fit score (inverse relationship)
        -- Max distance of 5, fit = 1 - (avg_distance / 5)
        RETURN GREATEST(0, 1 - (v_total_distance / v_levels_count / 5));
    ELSE
        RETURN 0;
    END IF;
END;
$$;


--
-- Name: FUNCTION fn_calculate_path_fit_score(p_employee_id uuid, p_path_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.fn_calculate_path_fit_score(p_employee_id uuid, p_path_id uuid) IS 'Calculates overall fit score for employee on a career path';


--
-- Name: fn_calculate_risk_score(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_calculate_risk_score(p_tenant_id uuid, p_employee_id uuid) RETURNS TABLE(risk_score integer, risk_level character varying, contributing_factors jsonb, recommended_actions jsonb, prediction_confidence numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_perf_avg NUMERIC;
  v_goal_rate NUMERIC;
  v_feedback_sentiment NUMERIC;
  v_checkin_freq NUMERIC;
  v_dept_avg NUMERIC;
  v_risk_score INTEGER;
  v_factors JSONB := '[]'::JSONB;
  v_actions JSONB := '[]'::JSONB;
  v_confidence NUMERIC := 0.75;
  v_data_points INTEGER := 0;
BEGIN
  -- Get historical performance average (last 3 years)
  SELECT COALESCE(AVG(COALESCE(pr.calibrated_rating, pr.overall_rating)), 3.0)
  INTO v_perf_avg
  FROM performance_reviews pr
  WHERE pr.tenant_id = p_tenant_id
    AND pr.employee_id = p_employee_id
    AND pr.status = 'completed'
    AND pr.review_period >= (NOW() - INTERVAL '3 years');

  IF v_perf_avg IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'perf_history',
      'name', 'Historical Performance',
      'value', ROUND(v_perf_avg, 2),
      'weight', 0.30,
      'impact', CASE WHEN v_perf_avg < 3 THEN 'negative' WHEN v_perf_avg > 4 THEN 'positive' ELSE 'neutral' END
    );
  END IF;

  -- Get goal completion rate
  SELECT COALESCE(
    COUNT(*) FILTER (WHERE status = 'completed')::NUMERIC / NULLIF(COUNT(*), 0) * 100,
    50
  )
  INTO v_goal_rate
  FROM goals
  WHERE tenant_id = p_tenant_id
    AND employee_id = p_employee_id
    AND created_at >= (NOW() - INTERVAL '1 year');

  IF v_goal_rate IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'goal_completion',
      'name', 'Goal Completion Rate',
      'value', ROUND(v_goal_rate, 1),
      'weight', 0.20,
      'impact', CASE WHEN v_goal_rate < 50 THEN 'negative' WHEN v_goal_rate > 80 THEN 'positive' ELSE 'neutral' END
    );
  END IF;

  -- Get feedback sentiment (from continuous feedback)
  SELECT COALESCE(AVG(sentiment_score), 0)
  INTO v_feedback_sentiment
  FROM continuous_feedback
  WHERE tenant_id = p_tenant_id
    AND to_employee_id = p_employee_id
    AND created_at >= (NOW() - INTERVAL '6 months');

  IF v_feedback_sentiment IS NOT NULL THEN
    v_data_points := v_data_points + 1;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'feedback_sentiment',
      'name', 'Feedback Sentiment',
      'value', ROUND(v_feedback_sentiment, 2),
      'weight', 0.15,
      'impact', CASE WHEN v_feedback_sentiment < -0.2 THEN 'negative' WHEN v_feedback_sentiment > 0.3 THEN 'positive' ELSE 'neutral' END
    );
  END IF;

  -- Get check-in frequency (per month, normalized)
  SELECT COALESCE(
    COUNT(*)::NUMERIC / GREATEST(EXTRACT(MONTH FROM AGE(NOW(), MIN(created_at))), 1),
    0
  )
  INTO v_checkin_freq
  FROM check_ins
  WHERE tenant_id = p_tenant_id
    AND employee_id = p_employee_id
    AND created_at >= (NOW() - INTERVAL '6 months');

  IF v_checkin_freq > 0 THEN
    v_data_points := v_data_points + 1;
    v_factors := v_factors || jsonb_build_object(
      'factor', 'checkin_frequency',
      'name', 'Check-in Activity',
      'value', ROUND(v_checkin_freq, 1),
      'weight', 0.10,
      'impact', CASE WHEN v_checkin_freq < 1 THEN 'negative' WHEN v_checkin_freq > 4 THEN 'positive' ELSE 'neutral' END
    );
  END IF;

  -- Get department average for comparison
  SELECT AVG(COALESCE(pr.calibrated_rating, pr.overall_rating))
  INTO v_dept_avg
  FROM performance_reviews pr
  JOIN employees e ON pr.employee_id = e.id
  WHERE pr.tenant_id = p_tenant_id
    AND e.org_unit_id = (SELECT org_unit_id FROM employees WHERE id = p_employee_id)
    AND pr.status = 'completed'
    AND pr.review_period >= (NOW() - INTERVAL '1 year');

  -- Calculate risk score (0-100, higher = more risk)
  v_risk_score := GREATEST(0, LEAST(100,
    -- Base score (inverted from 5-point scale)
    ((5 - COALESCE(v_perf_avg, 3)) / 5 * 40)::INTEGER +
    -- Goal completion (inverted)
    ((100 - COALESCE(v_goal_rate, 50)) / 100 * 25)::INTEGER +
    -- Feedback sentiment (inverted, scaled from -1 to 1)
    ((1 - COALESCE(v_feedback_sentiment, 0)) / 2 * 15)::INTEGER +
    -- Check-in activity (inverted, max 8/month)
    ((8 - LEAST(COALESCE(v_checkin_freq, 0), 8)) / 8 * 10)::INTEGER +
    -- Below department average penalty
    (CASE WHEN COALESCE(v_perf_avg, 3) < COALESCE(v_dept_avg, 3) - 0.5 THEN 10 ELSE 0 END)
  ));

  -- Determine risk level
  risk_level := CASE
    WHEN v_risk_score <= 25 THEN 'low'
    WHEN v_risk_score <= 50 THEN 'medium'
    WHEN v_risk_score <= 75 THEN 'high'
    ELSE 'critical'
  END;

  -- Calculate confidence based on data points
  v_confidence := LEAST(0.95, 0.50 + (v_data_points * 0.10));

  -- Generate recommended actions based on risk level
  SELECT jsonb_agg(jsonb_build_object(
    'action_code', pa.action_code,
    'action_name', pa.action_name,
    'category', pa.action_category,
    'description', pa.description,
    'estimated_impact', pa.estimated_impact,
    'typical_duration', pa.typical_duration,
    'priority', ROW_NUMBER() OVER (ORDER BY
      CASE pa.estimated_impact WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END
    )
  ))
  INTO v_actions
  FROM prediction_actions pa
  WHERE risk_level = ANY(pa.applicable_risk_levels)
  LIMIT 5;

  risk_score := v_risk_score;
  contributing_factors := v_factors;
  recommended_actions := COALESCE(v_actions, '[]'::JSONB);
  prediction_confidence := v_confidence;

  RETURN NEXT;
END;
$$;


--
-- Name: fn_calculate_skill_distance(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_calculate_skill_distance(p_employee_id uuid, p_level_id uuid) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_distance NUMERIC := 0;
    v_total_weight NUMERIC := 0;
    v_skill_record RECORD;
BEGIN
    FOR v_skill_record IN
        SELECT
            cls.skill_id,
            cls.min_composite_score AS required_score,
            cls.weight,
            cls.is_mandatory,
            COALESCE(esp.composite_score, 0) AS employee_score
        FROM career_path_level_skills cls
        LEFT JOIN employee_skill_profiles esp
            ON esp.skill_id = cls.skill_id
            AND esp.employee_id = p_employee_id
            AND esp.verification_status = 'verified'
        WHERE cls.level_id = p_level_id
    LOOP
        -- Calculate gap for this skill
        IF v_skill_record.employee_score < v_skill_record.required_score THEN
            v_distance := v_distance +
                (v_skill_record.required_score - v_skill_record.employee_score) * v_skill_record.weight;
        END IF;
        v_total_weight := v_total_weight + v_skill_record.weight;
    END LOOP;

    -- Normalize distance
    IF v_total_weight > 0 THEN
        RETURN v_distance / v_total_weight;
    ELSE
        RETURN 0;
    END IF;
END;
$$;


--
-- Name: FUNCTION fn_calculate_skill_distance(p_employee_id uuid, p_level_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.fn_calculate_skill_distance(p_employee_id uuid, p_level_id uuid) IS 'Calculates normalized skill distance between employee and career level';


--
-- Name: fn_career_transition_bridge(character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_career_transition_bridge(p_source_uri character varying, p_target_uri character varying) RETURNS TABLE(skill_label character varying, skill_type character varying, status character varying, closest_source_skill character varying, transferability double precision, is_essential boolean)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    WITH source_skills AS (
        SELECT s.id, s.preferred_label_en, s.embedding_en
        FROM esco_occupation_skills os
        JOIN esco_skills s ON s.id = os.skill_id
        JOIN esco_occupations o ON o.id = os.occupation_id
        WHERE o.uri = p_source_uri
    ),
    target_skills AS (
        SELECT s.id, s.preferred_label_en, s.skill_type, os.relation_type, s.embedding_en
        FROM esco_occupation_skills os
        JOIN esco_skills s ON s.id = os.skill_id
        JOIN esco_occupations o ON o.id = os.occupation_id
        WHERE o.uri = p_target_uri
    )
    SELECT
        ts.preferred_label_en,
        ts.skill_type,
        CASE
            WHEN ts.id IN (SELECT id FROM source_skills) THEN 'HAVE'
            WHEN (SELECT MIN(ss.embedding_en <=> ts.embedding_en) FROM source_skills ss) < 0.5 THEN 'TRANSFERABLE'
            ELSE 'LEARN'
        END::VARCHAR(20),
        (SELECT ss.preferred_label_en FROM source_skills ss
         ORDER BY ss.embedding_en <=> ts.embedding_en LIMIT 1),
        COALESCE(
            (1 - (SELECT MIN(ss.embedding_en <=> ts.embedding_en) FROM source_skills ss))::FLOAT,
            0.0
        ),
        ts.relation_type = 'essential'
    FROM target_skills ts
    ORDER BY
        CASE
            WHEN ts.id IN (SELECT id FROM source_skills) THEN 0
            WHEN (SELECT MIN(ss.embedding_en <=> ts.embedding_en) FROM source_skills ss) < 0.5 THEN 1
            ELSE 2
        END,
        CASE ts.relation_type WHEN 'essential' THEN 0 ELSE 1 END;
END;
$$;


--
-- Name: fn_cleanup_embedding_queue(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_cleanup_embedding_queue(p_days integer DEFAULT 7) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_count INTEGER;
BEGIN
    DELETE FROM embedding_queue
    WHERE status = 'completed'
    AND processed_at < NOW() - (p_days || ' days')::INTERVAL;

    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$$;


--
-- Name: fn_complete_embedding_queue(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_complete_embedding_queue(p_ids uuid[]) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_count INTEGER;
BEGIN
    UPDATE embedding_queue
    SET status = 'completed',
        processed_at = NOW()
    WHERE id = ANY(p_ids);

    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$$;


--
-- Name: fn_detect_calibration_outliers(uuid, uuid, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_detect_calibration_outliers(p_tenant_id uuid, p_session_id uuid, p_std_dev_threshold numeric DEFAULT 2.0) RETURNS TABLE(adjustment_id uuid, employee_id uuid, employee_name text, rating numeric, department_avg numeric, session_avg numeric, deviation numeric, outlier_reason character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  WITH session_stats AS (
    SELECT
      AVG(COALESCE(adjusted_rating, original_rating)) as avg_rating,
      STDDEV(COALESCE(adjusted_rating, original_rating)) as stddev_rating
    FROM calibration_adjustments
    WHERE calibration_session_id = p_session_id AND tenant_id = p_tenant_id
  ),
  dept_stats AS (
    SELECT
      e.org_unit_id,
      AVG(COALESCE(ca.adjusted_rating, ca.original_rating)) as dept_avg
    FROM calibration_adjustments ca
    JOIN employees e ON ca.employee_id = e.id
    WHERE ca.calibration_session_id = p_session_id AND ca.tenant_id = p_tenant_id
    GROUP BY e.org_unit_id
  )
  SELECT
    ca.id as adjustment_id,
    ca.employee_id,
    e.first_name || ' ' || e.last_name as employee_name,
    COALESCE(ca.adjusted_rating, ca.original_rating) as rating,
    ds.dept_avg as department_avg,
    ss.avg_rating as session_avg,
    ABS(COALESCE(ca.adjusted_rating, ca.original_rating) - ss.avg_rating) / NULLIF(ss.stddev_rating, 0) as deviation,
    (CASE
      WHEN ABS(COALESCE(ca.adjusted_rating, ca.original_rating) - ss.avg_rating) / NULLIF(ss.stddev_rating, 0) > p_std_dev_threshold THEN 'high_variance'
      WHEN COALESCE(ca.adjusted_rating, ca.original_rating) <= 1 OR COALESCE(ca.adjusted_rating, ca.original_rating) >= 5 THEN 'extreme_rating'
      WHEN ABS(COALESCE(ca.adjusted_rating, ca.original_rating) - ds.dept_avg) > 1 THEN 'dept_deviation'
      ELSE NULL
    END)::VARCHAR as outlier_reason
  FROM calibration_adjustments ca
  JOIN employees e ON ca.employee_id = e.id
  CROSS JOIN session_stats ss
  LEFT JOIN dept_stats ds ON e.org_unit_id = ds.org_unit_id
  WHERE ca.calibration_session_id = p_session_id
    AND ca.tenant_id = p_tenant_id
    AND (
      ABS(COALESCE(ca.adjusted_rating, ca.original_rating) - ss.avg_rating) / NULLIF(ss.stddev_rating, 0) > p_std_dev_threshold
      OR COALESCE(ca.adjusted_rating, ca.original_rating) <= 1
      OR COALESCE(ca.adjusted_rating, ca.original_rating) >= 5
    );
END;
$$;


--
-- Name: fn_embedding_queue_status(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_embedding_queue_status() RETURNS TABLE(status character varying, entity_type character varying, count bigint, oldest_entry timestamp with time zone, failed_count bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        eq.status,
        eq.entity_type,
        COUNT(*)::BIGINT as count,
        MIN(eq.created_at) as oldest_entry,
        COUNT(*) FILTER (WHERE eq.status = 'failed')::BIGINT as failed_count
    FROM embedding_queue eq
    GROUP BY eq.status, eq.entity_type
    ORDER BY eq.status, eq.entity_type;
END;
$$;


--
-- Name: fn_employee_career_recommendations(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_employee_career_recommendations(p_employee_id uuid, p_limit integer DEFAULT 10) RETURNS TABLE(occupation_id uuid, occupation_label character varying, isco_code character varying, skill_coverage double precision, total_essential integer, skills_held integer, skills_missing integer, embedding_match double precision)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    WITH emp_skills AS (
        SELECT DISTINCT es.esco_skill_id
        FROM employee_skills es
        WHERE es.employee_id = p_employee_id
    ),
    emp_profile_embedding AS (
        -- Average of employee's skill embeddings as profile vector
        SELECT avg(s.embedding_en) AS profile_emb
        FROM emp_skills es
        JOIN esco_skills s ON s.id = es.esco_skill_id
        WHERE s.embedding_en IS NOT NULL
    ),
    occ_coverage AS (
        SELECT
            o.id,
            o.preferred_label_en,
            o.isco_code,
            count(*) FILTER (WHERE os.relation_type = 'essential') AS total_ess,
            count(*) FILTER (WHERE os.relation_type = 'essential' AND os.skill_id IN (SELECT esco_skill_id FROM emp_skills)) AS held_ess,
            (1 - (o.embedding_en <=> epe.profile_emb))::FLOAT AS emb_match
        FROM esco_occupations o
        CROSS JOIN emp_profile_embedding epe
        JOIN esco_occupation_skills os ON os.occupation_id = o.id
        WHERE o.embedding_en IS NOT NULL
          AND epe.profile_emb IS NOT NULL
        GROUP BY o.id, o.preferred_label_en, o.isco_code, o.embedding_en, epe.profile_emb
        HAVING count(*) FILTER (WHERE os.relation_type = 'essential') > 0
    )
    SELECT
        oc.id,
        oc.preferred_label_en,
        oc.isco_code,
        (oc.held_ess::FLOAT / oc.total_ess)::FLOAT,
        oc.total_ess::INT,
        oc.held_ess::INT,
        (oc.total_ess - oc.held_ess)::INT,
        oc.emb_match
    FROM occ_coverage oc
    WHERE oc.held_ess > 0  -- at least some skill overlap
    ORDER BY (oc.held_ess::FLOAT / oc.total_ess * 0.6 + oc.emb_match * 0.4) DESC
    LIMIT p_limit;
END;
$$;


--
-- Name: fn_employees_view_delete(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_employees_view_delete() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  DELETE FROM public.employees_core WHERE id = OLD.id;
  RETURN OLD;
END;
$$;


--
-- Name: fn_employees_view_insert(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_employees_view_insert() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- core (18 col)
  INSERT INTO public.employees_core (
    id, tenant_id, skills, is_active, created_at, updated_at, pernr,
    employment_status, termination_date, termination_reason,
    profile_embedding, embedding_text_hash, embedding_model, embedding_generated_at,
    deleted_at, enrichment_consent, enrichment_consent_at, enrichment_consent_scope
  ) VALUES (
    COALESCE(NEW.id, uuid_generate_v4()), NEW.tenant_id, NEW.skills,
    COALESCE(NEW.is_active, true), COALESCE(NEW.created_at, now()), COALESCE(NEW.updated_at, now()),
    NEW.pernr, NEW.employment_status, NEW.termination_date, NEW.termination_reason,
    NEW.profile_embedding, NEW.embedding_text_hash, NEW.embedding_model, NEW.embedding_generated_at,
    NEW.deleted_at, COALESCE(NEW.enrichment_consent, false), NEW.enrichment_consent_at, NEW.enrichment_consent_scope
  );

  -- pii (38 col)
  INSERT INTO public.employees_pii (
    employee_id, tenant_id,
    first_name, last_name, middle_name, email, personal_email,
    birth_date, birth_place, gender, nationality, marital_status,
    address_street, address_city, address_postal_code, address_country, address_region,
    temp_address_street, temp_address_city, temp_address_postal_code, temp_address_country,
    phone_mobile, phone_work, phone_home,
    tax_id, national_id, national_id_expiry,
    passport_number, passport_expiry, driver_license, driver_license_expiry,
    emergency_contact_name, emergency_contact_phone, emergency_contact_relationship,
    family_members, education_history,
    highest_education_level, highest_education_institution, highest_education_field, highest_education_year
  ) VALUES (
    COALESCE(NEW.id, (SELECT id FROM public.employees_core WHERE id = NEW.id)),
    NEW.tenant_id,
    NEW.first_name, NEW.last_name, NEW.middle_name, NEW.email, NEW.personal_email,
    NEW.birth_date, NEW.birth_place, NEW.gender, NEW.nationality, NEW.marital_status,
    NEW.address_street, NEW.address_city, NEW.address_postal_code, NEW.address_country, NEW.address_region,
    NEW.temp_address_street, NEW.temp_address_city, NEW.temp_address_postal_code, NEW.temp_address_country,
    NEW.phone_mobile, NEW.phone_work, NEW.phone_home,
    NEW.tax_id, NEW.national_id, NEW.national_id_expiry,
    NEW.passport_number, NEW.passport_expiry, NEW.driver_license, NEW.driver_license_expiry,
    NEW.emergency_contact_name, NEW.emergency_contact_phone, NEW.emergency_contact_relationship,
    NEW.family_members, NEW.education_history,
    NEW.highest_education_level, NEW.highest_education_institution, NEW.highest_education_field, NEW.highest_education_year
  );

  -- hr (28 col)
  INSERT INTO public.employees_hr (
    employee_id, tenant_id,
    job_title, department, location, manager_id, hire_date,
    performance_rating, potential, legacy_org_unit_code,
    cost_center, cost_center_id, org_unit_id, location_id, position_id,
    employee_group, employee_subgroup, company_code, personnel_area, personnel_subarea,
    probation_end_date, seniority_date, contract_end_date, work_schedule_percentage,
    auth_username, auth_password_hash, auth_role, auth_permissions, auth_last_login, auth_username_candidate
  ) VALUES (
    COALESCE(NEW.id, (SELECT id FROM public.employees_core WHERE id = NEW.id)),
    NEW.tenant_id,
    NEW.job_title, NEW.department, NEW.location, NEW.manager_id, NEW.hire_date,
    NEW.performance_rating, NEW.potential, NEW.legacy_org_unit_code,
    NEW.cost_center, NEW.cost_center_id, NEW.org_unit_id, NEW.location_id, NEW.position_id,
    NEW.employee_group, NEW.employee_subgroup, NEW.company_code, NEW.personnel_area, NEW.personnel_subarea,
    NEW.probation_end_date, NEW.seniority_date, NEW.contract_end_date, NEW.work_schedule_percentage,
    NEW.auth_username, NEW.auth_password_hash, NEW.auth_role, NEW.auth_permissions, NEW.auth_last_login, NEW.auth_username_candidate
  );

  -- payroll (11 col)
  INSERT INTO public.employees_payroll (
    employee_id, tenant_id,
    salary, currency,
    pay_scale_area, pay_scale_type, pay_scale_group, pay_scale_level, pay_periods_per_year,
    iban, swift_bic, bank_name, bank_account_number
  ) VALUES (
    COALESCE(NEW.id, (SELECT id FROM public.employees_core WHERE id = NEW.id)),
    NEW.tenant_id,
    NEW.salary, NEW.currency,
    NEW.pay_scale_area, NEW.pay_scale_type, NEW.pay_scale_group, NEW.pay_scale_level, NEW.pay_periods_per_year,
    NEW.iban, NEW.swift_bic, NEW.bank_name, NEW.bank_account_number
  );

  RETURN NEW;
END;
$$;


--
-- Name: fn_employees_view_update(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_employees_view_update() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- core
  UPDATE public.employees_core SET
    tenant_id = NEW.tenant_id,
    skills = NEW.skills,
    is_active = NEW.is_active,
    updated_at = COALESCE(NEW.updated_at, now()),
    pernr = NEW.pernr,
    employment_status = NEW.employment_status,
    termination_date = NEW.termination_date,
    termination_reason = NEW.termination_reason,
    profile_embedding = NEW.profile_embedding,
    embedding_text_hash = NEW.embedding_text_hash,
    embedding_model = NEW.embedding_model,
    embedding_generated_at = NEW.embedding_generated_at,
    deleted_at = NEW.deleted_at,
    enrichment_consent = NEW.enrichment_consent,
    enrichment_consent_at = NEW.enrichment_consent_at,
    enrichment_consent_scope = NEW.enrichment_consent_scope
  WHERE id = OLD.id;

  -- pii
  UPDATE public.employees_pii SET
    tenant_id = NEW.tenant_id,
    first_name = NEW.first_name, last_name = NEW.last_name, middle_name = NEW.middle_name,
    email = NEW.email, personal_email = NEW.personal_email,
    birth_date = NEW.birth_date, birth_place = NEW.birth_place,
    gender = NEW.gender, nationality = NEW.nationality, marital_status = NEW.marital_status,
    address_street = NEW.address_street, address_city = NEW.address_city,
    address_postal_code = NEW.address_postal_code, address_country = NEW.address_country, address_region = NEW.address_region,
    temp_address_street = NEW.temp_address_street, temp_address_city = NEW.temp_address_city,
    temp_address_postal_code = NEW.temp_address_postal_code, temp_address_country = NEW.temp_address_country,
    phone_mobile = NEW.phone_mobile, phone_work = NEW.phone_work, phone_home = NEW.phone_home,
    tax_id = NEW.tax_id, national_id = NEW.national_id, national_id_expiry = NEW.national_id_expiry,
    passport_number = NEW.passport_number, passport_expiry = NEW.passport_expiry,
    driver_license = NEW.driver_license, driver_license_expiry = NEW.driver_license_expiry,
    emergency_contact_name = NEW.emergency_contact_name,
    emergency_contact_phone = NEW.emergency_contact_phone,
    emergency_contact_relationship = NEW.emergency_contact_relationship,
    family_members = NEW.family_members, education_history = NEW.education_history,
    highest_education_level = NEW.highest_education_level,
    highest_education_institution = NEW.highest_education_institution,
    highest_education_field = NEW.highest_education_field,
    highest_education_year = NEW.highest_education_year,
    updated_at = now()
  WHERE employee_id = OLD.id;

  -- hr
  UPDATE public.employees_hr SET
    tenant_id = NEW.tenant_id,
    job_title = NEW.job_title, department = NEW.department, location = NEW.location,
    manager_id = NEW.manager_id, hire_date = NEW.hire_date,
    performance_rating = NEW.performance_rating, potential = NEW.potential,
    legacy_org_unit_code = NEW.legacy_org_unit_code,
    cost_center = NEW.cost_center, cost_center_id = NEW.cost_center_id,
    org_unit_id = NEW.org_unit_id, location_id = NEW.location_id, position_id = NEW.position_id,
    employee_group = NEW.employee_group, employee_subgroup = NEW.employee_subgroup,
    company_code = NEW.company_code, personnel_area = NEW.personnel_area, personnel_subarea = NEW.personnel_subarea,
    probation_end_date = NEW.probation_end_date, seniority_date = NEW.seniority_date,
    contract_end_date = NEW.contract_end_date, work_schedule_percentage = NEW.work_schedule_percentage,
    auth_username = NEW.auth_username, auth_password_hash = NEW.auth_password_hash,
    auth_role = NEW.auth_role, auth_permissions = NEW.auth_permissions,
    auth_last_login = NEW.auth_last_login, auth_username_candidate = NEW.auth_username_candidate,
    updated_at = now()
  WHERE employee_id = OLD.id;

  -- payroll
  UPDATE public.employees_payroll SET
    tenant_id = NEW.tenant_id,
    salary = NEW.salary, currency = NEW.currency,
    pay_scale_area = NEW.pay_scale_area, pay_scale_type = NEW.pay_scale_type,
    pay_scale_group = NEW.pay_scale_group, pay_scale_level = NEW.pay_scale_level,
    pay_periods_per_year = NEW.pay_periods_per_year,
    iban = NEW.iban, swift_bic = NEW.swift_bic,
    bank_name = NEW.bank_name, bank_account_number = NEW.bank_account_number,
    updated_at = now()
  WHERE employee_id = OLD.id;

  RETURN NEW;
END;
$$;


--
-- Name: fn_fail_embedding_queue(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_fail_embedding_queue(p_id uuid, p_error text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE embedding_queue
    SET status = CASE
            WHEN attempts >= max_attempts THEN 'failed'
            ELSE 'pending'
        END,
        error_message = p_error,
        processed_at = NOW()
    WHERE id = p_id;
END;
$$;


--
-- Name: fn_find_matching_occupations(character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_find_matching_occupations(p_query_text character varying, p_language character varying DEFAULT 'en'::character varying, p_limit integer DEFAULT 10) RETURNS TABLE(occupation_id uuid, uri character varying, preferred_label character varying, isco_code character varying, similarity double precision)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_query_embedding vector(1536);
BEGIN
    -- Use the closest skill embedding as a proxy for the query
    -- (Real implementation would call OpenAI API for query embedding)
    IF p_language = 'it' THEN
        SELECT s.embedding_it INTO v_query_embedding
        FROM esco_skills s
        WHERE s.embedding_it IS NOT NULL
          AND s.preferred_label_it ILIKE '%' || p_query_text || '%'
        ORDER BY length(s.preferred_label_it) ASC
        LIMIT 1;

        IF v_query_embedding IS NULL THEN
            SELECT s.embedding_it INTO v_query_embedding
            FROM esco_skills s
            WHERE s.embedding_it IS NOT NULL
            ORDER BY s.preferred_label_it <-> p_query_text
            LIMIT 1;
        END IF;

        RETURN QUERY
        SELECT o.id, o.uri, o.preferred_label_it, o.isco_code,
               (1 - (o.embedding_it <=> v_query_embedding))::FLOAT
        FROM esco_occupations o
        WHERE o.embedding_it IS NOT NULL
        ORDER BY o.embedding_it <=> v_query_embedding
        LIMIT p_limit;
    ELSE
        SELECT s.embedding_en INTO v_query_embedding
        FROM esco_skills s
        WHERE s.embedding_en IS NOT NULL
          AND s.preferred_label_en ILIKE '%' || p_query_text || '%'
        ORDER BY length(s.preferred_label_en) ASC
        LIMIT 1;

        IF v_query_embedding IS NULL THEN
            SELECT s.embedding_en INTO v_query_embedding
            FROM esco_skills s
            WHERE s.embedding_en IS NOT NULL
            ORDER BY s.preferred_label_en <-> p_query_text
            LIMIT 1;
        END IF;

        RETURN QUERY
        SELECT o.id, o.uri, o.preferred_label_en, o.isco_code,
               (1 - (o.embedding_en <=> v_query_embedding))::FLOAT
        FROM esco_occupations o
        WHERE o.embedding_en IS NOT NULL
        ORDER BY o.embedding_en <=> v_query_embedding
        LIMIT p_limit;
    END IF;
END;
$$;


--
-- Name: fn_find_mentor_matches(uuid, uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_find_mentor_matches(p_tenant_id uuid, p_mentee_id uuid, p_skill_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 10) RETURNS TABLE(mentor_id uuid, mentor_name text, mentor_title text, mentor_department text, skill_name text, mentee_level numeric, mentor_level numeric, match_score numeric, match_factors jsonb)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  WITH mentee_gaps AS (
    -- Get skills where mentee needs improvement
    SELECT
      psl.linked_skill_id as skill_id,
      es.preferred_label_en as skill_name,
      COALESCE(esp.composite_score, psl.competency_rating) as current_level
    FROM performance_skill_links psl
    LEFT JOIN esco_skills es ON psl.linked_skill_id = es.id
    LEFT JOIN employee_skill_profiles esp ON esp.employee_id = psl.employee_id AND esp.skill_id = psl.linked_skill_id
    WHERE psl.tenant_id = p_tenant_id
      AND psl.employee_id = p_mentee_id
      AND psl.rating_level = 'low'
      AND psl.linked_skill_id IS NOT NULL
      AND (p_skill_id IS NULL OR psl.linked_skill_id = p_skill_id)
  ),
  potential_mentors AS (
    -- Find employees with strong skills in those areas
    SELECT
      esp.employee_id as mentor_id,
      esp.skill_id,
      esp.composite_score as mentor_level,
      (e.first_name || ' ' || e.last_name)::TEXT as mentor_name,
      e.job_title::TEXT as mentor_title,
      d.name::TEXT as mentor_department
    FROM employee_skill_profiles esp
    JOIN employees e ON esp.employee_id = e.id
    LEFT JOIN org_units d ON e.org_unit_id = d.id
    JOIN mentee_gaps mg ON esp.skill_id = mg.skill_id
    WHERE esp.tenant_id = p_tenant_id
      AND esp.employee_id <> p_mentee_id
      AND esp.composite_score >= 4.0  -- Must be highly proficient
      AND e.employment_status = 'active'
      AND esp.composite_score > mg.current_level + 1.0  -- At least 1 level higher
  )
  SELECT
    pm.mentor_id,
    pm.mentor_name,
    pm.mentor_title,
    pm.mentor_department,
    es.preferred_label_en::TEXT as skill_name,
    mg.current_level as mentee_level,
    pm.mentor_level,
    -- Calculate match score based on multiple factors
    (
      (pm.mentor_level - mg.current_level) / 4.0 * 0.4 +  -- Skill gap weight
      0.3 +  -- Base match score
      CASE WHEN pm.mentor_department = (SELECT name FROM org_units d2 JOIN employees e2 ON d2.id = e2.org_unit_id WHERE e2.id = p_mentee_id)
           THEN 0.15 ELSE 0 END +  -- Same department bonus
      0.15  -- Availability factor (simplified)
    )::NUMERIC as match_score,
    jsonb_build_object(
      'skill_gap', pm.mentor_level - mg.current_level,
      'same_department', pm.mentor_department = (SELECT name FROM org_units d2 JOIN employees e2 ON d2.id = e2.org_unit_id WHERE e2.id = p_mentee_id),
      'mentor_proficiency', pm.mentor_level
    ) as match_factors
  FROM potential_mentors pm
  JOIN esco_skills es ON pm.skill_id = es.id
  JOIN mentee_gaps mg ON pm.skill_id = mg.skill_id
  ORDER BY match_score DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: fn_find_similar_skills(character varying, character varying, double precision, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_find_similar_skills(p_skill_uri character varying, p_language character varying DEFAULT 'en'::character varying, p_threshold double precision DEFAULT 0.3, p_limit integer DEFAULT 20) RETURNS TABLE(skill_id uuid, uri character varying, preferred_label character varying, skill_type character varying, reuse_level character varying, similarity double precision)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    IF p_language = 'it' THEN
        RETURN QUERY
        SELECT s2.id, s2.uri, s2.preferred_label_it, s2.skill_type, s2.reuse_level,
               (1 - (s2.embedding_it <=> s1.embedding_it))::FLOAT
        FROM esco_skills s1
        JOIN esco_skills s2 ON s2.id != s1.id
        WHERE s1.uri = p_skill_uri
          AND s2.embedding_it IS NOT NULL
          AND (1 - (s2.embedding_it <=> s1.embedding_it)) >= p_threshold
        ORDER BY s2.embedding_it <=> s1.embedding_it
        LIMIT p_limit;
    ELSE
        RETURN QUERY
        SELECT s2.id, s2.uri, s2.preferred_label_en, s2.skill_type, s2.reuse_level,
               (1 - (s2.embedding_en <=> s1.embedding_en))::FLOAT
        FROM esco_skills s1
        JOIN esco_skills s2 ON s2.id != s1.id
        WHERE s1.uri = p_skill_uri
          AND s2.embedding_en IS NOT NULL
          AND (1 - (s2.embedding_en <=> s1.embedding_en)) >= p_threshold
        ORDER BY s2.embedding_en <=> s1.embedding_en
        LIMIT p_limit;
    END IF;
END;
$$;


--
-- Name: fn_generate_org_prototype(uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_generate_org_prototype(p_tenant_id uuid, p_dry_run boolean DEFAULT true) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_tenant RECORD;
    v_rule RECORD;
    v_nace_primary VARCHAR(10);
    v_nace_section VARCHAR(5);
    v_result JSONB := '{}';
    v_departments JSONB := '[]';
    v_positions JSONB := '[]';
    v_dept_count INT := 0;
    v_pos_count INT := 0;
    v_skill_count INT := 0;
    v_dept_rec RECORD;
    v_occ_rec RECORD;
    v_dept_id UUID;
    v_pos_id UUID;
    v_dept_code VARCHAR(20);
    v_positions_per_dept INT;
    v_dept_idx INT := 0;
    v_profile_id UUID;
BEGIN
    -- ========================================================================
    -- Step 1: Load tenant ontological profile
    -- ========================================================================
    SELECT t.id, t.code, t.name, t.nace_primary, t.nace_code, t.company_size,
           t.employee_count, t.industry_type
    INTO v_tenant
    FROM tenants t WHERE t.id = p_tenant_id;

    IF v_tenant.id IS NULL THEN
        RETURN jsonb_build_object('error', 'Tenant not found');
    END IF;

    v_nace_primary := COALESCE(v_tenant.nace_primary, v_tenant.nace_code);
    IF v_nace_primary IS NULL THEN
        RETURN jsonb_build_object('error', 'Tenant has no NACE code configured');
    END IF;

    -- Extract NACE section letter (first char if letter, otherwise lookup)
    IF v_nace_primary ~ '^[A-Z]' THEN
        v_nace_section := LEFT(v_nace_primary, 1);
    ELSE
        -- Numeric NACE code: find section via nace_divisions/nace_sections
        SELECT nd.section_code INTO v_nace_section
        FROM nace_divisions nd
        WHERE nd.code = LEFT(v_nace_primary, 2)
        LIMIT 1;
        -- Fallback: derive from industry_type
        IF v_nace_section IS NULL THEN
            v_nace_section := LEFT(v_nace_primary, 1);
        END IF;
    END IF;

    -- ========================================================================
    -- Step 2: Load prototype rules for company size
    -- ========================================================================
    -- Try section-specific rule first, then generic
    SELECT * INTO v_rule
    FROM org_prototype_rules
    WHERE company_size = COALESCE(v_tenant.company_size, 'SMALL')
      AND nace_section = v_nace_section;

    IF v_rule.id IS NULL THEN
        SELECT * INTO v_rule
        FROM org_prototype_rules
        WHERE company_size = COALESCE(v_tenant.company_size, 'SMALL')
          AND nace_section IS NULL;
    END IF;

    IF v_rule.id IS NULL THEN
        RETURN jsonb_build_object('error', 'No prototype rule for size: ' || COALESCE(v_tenant.company_size, 'NULL'));
    END IF;

    -- ========================================================================
    -- Step 3: Find ESCO occupations relevant to tenant's NACE
    -- Uses cascading fallback: exact class → group → division → section
    -- ========================================================================
    DROP TABLE IF EXISTS _proto_occupations;
    CREATE TEMP TABLE _proto_occupations (
        occ_id UUID,
        uri VARCHAR(500),
        label_en VARCHAR(500),
        label_it VARCHAR(500),
        isco_code VARCHAR(10),
        isco_major VARCHAR(2),
        relevance INT  -- 1=exact, 2=group, 3=division, 4=section
    ) ON COMMIT DROP;

    -- NACE codes in esco_occupations.nace_codes are URIs like:
    -- 'http://data.europa.eu/ux2/nace2.1/6419' (sometimes with trailing comma)
    -- We extract the numeric code and match against the tenant's nace_primary.
    -- v_nace_primary is e.g. '64.19' — ESCO uses '6419' (no dot).

    -- Helper: normalize nace_primary to ESCO format (remove dots)
    DECLARE
        v_nace_nodot VARCHAR(10) := replace(v_nace_primary, '.', '');
        v_nace_div VARCHAR(4) := LEFT(replace(v_nace_primary, '.', ''), 2);
        v_nace_uri_prefix VARCHAR(100) := 'http://data.europa.eu/ux2/nace2.1/';
    BEGIN

    -- Level 1: Exact NACE class (e.g., URI ends with '6419')
    INSERT INTO _proto_occupations
    SELECT o.id, o.uri, o.preferred_label_en, o.preferred_label_it,
           o.isco_code, LEFT(o.isco_code, 1), 1
    FROM esco_occupations o
    WHERE EXISTS (
        SELECT 1 FROM unnest(o.nace_codes) nc
        WHERE replace(nc, ',', '') = v_nace_uri_prefix || v_nace_nodot
    );

    -- Level 2: NACE group (e.g., URI contains '641' — first 3 digits)
    IF (SELECT count(*) FROM _proto_occupations) < 10 THEN
        INSERT INTO _proto_occupations
        SELECT o.id, o.uri, o.preferred_label_en, o.preferred_label_it,
               o.isco_code, LEFT(o.isco_code, 1), 2
        FROM esco_occupations o
        WHERE EXISTS (
            SELECT 1 FROM unnest(o.nace_codes) nc
            WHERE replace(nc, ',', '') LIKE v_nace_uri_prefix || LEFT(v_nace_nodot, 3) || '%'
        )
        AND o.id NOT IN (SELECT occ_id FROM _proto_occupations);
    END IF;

    -- Level 3: NACE division (e.g., URI contains '64' — first 2 digits)
    IF (SELECT count(*) FROM _proto_occupations) < 10 THEN
        INSERT INTO _proto_occupations
        SELECT o.id, o.uri, o.preferred_label_en, o.preferred_label_it,
               o.isco_code, LEFT(o.isco_code, 1), 3
        FROM esco_occupations o
        WHERE EXISTS (
            SELECT 1 FROM unnest(o.nace_codes) nc
            WHERE replace(nc, ',', '') LIKE v_nace_uri_prefix || v_nace_div || '%'
        )
        AND o.id NOT IN (SELECT occ_id FROM _proto_occupations);
    END IF;

    -- Level 4: Fallback — use embedding similarity to tenant's industry
    -- Find occupations whose embedding is closest to the NACE section description
    IF (SELECT count(*) FROM _proto_occupations) < 10 THEN
        INSERT INTO _proto_occupations
        SELECT o.id, o.uri, o.preferred_label_en, o.preferred_label_it,
               o.isco_code, LEFT(o.isco_code, 1), 4
        FROM esco_occupations o
        WHERE o.embedding_en IS NOT NULL
          AND o.id NOT IN (SELECT occ_id FROM _proto_occupations)
        ORDER BY o.embedding_en <=> (
            SELECT ns.embedding_en FROM nace_sections ns WHERE ns.code = v_nace_section LIMIT 1
        )
        LIMIT 30;
    END IF;

    END; -- end of DECLARE block

    -- ========================================================================
    -- Step 4: Group occupations by ISCO major group → departments
    -- Use org_prototype_templates to map ISCO groups to department names
    -- ========================================================================
    DROP TABLE IF EXISTS _proto_departments;
    CREATE TEMP TABLE _proto_departments (
        dept_name_en VARCHAR(100),
        dept_name_it VARCHAR(100),
        function_type VARCHAR(20),
        isco_groups TEXT[],
        occupation_count INT,
        dept_code VARCHAR(20)
    ) ON COMMIT DROP;

    INSERT INTO _proto_departments (dept_name_en, dept_name_it, function_type, isco_groups, occupation_count, dept_code)
    SELECT
        t.department_name_en,
        t.department_name_it,
        t.function_type,
        array_agg(DISTINCT t.isco_major_group),
        COALESCE(sum(occ_cnt), 0)::INT,
        'DEPT-' || row_number() OVER (ORDER BY t.function_type, t.department_name_en)
    FROM org_prototype_templates t
    LEFT JOIN (
        SELECT isco_major, count(*) AS occ_cnt
        FROM _proto_occupations
        GROUP BY isco_major
    ) po ON po.isco_major = t.isco_major_group
    WHERE t.rule_id = v_rule.id
    GROUP BY t.department_name_en, t.department_name_it, t.function_type
    HAVING COALESCE(sum(occ_cnt), 0) > 0
        OR t.function_type = 'MANAGEMENT'  -- always include management
    ORDER BY t.function_type, t.department_name_en;

    -- Ensure we have at least min_departments by including empty core depts
    IF (SELECT count(*) FROM _proto_departments) < v_rule.min_departments THEN
        INSERT INTO _proto_departments (dept_name_en, dept_name_it, function_type, isco_groups, occupation_count, dept_code)
        SELECT t.department_name_en, t.department_name_it, t.function_type,
               ARRAY[t.isco_major_group], 0,
               'DEPT-' || (SELECT count(*) + 1 FROM _proto_departments)
        FROM org_prototype_templates t
        WHERE t.rule_id = v_rule.id
          AND t.department_name_en NOT IN (SELECT dept_name_en FROM _proto_departments)
        LIMIT (v_rule.min_departments - (SELECT count(*) FROM _proto_departments));
    END IF;

    -- ========================================================================
    -- Step 5: Generate the structure (dry-run → JSONB, apply → INSERT)
    -- ========================================================================

    -- Create org_template as parent container for job_templates (required by ck_job_has_parent)
    IF NOT p_dry_run THEN
        v_profile_id := gen_random_uuid();
        INSERT INTO org_templates (
            id, nace_section_code, nace_division_code,
            company_size_min, company_size_max,
            template_name, description,
            org_structure, recommended_roles
        ) VALUES (
            v_profile_id,
            COALESCE(v_nace_section, 'X'),
            LEFT(replace(v_nace_primary, '.', ''), 2),
            COALESCE(v_tenant.employee_count, 1),
            COALESCE(v_tenant.employee_count, 100) * 2,
            'Prototype: ' || v_tenant.name || ' (' || v_nace_primary || ')',
            'Auto-generated org prototype for ' || v_tenant.name,
            '{}', '[]'
        );
    ELSE
        v_profile_id := gen_random_uuid(); -- placeholder for dry-run
    END IF;

    v_dept_idx := 0;
    FOR v_dept_rec IN
        SELECT * FROM _proto_departments ORDER BY function_type, dept_name_en
    LOOP
        v_dept_idx := v_dept_idx + 1;
        v_dept_code := 'PROTO-' || v_dept_idx;
        v_dept_id := gen_random_uuid();

        -- Calculate positions per department
        v_positions_per_dept := GREATEST(1,
            CEIL(v_dept_rec.occupation_count * v_rule.role_specialization_factor)
        );

        -- Build positions JSONB for this department
        DECLARE
            v_dept_positions JSONB := '[]';
            v_pos_idx INT := 0;
        BEGIN
            FOR v_occ_rec IN
                SELECT po.occ_id, po.uri, po.label_en, po.label_it, po.isco_code
                FROM _proto_occupations po
                WHERE po.isco_major = ANY(v_dept_rec.isco_groups)
                ORDER BY po.relevance, po.label_en
                LIMIT v_positions_per_dept
            LOOP
                v_pos_idx := v_pos_idx + 1;
                v_pos_id := gen_random_uuid();
                v_pos_count := v_pos_count + 1;

                -- Count essential skills for this occupation
                DECLARE
                    v_essential_count INT;
                BEGIN
                    SELECT count(*) INTO v_essential_count
                    FROM esco_occupation_skills os
                    WHERE os.occupation_id = v_occ_rec.occ_id
                      AND os.relation_type = 'essential';

                    v_skill_count := v_skill_count + v_essential_count;

                    v_dept_positions := v_dept_positions || jsonb_build_object(
                        'id', v_pos_id,
                        'title_en', v_occ_rec.label_en,
                        'title_it', COALESCE(v_occ_rec.label_it, v_occ_rec.label_en),
                        'esco_occupation_uri', v_occ_rec.uri,
                        'isco_code', v_occ_rec.isco_code,
                        'essential_skills', v_essential_count
                    );

                    -- If not dry-run, INSERT the position
                    IF NOT p_dry_run THEN
                        INSERT INTO job_templates (
                            id, profile_id, tenant_id, job_code,
                            title_it, title_en,
                            esco_occupation_uri, esco_occupation_code,
                            esco_occupation_title,
                            is_management, is_prototype_generated, is_active, created_at
                        ) VALUES (
                            v_pos_id, v_profile_id, p_tenant_id,
                            v_dept_code || '-' || v_pos_idx,
                            COALESCE(v_occ_rec.label_it, v_occ_rec.label_en),
                            v_occ_rec.label_en,
                            v_occ_rec.uri,
                            v_occ_rec.isco_code,
                            v_occ_rec.label_en,
                            (LEFT(v_occ_rec.isco_code, 1) = '1'),
                            true, true, NOW()
                        );

                        -- Insert essential skill requirements
                        INSERT INTO position_skill_requirements (
                            tenant_id, position_id, position_name,
                            esco_skill_id, requirement_type, minimum_proficiency, weight
                        )
                        SELECT
                            p_tenant_id, v_pos_id, v_occ_rec.label_en,
                            os.skill_id, 'essential', 3, 1.0
                        FROM esco_occupation_skills os
                        WHERE os.occupation_id = v_occ_rec.occ_id
                          AND os.relation_type = 'essential';
                    END IF;
                END;
            END LOOP;

            -- Build department in output
            v_dept_count := v_dept_count + 1;
            v_departments := v_departments || jsonb_build_object(
                'id', v_dept_id,
                'code', v_dept_code,
                'name_en', v_dept_rec.dept_name_en,
                'name_it', v_dept_rec.dept_name_it,
                'function_type', v_dept_rec.function_type,
                'occupation_count', v_dept_rec.occupation_count,
                'positions_generated', v_pos_idx,
                'positions', v_dept_positions
            );

            -- If not dry-run, INSERT department
            IF NOT p_dry_run THEN
                INSERT INTO org_units (
                    id, tenant_id, code, name, name_en, description,
                    is_active, created_at
                ) VALUES (
                    v_dept_id, p_tenant_id, v_dept_code,
                    v_dept_rec.dept_name_en, v_dept_rec.dept_name_en,
                    'Auto-generated from NACE ' || v_nace_primary || ' (' || v_dept_rec.function_type || ')',
                    true, NOW()
                )
                ON CONFLICT DO NOTHING;
            END IF;
        END;
    END LOOP;

    -- ========================================================================
    -- Step 6: Save onboarding profile snapshot
    -- ========================================================================
    v_result := jsonb_build_object(
        'tenant', jsonb_build_object(
            'id', v_tenant.id,
            'code', v_tenant.code,
            'name', v_tenant.name,
            'nace_primary', v_nace_primary,
            'nace_section', v_nace_section,
            'company_size', v_tenant.company_size,
            'industry_type', v_tenant.industry_type
        ),
        'rule', jsonb_build_object(
            'company_size', v_rule.company_size,
            'specialization_factor', v_rule.role_specialization_factor,
            'max_hierarchy_levels', v_rule.max_hierarchy_levels,
            'merge_support', v_rule.merge_support_functions
        ),
        'occupations_found', (SELECT count(*) FROM _proto_occupations),
        'departments', v_departments,
        'summary', jsonb_build_object(
            'departments_generated', v_dept_count,
            'positions_generated', v_pos_count,
            'skill_requirements_generated', v_skill_count,
            'dry_run', p_dry_run
        )
    );

    IF NOT p_dry_run THEN
        INSERT INTO tenant_onboarding_profiles (
            tenant_id, nace_occupations_snapshot, size_modifiers, prototype_config,
            departments_generated, positions_generated, skill_requirements_generated
        ) VALUES (
            p_tenant_id,
            (SELECT jsonb_agg(jsonb_build_object('uri', uri, 'label', label_en, 'isco', isco_code, 'relevance', relevance))
             FROM _proto_occupations),
            jsonb_build_object('company_size', v_rule.company_size, 'factor', v_rule.role_specialization_factor),
            v_result->'rule',
            v_dept_count, v_pos_count, v_skill_count
        );

        -- Mark onboarding completed
        UPDATE tenants SET onboarding_completed_at = NOW() WHERE id = p_tenant_id;
    END IF;

    RETURN v_result;
END;
$$;


--
-- Name: fn_generate_predictions(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_generate_predictions(p_tenant_id uuid, p_prediction_period character varying DEFAULT NULL::character varying) RETURNS TABLE(employees_processed integer, predictions_created integer, hipos_identified integer, high_risk_count integer)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_period VARCHAR(20);
  v_model_version INTEGER;
  v_processed INTEGER := 0;
  v_created INTEGER := 0;
  v_hipos INTEGER := 0;
  v_high_risk INTEGER := 0;
  v_emp RECORD;
  v_risk RECORD;
  v_hipo RECORD;
BEGIN
  -- Default period to current quarter
  v_period := COALESCE(p_prediction_period, 'Q' || EXTRACT(QUARTER FROM NOW())::TEXT || '-' || EXTRACT(YEAR FROM NOW())::TEXT);

  -- Get next model version
  SELECT COALESCE(MAX(model_version), 0) + 1
  INTO v_model_version
  FROM performance_predictions
  WHERE tenant_id = p_tenant_id;

  -- Mark previous predictions as not current
  UPDATE performance_predictions
  SET is_current = false
  WHERE tenant_id = p_tenant_id
    AND is_current = true;

  -- Process each employee
  FOR v_emp IN
    SELECT id FROM employees
    WHERE tenant_id = p_tenant_id
      AND status = 'active'
  LOOP
    v_processed := v_processed + 1;

    -- Calculate risk score
    SELECT * INTO v_risk FROM fn_calculate_risk_score(p_tenant_id, v_emp.id);

    -- Calculate HiPo score
    SELECT * INTO v_hipo FROM fn_calculate_hipo_score(p_tenant_id, v_emp.id);

    -- Insert prediction
    INSERT INTO performance_predictions (
      tenant_id,
      employee_id,
      prediction_period,
      predicted_rating,
      confidence_interval_low,
      confidence_interval_high,
      risk_score,
      risk_level,
      is_high_potential,
      hipo_score,
      hipo_justification,
      contributing_factors,
      recommended_actions,
      prediction_confidence,
      model_version,
      model_name,
      is_current
    ) VALUES (
      p_tenant_id,
      v_emp.id,
      v_period,
      5.0 - (v_risk.risk_score::NUMERIC / 25), -- Convert risk to predicted rating
      GREATEST(1.0, 5.0 - (v_risk.risk_score::NUMERIC / 25) - 0.5),
      LEAST(5.0, 5.0 - (v_risk.risk_score::NUMERIC / 25) + 0.5),
      v_risk.risk_score,
      v_risk.risk_level,
      v_hipo.is_high_potential,
      v_hipo.hipo_score,
      v_hipo.hipo_justification,
      v_risk.contributing_factors || v_hipo.potential_factors,
      v_risk.recommended_actions,
      v_risk.prediction_confidence,
      v_model_version,
      'heuresys-perf-v1',
      true
    );

    v_created := v_created + 1;

    IF v_hipo.is_high_potential THEN
      v_hipos := v_hipos + 1;
    END IF;

    IF v_risk.risk_level IN ('high', 'critical') THEN
      v_high_risk := v_high_risk + 1;
    END IF;
  END LOOP;

  employees_processed := v_processed;
  predictions_created := v_created;
  hipos_identified := v_hipos;
  high_risk_count := v_high_risk;

  RETURN NEXT;
END;
$$;


--
-- Name: fn_get_embedding_queue_batch(integer, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_get_embedding_queue_batch(p_batch_size integer DEFAULT 50, p_entity_type character varying DEFAULT NULL::character varying) RETURNS TABLE(id uuid, entity_type character varying, entity_id uuid, tenant_id uuid, operation character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH batch AS (
        SELECT eq.id
        FROM embedding_queue eq
        WHERE eq.status = 'pending'
        AND eq.attempts < eq.max_attempts
        AND (p_entity_type IS NULL OR eq.entity_type = p_entity_type)
        ORDER BY eq.priority, eq.created_at
        LIMIT p_batch_size
        FOR UPDATE SKIP LOCKED
    )
    UPDATE embedding_queue eq
    SET status = 'processing',
        processed_at = NOW(),
        attempts = attempts + 1
    FROM batch
    WHERE eq.id = batch.id
    RETURNING eq.id, eq.entity_type, eq.entity_id, eq.tenant_id, eq.operation;
END;
$$;


--
-- Name: fn_get_feedback_for_review(uuid, uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_get_feedback_for_review(p_tenant_id uuid, p_employee_id uuid, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date) RETURNS TABLE(feedback_id uuid, from_employee_name text, feedback_type character varying, message text, category character varying, related_goal_title text, created_at timestamp with time zone, sentiment_score numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    cf.id as feedback_id,
    (f.first_name || ' ' || f.last_name)::TEXT as from_employee_name,
    cf.feedback_type,
    cf.message,
    cf.category,
    g.title::TEXT as related_goal_title,
    cf.created_at::TIMESTAMPTZ,
    cf.sentiment_score
  FROM continuous_feedback cf
  JOIN employees f ON cf.from_employee_id = f.id
  LEFT JOIN goals g ON cf.related_goal_id = g.id
  WHERE cf.tenant_id = p_tenant_id
    AND cf.to_employee_id = p_employee_id
    AND (p_start_date IS NULL OR cf.created_at >= p_start_date)
    AND (p_end_date IS NULL OR cf.created_at <= p_end_date)
  ORDER BY cf.created_at DESC;
END;
$$;


--
-- Name: FUNCTION fn_get_feedback_for_review(p_tenant_id uuid, p_employee_id uuid, p_start_date date, p_end_date date); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.fn_get_feedback_for_review(p_tenant_id uuid, p_employee_id uuid, p_start_date date, p_end_date date) IS 'Get all continuous feedback for an employee within a date range (for performance review aggregation)';


--
-- Name: fn_get_onet_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_get_onet_stats() RETURNS TABLE(occupations_total bigint, occupations_with_embeddings bigint, skills_total bigint, skills_mapped_to_esco bigint, abilities_total bigint, knowledge_total bigint, work_activities_total bigint, occupation_skill_links bigint, last_import_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        (SELECT COUNT(*) FROM onet_occupations),
        0::BIGINT,
        (SELECT COUNT(*) FROM onet_skills),
        (SELECT COUNT(*) FROM onet_skills WHERE esco_skill_id IS NOT NULL),
        (SELECT COUNT(*) FROM onet_abilities),
        (SELECT COUNT(*) FROM onet_knowledge),
        (SELECT COUNT(*) FROM onet_work_activities),
        (SELECT COUNT(*) FROM onet_occupation_skills),
        (SELECT MAX(completed_at) FROM onet_import_jobs WHERE status = 'completed');
END;
$$;


--
-- Name: fn_get_review_period_goals(uuid, uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_get_review_period_goals(p_tenant_id uuid, p_employee_id uuid, p_period_start date, p_period_end date) RETURNS TABLE(goal_id uuid, title character varying, description text, goal_type character varying, start_date date, due_date date, status character varying, progress_percent integer, weight numeric, category character varying, parent_goal_id uuid, parent_goal_title character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    g.id as goal_id,
    g.title,
    g.description,
    g.goal_type,
    g.start_date,
    g.due_date,
    g.status,
    g.progress_percent,
    g.weight,
    g.category,
    g.parent_goal_id,
    pg.title as parent_goal_title
  FROM goals g
  LEFT JOIN goals pg ON g.parent_goal_id = pg.id
  WHERE g.tenant_id = p_tenant_id
    AND g.employee_id = p_employee_id
    AND (
      -- Goals that overlap with the review period
      (g.start_date <= p_period_end AND COALESCE(g.due_date, p_period_end) >= p_period_start)
      OR
      -- Goals due within the review period
      (g.due_date BETWEEN p_period_start AND p_period_end)
    )
  ORDER BY g.due_date, g.weight DESC, g.title;
END;
$$;


--
-- Name: FUNCTION fn_get_review_period_goals(p_tenant_id uuid, p_employee_id uuid, p_period_start date, p_period_end date); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.fn_get_review_period_goals(p_tenant_id uuid, p_employee_id uuid, p_period_start date, p_period_end date) IS 'Returns all goals for an employee that fall within a performance review period';


--
-- Name: fn_identify_360_peers(uuid, uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_identify_360_peers(p_tenant_id uuid, p_employee_id uuid, p_review_cycle_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 10) RETURNS TABLE(peer_id uuid, peer_name text, peer_department text, relationship_type character varying, confidence_score numeric, reason text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  WITH employee_info AS (
    SELECT org_unit_id, manager_id, job_title FROM employees WHERE id = p_employee_id
  ),
  -- Direct reports
  direct_reports AS (
    SELECT
      e.id as peer_id,
      e.first_name || ' ' || e.last_name as peer_name,
      d.name as department_name,
      'direct_report'::VARCHAR as rel_type,
      0.95::NUMERIC as score,
      'Direct report'::TEXT as reason
    FROM employees e
    LEFT JOIN org_units d ON e.org_unit_id = d.id
    WHERE e.manager_id = p_employee_id AND e.tenant_id = p_tenant_id AND e.is_active = true
    LIMIT 5
  ),
  -- Same department peers
  department_peers AS (
    SELECT
      e.id as peer_id,
      e.first_name || ' ' || e.last_name as peer_name,
      d.name as department_name,
      'peer'::VARCHAR as rel_type,
      0.80::NUMERIC as score,
      'Same department'::TEXT as reason
    FROM employees e
    JOIN employee_info ei ON e.org_unit_id = ei.org_unit_id
    LEFT JOIN org_units d ON e.org_unit_id = d.id
    WHERE e.id != p_employee_id AND e.tenant_id = p_tenant_id AND e.is_active = true
    LIMIT 5
  ),
  -- Project collaborators (from goals with same parent)
  project_peers AS (
    SELECT DISTINCT
      g2.employee_id as peer_id,
      e.first_name || ' ' || e.last_name as peer_name,
      d.name as department_name,
      'cross_functional'::VARCHAR as rel_type,
      0.70::NUMERIC as score,
      'Goal collaboration'::TEXT as reason
    FROM goals g1
    JOIN goals g2 ON g1.parent_goal_id = g2.parent_goal_id AND g1.employee_id != g2.employee_id
    JOIN employees e ON g2.employee_id = e.id
    LEFT JOIN org_units d ON e.org_unit_id = d.id
    WHERE g1.employee_id = p_employee_id
      AND g1.tenant_id = p_tenant_id
      AND e.is_active = true
    LIMIT 5
  ),
  -- Manager
  manager AS (
    SELECT
      ei.manager_id as peer_id,
      e.first_name || ' ' || e.last_name as peer_name,
      d.name as department_name,
      'manager'::VARCHAR as rel_type,
      1.0::NUMERIC as score,
      'Direct manager'::TEXT as reason
    FROM employee_info ei
    JOIN employees e ON ei.manager_id = e.id
    LEFT JOIN org_units d ON e.org_unit_id = d.id
    WHERE ei.manager_id IS NOT NULL
  )
  SELECT * FROM manager
  UNION ALL
  SELECT * FROM direct_reports
  UNION ALL
  SELECT * FROM department_peers
  UNION ALL
  SELECT * FROM project_peers
  ORDER BY score DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: fn_link_performance_to_skills(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_link_performance_to_skills(p_tenant_id uuid, p_performance_review_id uuid) RETURNS TABLE(competencies_processed integer, low_ratings_found integer, skills_linked integer, gap_analyses_triggered integer)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_employee_id UUID;
  v_section JSONB;
  v_competency JSONB;
  v_processed INTEGER := 0;
  v_low INTEGER := 0;
  v_linked INTEGER := 0;
  v_gaps INTEGER := 0;
  v_skill_id UUID;
  v_rating NUMERIC;
  v_rating_level VARCHAR(20);
BEGIN
  -- Get employee ID from the review
  SELECT employee_id INTO v_employee_id
  FROM performance_reviews
  WHERE id = p_performance_review_id AND tenant_id = p_tenant_id;

  IF v_employee_id IS NULL THEN
    RAISE EXCEPTION 'Performance review not found';
  END IF;

  -- Process section_ratings JSONB (competencies are typically stored here)
  FOR v_section IN
    SELECT jsonb_array_elements(section_ratings)
    FROM performance_reviews
    WHERE id = p_performance_review_id
  LOOP
    v_processed := v_processed + 1;

    -- Extract rating and name
    v_rating := (v_section->>'rating')::NUMERIC;

    -- Determine rating level
    v_rating_level := CASE
      WHEN v_rating <= 2 THEN 'low'
      WHEN v_rating <= 3.5 THEN 'medium'
      ELSE 'high'
    END;

    -- Try to find matching skill in ESCO
    SELECT id INTO v_skill_id
    FROM esco_skills
    WHERE LOWER(preferred_label_en) = LOWER(v_section->>'name')
      OR LOWER(preferred_label_en) LIKE '%' || LOWER(v_section->>'name') || '%'
    LIMIT 1;

    -- Insert link
    INSERT INTO performance_skill_links (
      tenant_id,
      performance_review_id,
      employee_id,
      competency_name,
      competency_rating,
      rating_level,
      linked_skill_id,
      recommended_actions
    ) VALUES (
      p_tenant_id,
      p_performance_review_id,
      v_employee_id,
      v_section->>'name',
      v_rating,
      v_rating_level,
      v_skill_id,
      CASE WHEN v_rating_level = 'low' THEN
        jsonb_build_array(
          jsonb_build_object(
            'type', 'training',
            'priority', 'high',
            'description', 'Enroll in training for ' || (v_section->>'name')
          ),
          jsonb_build_object(
            'type', 'mentoring',
            'priority', 'medium',
            'description', 'Find mentor with expertise in ' || (v_section->>'name')
          )
        )
      ELSE '[]'::JSONB END
    )
    ON CONFLICT (performance_review_id, competency_name) DO UPDATE SET
      competency_rating = EXCLUDED.competency_rating,
      rating_level = EXCLUDED.rating_level,
      linked_skill_id = EXCLUDED.linked_skill_id,
      recommended_actions = EXCLUDED.recommended_actions;

    IF v_skill_id IS NOT NULL THEN
      v_linked := v_linked + 1;
    END IF;

    IF v_rating_level = 'low' THEN
      v_low := v_low + 1;
    END IF;
  END LOOP;

  competencies_processed := v_processed;
  low_ratings_found := v_low;
  skills_linked := v_linked;
  gap_analyses_triggered := v_gaps;

  RETURN NEXT;
END;
$$;


--
-- Name: fn_log_calibration_action(uuid, uuid, uuid, character varying, uuid, jsonb, jsonb, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_log_calibration_action(p_tenant_id uuid, p_session_id uuid, p_adjustment_id uuid, p_action_type character varying, p_action_by uuid, p_old_value jsonb, p_new_value jsonb, p_description text) RETURNS uuid
    LANGUAGE plpgsql
