--
-- Name: fn_occupation_similarity(character varying, double precision, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_occupation_similarity(p_occupation_uri character varying, p_threshold double precision DEFAULT 0.5, p_limit integer DEFAULT 20) RETURNS TABLE(occupation_id uuid, uri character varying, preferred_label character varying, isco_code character varying, embedding_similarity double precision, skill_overlap_jaccard double precision, combined_score double precision)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    WITH source AS (
        SELECT o.id, o.embedding_en
        FROM esco_occupations o WHERE o.uri = p_occupation_uri
    ),
    source_skills AS (
        SELECT os.skill_id
        FROM esco_occupation_skills os
        JOIN source s ON s.id = os.occupation_id
        WHERE os.relation_type = 'essential'
    ),
    candidates AS (
        SELECT o.id, o.uri, o.preferred_label_en, o.isco_code,
               (1 - (o.embedding_en <=> s.embedding_en))::FLOAT AS emb_sim
        FROM esco_occupations o, source s
        WHERE o.id != s.id
          AND o.embedding_en IS NOT NULL
          AND (1 - (o.embedding_en <=> s.embedding_en)) >= p_threshold
        ORDER BY o.embedding_en <=> s.embedding_en
        LIMIT p_limit * 2  -- fetch extra for re-ranking
    ),
    with_jaccard AS (
        SELECT c.*,
            COALESCE(
                (SELECT count(*)::FLOAT /
                        NULLIF((SELECT count(DISTINCT skill_id)
                                FROM esco_occupation_skills
                                WHERE occupation_id IN (c.id, (SELECT id FROM source))
                                  AND relation_type = 'essential'), 0)
                 FROM esco_occupation_skills os1
                 WHERE os1.occupation_id = c.id
                   AND os1.relation_type = 'essential'
                   AND os1.skill_id IN (SELECT skill_id FROM source_skills)
                ), 0.0
            ) AS jaccard
        FROM candidates c
    )
    SELECT wj.id, wj.uri, wj.preferred_label_en, wj.isco_code,
           wj.emb_sim, wj.jaccard,
           (wj.emb_sim * 0.4 + wj.jaccard * 0.6)::FLOAT  -- weighted: skill overlap matters more
    FROM with_jaccard wj
    ORDER BY (wj.emb_sim * 0.4 + wj.jaccard * 0.6) DESC
    LIMIT p_limit;
END;
$$;


--
-- Name: fn_queue_embedding(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_queue_embedding() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_entity_type VARCHAR(50);
    v_tenant_id UUID;
    v_operation VARCHAR(20);
BEGIN
    -- Determine entity type from table name
    v_entity_type := TG_ARGV[0];

    -- Determine operation
    IF TG_OP = 'DELETE' THEN
        v_operation := 'delete';
        v_tenant_id := OLD.tenant_id;

        -- Insert delete operation
        INSERT INTO embedding_queue (entity_type, entity_id, tenant_id, operation, priority)
        VALUES (v_entity_type, OLD.id, v_tenant_id, v_operation, 3)
        ON CONFLICT (entity_type, entity_id, status)
        DO UPDATE SET
            operation = 'delete',
            created_at = NOW(),
            attempts = 0,
            error_message = NULL;

        RETURN OLD;
    ELSE
        v_operation := 'upsert';
        v_tenant_id := NEW.tenant_id;

        -- Insert or update queue entry
        INSERT INTO embedding_queue (entity_type, entity_id, tenant_id, operation, priority)
        VALUES (v_entity_type, NEW.id, v_tenant_id, v_operation, 5)
        ON CONFLICT (entity_type, entity_id, status)
        DO UPDATE SET
            operation = 'upsert',
            created_at = NOW(),
            attempts = 0,
            error_message = NULL
        WHERE embedding_queue.status = 'pending';

        RETURN NEW;
    END IF;
END;
$$;


--
-- Name: fn_queue_employee_sync(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_queue_employee_sync() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Only queue if employee has pernr (linked to SAP)
    IF NEW.pernr IS NOT NULL THEN
        INSERT INTO sync_queue (entity_type, entity_id, tenant_id, operation)
        VALUES (
            'employee',
            NEW.id,
            NEW.tenant_id,
            CASE
                WHEN TG_OP = 'INSERT' THEN 'create'
                WHEN TG_OP = 'UPDATE' THEN 'update'
                ELSE 'update'
            END
        )
        ON CONFLICT DO NOTHING;
    END IF;
    RETURN NEW;
END;
$$;


