--
-- Name: fn_skill_gap_analysis(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_skill_gap_analysis(p_employee_id uuid, p_target_occupation_uri character varying) RETURNS TABLE(missing_skill_id uuid, missing_skill_label character varying, skill_type character varying, relation_type character varying, closest_existing_skill character varying, transferability double precision, gap_difficulty character varying)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    WITH emp_skills AS (
        SELECT es.esco_skill_id, sk.preferred_label_en, sk.embedding_en
        FROM employee_skills es
        JOIN esco_skills sk ON sk.id = es.esco_skill_id
        WHERE es.employee_id = p_employee_id
    ),
    target_skills AS (
        SELECT s.id, s.preferred_label_en, s.skill_type, os.relation_type, s.embedding_en
        FROM esco_occupation_skills os
        JOIN esco_skills s ON s.id = os.skill_id
        JOIN esco_occupations o ON o.id = os.occupation_id
        WHERE o.uri = p_target_occupation_uri
    ),
    gap AS (
        SELECT
            ts.id,
            ts.preferred_label_en,
            ts.skill_type,
            ts.relation_type,
            (SELECT es.preferred_label_en
             FROM emp_skills es
             ORDER BY es.embedding_en <=> ts.embedding_en LIMIT 1
            ) AS closest_label,
            COALESCE(
                (SELECT (1 - (ts.embedding_en <=> es.embedding_en))::FLOAT
                 FROM emp_skills es
                 ORDER BY es.embedding_en <=> ts.embedding_en LIMIT 1),
                0.0
            ) AS transfer_score
        FROM target_skills ts
        WHERE ts.id NOT IN (SELECT esco_skill_id FROM emp_skills)
    )
    SELECT
        g.id,
        g.preferred_label_en,
        g.skill_type,
        g.relation_type,
        g.closest_label,
        g.transfer_score,
        CASE
            WHEN g.transfer_score >= 0.5 THEN 'easy'
            WHEN g.transfer_score >= 0.35 THEN 'moderate'
            ELSE 'hard'
        END::VARCHAR(20)
    FROM gap g
    ORDER BY
        CASE g.relation_type WHEN 'essential' THEN 0 ELSE 1 END,
        g.transfer_score ASC;
END;
$$;


--
-- Name: fn_suggest_esco_for_text(character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_suggest_esco_for_text(p_text character varying, p_language character varying DEFAULT 'en'::character varying, p_limit integer DEFAULT 10) RETURNS TABLE(skill_id uuid, preferred_label character varying, skill_type character varying, relevance double precision)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_proxy_embedding vector(1536);
BEGIN
    -- Use pg_trgm to find closest skill label, then use its embedding
    IF p_language = 'it' THEN
        SELECT s.embedding_it INTO v_proxy_embedding
        FROM esco_skills s
        WHERE s.embedding_it IS NOT NULL
        ORDER BY s.preferred_label_it <-> p_text
        LIMIT 1;

        RETURN QUERY
        SELECT s.id, s.preferred_label_it, s.skill_type,
               (1 - (s.embedding_it <=> v_proxy_embedding))::FLOAT
        FROM esco_skills s
        WHERE s.embedding_it IS NOT NULL
        ORDER BY s.embedding_it <=> v_proxy_embedding
        LIMIT p_limit;
    ELSE
        SELECT s.embedding_en INTO v_proxy_embedding
        FROM esco_skills s
        WHERE s.embedding_en IS NOT NULL
        ORDER BY s.preferred_label_en <-> p_text
        LIMIT 1;

        RETURN QUERY
        SELECT s.id, s.preferred_label_en, s.skill_type,
               (1 - (s.embedding_en <=> v_proxy_embedding))::FLOAT
        FROM esco_skills s
        WHERE s.embedding_en IS NOT NULL
        ORDER BY s.embedding_en <=> v_proxy_embedding
        LIMIT p_limit;
    END IF;
END;
$$;


--
-- Name: fn_trigger_gap_analysis_for_low_ratings(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_trigger_gap_analysis_for_low_ratings(p_tenant_id uuid, p_employee_id uuid) RETURNS TABLE(gap_analysis_id uuid, skill_gaps_count integer, priority_skills jsonb)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_gap_id UUID;
  v_gaps JSONB := '[]'::JSONB;
  v_priority JSONB := '[]'::JSONB;
  v_gap_count INTEGER := 0;
  v_link RECORD;
BEGIN
  -- Get all low-rated competencies for this employee
  FOR v_link IN
    SELECT
      psl.competency_name,
      psl.competency_rating,
      psl.linked_skill_id,
      es.preferred_label_en as skill_name,
      esp.composite_score as current_level
    FROM performance_skill_links psl
    LEFT JOIN esco_skills es ON psl.linked_skill_id = es.id
    LEFT JOIN employee_skill_profiles esp ON esp.employee_id = psl.employee_id AND esp.skill_id = psl.linked_skill_id
    WHERE psl.tenant_id = p_tenant_id
      AND psl.employee_id = p_employee_id
      AND psl.rating_level = 'low'
      AND psl.is_addressed = false
  LOOP
    v_gap_count := v_gap_count + 1;

    v_gaps := v_gaps || jsonb_build_object(
      'skill_name', COALESCE(v_link.skill_name, v_link.competency_name),
      'skill_id', v_link.linked_skill_id,
      'current_level', COALESCE(v_link.current_level, v_link.competency_rating),
      'target_level', 3.5,
      'gap_size', 3.5 - COALESCE(v_link.current_level, v_link.competency_rating),
      'priority', 'high',
      'source', 'performance_review'
    );

    v_priority := v_priority || jsonb_build_object(
      'skill_name', COALESCE(v_link.skill_name, v_link.competency_name),
      'urgency', 'immediate',
      'development_time', '3-6 months'
    );
  END LOOP;

  IF v_gap_count > 0 THEN
    -- Create gap analysis record
    INSERT INTO skill_gap_analyses (
      tenant_id,
      analysis_name,
      analysis_type,
      target_entity_type,
      target_entity_id,
      analysis_date,
      skill_gaps,
      priority_skills,
      recommendations,
      created_by
    ) VALUES (
      p_tenant_id,
      'Performance-Based Gap Analysis - ' || to_char(NOW(), 'YYYY-MM-DD'),
      'performance_triggered',
      'employee',
      p_employee_id,
      CURRENT_DATE,
      v_gaps,
      v_priority,
      jsonb_build_array(
        jsonb_build_object(
          'type', 'training',
          'description', 'Complete identified training within 3 months'
        ),
        jsonb_build_object(
          'type', 'mentoring',
          'description', 'Establish mentorship relationship within 2 weeks'
        ),
        jsonb_build_object(
          'type', 'project',
          'description', 'Apply skills in stretch assignment'
        )
      ),
      NULL  -- created_by is NULL since function runs without user context
    )
    RETURNING id INTO v_gap_id;

    -- Update the links with the gap analysis ID
    UPDATE performance_skill_links
    SET linked_gap_analysis_id = v_gap_id
    WHERE tenant_id = p_tenant_id
      AND employee_id = p_employee_id
      AND rating_level = 'low'
      AND is_addressed = false;
  END IF;

  gap_analysis_id := v_gap_id;
  skill_gaps_count := v_gap_count;
  priority_skills := v_priority;

  RETURN NEXT;
END;
$$;


