--
-- Name: generate_codice_fiscale(text, text, date, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_codice_fiscale(p_cognome text, p_nome text, p_data_nascita date, p_sesso text, p_comune_codice text DEFAULT 'F205'::text) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_cognome_cf TEXT;
    v_nome_cf TEXT;
    v_anno TEXT;
    v_mese TEXT;
    v_giorno TEXT;
    v_cf TEXT;
    v_consonanti TEXT;
    v_vocali TEXT;
    v_mesi TEXT[] := ARRAY['A','B','C','D','E','H','L','M','P','R','S','T'];
BEGIN
    v_consonanti := regexp_replace(UPPER(p_cognome), '[^BCDFGHJKLMNPQRSTVWXYZ]', '', 'g');
    v_vocali := regexp_replace(UPPER(p_cognome), '[^AEIOU]', '', 'g');
    v_cognome_cf := LEFT(v_consonanti || v_vocali || 'XXX', 3);
    
    v_consonanti := regexp_replace(UPPER(p_nome), '[^BCDFGHJKLMNPQRSTVWXYZ]', '', 'g');
    v_vocali := regexp_replace(UPPER(p_nome), '[^AEIOU]', '', 'g');
    IF LENGTH(v_consonanti) >= 4 THEN
        v_nome_cf := SUBSTRING(v_consonanti, 1, 1) || SUBSTRING(v_consonanti, 3, 2);
    ELSE
        v_nome_cf := LEFT(v_consonanti || v_vocali || 'XXX', 3);
    END IF;
    
    v_anno := RIGHT(EXTRACT(YEAR FROM p_data_nascita)::TEXT, 2);
    v_mese := v_mesi[EXTRACT(MONTH FROM p_data_nascita)::INT];
    
    IF UPPER(p_sesso) IN ('F', 'FEMALE') THEN
        v_giorno := LPAD((EXTRACT(DAY FROM p_data_nascita) + 40)::TEXT, 2, '0');
    ELSE
        v_giorno := LPAD(EXTRACT(DAY FROM p_data_nascita)::TEXT, 2, '0');
    END IF;
    
    v_cf := v_cognome_cf || v_nome_cf || v_anno || v_mese || v_giorno || p_comune_codice;
    v_cf := v_cf || CHR(65 + (ASCII(SUBSTRING(v_cf, 1, 1)) % 26));
    
    RETURN v_cf;
END;
$$;


--
-- Name: generate_italian_iban(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_italian_iban(p_seed integer DEFAULT 0) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_abi TEXT[] := ARRAY['03069', '02008', '01005', '05034', '03015', '05428', '03268', '01030'];
    v_cab TEXT[] := ARRAY['09606', '01600', '01000', '01601', '01602', '11101', '01603', '01604'];
    v_cin TEXT[] := ARRAY['X', 'Y', 'Z', 'W', 'V', 'U', 'T', 'S'];
    v_account TEXT;
BEGIN
    v_account := LPAD((1000000000 + (p_seed * 7919) % 900000000)::TEXT, 12, '0');
    RETURN 'IT' || LPAD((60 + (p_seed % 40))::TEXT, 2, '0') || 
           v_cin[1 + (p_seed % 8)] || v_abi[1 + (p_seed % 8)] || 
           v_cab[1 + (p_seed % 8)] || v_account;
END;
$$;


--
-- Name: generate_italian_mobile(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_italian_mobile(p_seed integer DEFAULT 0) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_prefixes TEXT[] := ARRAY['320','327','328','329','330','331','333','335','338','339','340','345','347','348','349','350','351','366','368','380','388','389'];
    v_number TEXT;
BEGIN
    v_number := LPAD((1000000 + (p_seed * 3571) % 9000000)::TEXT, 7, '0');
    RETURN '+39 ' || v_prefixes[1 + (p_seed % 22)] || ' ' || SUBSTRING(v_number, 1, 3) || ' ' || SUBSTRING(v_number, 4, 4);
END;
$$;


--
-- Name: generate_pernr(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_pernr(p_bukrs character varying) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_max_pernr INTEGER;
    v_new_pernr VARCHAR(8);
    v_prefix VARCHAR(2);
BEGIN
    -- Get prefix based on company code (first 2 chars)
    v_prefix := SUBSTRING(p_bukrs FROM 1 FOR 2);

    -- Find max PERNR for this company
    SELECT COALESCE(MAX(CAST(SUBSTRING(pernr FROM 3) AS INTEGER)), 0)
    INTO v_max_pernr
    FROM user_pernr_mapping
    WHERE bukrs = p_bukrs;

    -- Generate new PERNR: XX + 6-digit sequence
    v_new_pernr := v_prefix || LPAD((v_max_pernr + 1)::TEXT, 6, '0');

    RETURN v_new_pernr;
END;
$$;


--
-- Name: generate_profile_code(character, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_profile_code(p_section_code character, p_division_code character varying, p_group_code character varying, p_size_code character varying) RETURNS character varying
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_group_suffix VARCHAR(2);
BEGIN
    -- Extract group suffix (e.g., "01.1" -> "1", "25.62" -> "62")
    v_group_suffix := SUBSTRING(p_group_code FROM POSITION('.' IN p_group_code) + 1);

    -- Generate code: A01.1MI format
    RETURN p_section_code || p_division_code || '.' || v_group_suffix || p_size_code;
END;
$$;


