--
-- Name: get_ai_cost_summary(character varying, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_ai_cost_summary(p_provider character varying DEFAULT NULL::character varying, p_since timestamp with time zone DEFAULT (now() - '30 days'::interval)) RETURNS TABLE(provider character varying, total_requests bigint, total_tokens bigint, total_cost numeric, avg_latency_ms numeric, success_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        aul.provider,
        COUNT(*)::BIGINT as total_requests,
        COALESCE(SUM(aul.total_tokens), 0)::BIGINT as total_tokens,
        COALESCE(SUM(aul.cost), 0)::DECIMAL(10, 6) as total_cost,
        COALESCE(AVG(aul.latency_ms), 0)::DECIMAL(10, 2) as avg_latency_ms,
        COALESCE(
            ROUND(SUM(CASE WHEN aul.success THEN 1 ELSE 0 END)::DECIMAL / NULLIF(COUNT(*), 0) * 100, 2),
            0
        )::DECIMAL(5, 2) as success_rate
    FROM ai_usage_log aul
    WHERE aul.created_at >= p_since
      AND (p_provider IS NULL OR aul.provider = p_provider)
    GROUP BY aul.provider
    ORDER BY total_cost DESC;
END;
$$;


--
-- Name: get_all_subordinates(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_all_subordinates(p_manager_id uuid) RETURNS TABLE(employee_id uuid, employee_name text, employee_role character varying, depth integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH RECURSIVE subordinates AS (
        -- Direct reports
        SELECT
            e.id,
            e.first_name || ' ' || e.last_name as full_name,
            e.auth_role,
            1 as level
        FROM employees e
        WHERE e.manager_id = p_manager_id
        AND e.is_active = true

        UNION ALL

        -- Indirect reports
        SELECT
            e.id,
            e.first_name || ' ' || e.last_name,
            e.auth_role,
            s.level + 1
        FROM employees e
        JOIN subordinates s ON e.manager_id = s.id
        WHERE e.is_active = true
        AND s.level < 10  -- Prevent infinite recursion
    )
    SELECT id, full_name, auth_role, level
    FROM subordinates
    ORDER BY level, full_name;
END;
$$;


--
-- Name: FUNCTION get_all_subordinates(p_manager_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_all_subordinates(p_manager_id uuid) IS 'Returns all direct and indirect subordinates of a manager';


--
-- Name: get_career_path_adjacent_skills(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_career_path_adjacent_skills(p_skill_id uuid, p_limit integer DEFAULT 10) RETURNS TABLE(adjacent_skill_id uuid, adjacent_skill_label character varying, adjacency_score numeric, adjacency_type character varying, primary_category character varying, cognitive_level integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        sa.adjacent_skill_id,
        es.preferred_label,
        sa.adjacency_score,
        sa.adjacency_type,
        sc.primary_category,
        sc.cognitive_level
    FROM skill_adjacencies sa
    INNER JOIN esco_skills es ON sa.adjacent_skill_id = es.id
    LEFT JOIN skill_classifications sc ON es.id = sc.esco_skill_id
    WHERE sa.skill_id = p_skill_id
    ORDER BY sa.adjacency_score DESC
    LIMIT p_limit;
END;
$$;


--
-- Name: get_cluster_skills(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cluster_skills(p_cluster_id uuid) RETURNS TABLE(skill_id uuid, preferred_label character varying, primary_category character varying, cognitive_level integer, cluster_code character varying, cluster_name character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH RECURSIVE cluster_tree AS (
        SELECT id, code, name_en
        FROM skill_clusters
        WHERE id = p_cluster_id

        UNION ALL

        SELECT skc.id, skc.code, skc.name_en
        FROM skill_clusters skc
        INNER JOIN cluster_tree ct ON skc.parent_cluster_id = ct.id
    )
    SELECT
        es.id,
        es.preferred_label,
        sc.primary_category,
        sc.cognitive_level,
        ct.code,
        ct.name_en
    FROM esco_skills es
    INNER JOIN skill_classifications sc ON es.id = sc.esco_skill_id
    INNER JOIN cluster_tree ct ON sc.skill_cluster_id = ct.id;
END;
$$;


--
-- Name: get_cognitive_level_label(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cognitive_level_label(level integer) RETURNS character varying
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
    RETURN CASE level
        WHEN 1 THEN 'Remember/Understand'
        WHEN 2 THEN 'Apply'
        WHEN 3 THEN 'Analyze/Evaluate'
        WHEN 4 THEN 'Create'
        ELSE NULL
    END;
END;
$$;


--
-- Name: get_employee_permissions(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_employee_permissions(p_employee_id uuid) RETURNS TABLE(permission_code character varying, scope public.permission_scope, source character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_role VARCHAR;
BEGIN
    -- Get employee's role
    SELECT auth_role INTO v_role FROM employees WHERE id = p_employee_id;

    IF v_role IS NULL THEN
        v_role := 'EMPLOYEE';
    END IF;

    -- Return role-based permissions
    RETURN QUERY
    SELECT
        p.code::VARCHAR,
        rp.scope,
        'role'::VARCHAR as source
    FROM role_permissions rp
    JOIN permissions p ON rp.permission_id = p.id
    WHERE rp.role::TEXT = v_role
    AND p.is_active = true

    UNION ALL

    -- Return custom granted overrides
    SELECT
        p.code::VARCHAR,
        COALESCE(epo.scope, p.default_scope),
        'override'::VARCHAR as source
    FROM employee_permission_overrides epo
    JOIN permissions p ON epo.permission_id = p.id
    WHERE epo.employee_id = p_employee_id
    AND epo.is_granted = true
    AND p.is_active = true
    AND (epo.expires_at IS NULL OR epo.expires_at > now())

    EXCEPT

    -- Remove revoked permissions
    SELECT
        p.code::VARCHAR,
        rp.scope,
        'role'::VARCHAR
    FROM employee_permission_overrides epo
    JOIN permissions p ON epo.permission_id = p.id
    JOIN role_permissions rp ON rp.permission_id = p.id AND rp.role::TEXT = v_role
    WHERE epo.employee_id = p_employee_id
    AND epo.is_granted = false
    AND (epo.expires_at IS NULL OR epo.expires_at > now());
END;
$$;


--
-- Name: FUNCTION get_employee_permissions(p_employee_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_employee_permissions(p_employee_id uuid) IS 'Returns effective permissions for an employee (role-based + overrides)';


--
-- Name: get_manager_chain(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_manager_chain(p_employee_id uuid) RETURNS TABLE(level integer, manager_id uuid, manager_name text, manager_role character varying, manager_title character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_current_id UUID;
    v_level INTEGER := 0;
    v_visited UUID[] := ARRAY[]::UUID[];
BEGIN
    v_current_id := (SELECT e.manager_id FROM employees e WHERE e.id = p_employee_id);

    WHILE v_current_id IS NOT NULL AND v_level < 20 LOOP
        -- Cycle detection
        IF v_current_id = ANY(v_visited) THEN
            EXIT;
        END IF;

        v_visited := v_visited || v_current_id;
        v_level := v_level + 1;

        RETURN QUERY
        SELECT
            v_level,
            e.id,
            e.first_name || ' ' || e.last_name,
            e.auth_role,
            e.job_title
        FROM employees e
        WHERE e.id = v_current_id;

        v_current_id := (SELECT e.manager_id FROM employees e WHERE e.id = v_current_id);
    END LOOP;
END;
$$;


--
-- Name: FUNCTION get_manager_chain(p_employee_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_manager_chain(p_employee_id uuid) IS 'Returns the complete reporting chain for an employee';


