--
-- Name: get_session_hierarchy_stats(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_session_hierarchy_stats(p_session_id uuid) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_stats JSONB;
BEGIN
    SELECT jsonb_build_object(
        'total_employees', COUNT(*),
        'by_level', jsonb_object_agg(
            COALESCE(hierarchy_level::text, 'unassigned'),
            level_count
        ),
        'by_change_type', jsonb_object_agg(
            change_type,
            type_count
        ),
        'approved_count', SUM(CASE WHEN is_approved THEN 1 ELSE 0 END),
        'pending_count', SUM(CASE WHEN NOT is_approved THEN 1 ELSE 0 END)
    ) INTO v_stats
    FROM (
        SELECT
            hierarchy_level,
            change_type,
            is_approved,
            COUNT(*) OVER (PARTITION BY hierarchy_level) as level_count,
            COUNT(*) OVER (PARTITION BY change_type) as type_count
        FROM employees_staging
        WHERE session_id = p_session_id
    ) sub;

    RETURN COALESCE(v_stats, '{}'::jsonb);
END;
$$;


--
-- Name: get_skill_relationships_graph(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_skill_relationships_graph(p_skill_id uuid, p_depth integer DEFAULT 2) RETURNS TABLE(source_id uuid, source_label character varying, target_id uuid, target_label character varying, relationship_type character varying, relationship_strength numeric, depth integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH RECURSIVE skill_graph AS (
        -- Base case: direct relationships
        SELECT
            sr.source_skill_id,
            es1.preferred_label AS source_label,
            sr.target_skill_id,
            es2.preferred_label AS target_label,
            sr.relationship_type,
            sr.relationship_strength,
            1 AS depth
        FROM skill_relationships sr
        INNER JOIN esco_skills es1 ON sr.source_skill_id = es1.id
        INNER JOIN esco_skills es2 ON sr.target_skill_id = es2.id
        WHERE sr.source_skill_id = p_skill_id OR sr.target_skill_id = p_skill_id

        UNION

        -- Recursive case: relationships of related skills
        SELECT
            sr.source_skill_id,
            es1.preferred_label,
            sr.target_skill_id,
            es2.preferred_label,
            sr.relationship_type,
            sr.relationship_strength,
            sg.depth + 1
        FROM skill_relationships sr
        INNER JOIN esco_skills es1 ON sr.source_skill_id = es1.id
        INNER JOIN esco_skills es2 ON sr.target_skill_id = es2.id
        INNER JOIN skill_graph sg ON (sr.source_skill_id = sg.target_id OR sr.target_skill_id = sg.source_id)
        WHERE sg.depth < p_depth
    )
    SELECT DISTINCT * FROM skill_graph;
END;
$$;


