--
-- Name: get_trending_skills(character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_trending_skills(p_country_code character varying DEFAULT NULL::character varying, p_industry character varying DEFAULT NULL::character varying, p_days integer DEFAULT 30) RETURNS TABLE(skill_uri character varying, skill_name character varying, current_demand integer, previous_demand integer, growth_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH current_period AS (
        SELECT
            unnest(mapped_esco_skills::text[]) as skill,
            COUNT(*) as cnt
        FROM job_market_postings
        WHERE posting_date >= CURRENT_DATE - p_days
          AND (p_country_code IS NULL OR country_code = p_country_code)
          AND (p_industry IS NULL OR industry = p_industry)
        GROUP BY skill
    ),
    previous_period AS (
        SELECT
            unnest(mapped_esco_skills::text[]) as skill,
            COUNT(*) as cnt
        FROM job_market_postings
        WHERE posting_date >= CURRENT_DATE - (p_days * 2)
          AND posting_date < CURRENT_DATE - p_days
          AND (p_country_code IS NULL OR country_code = p_country_code)
          AND (p_industry IS NULL OR industry = p_industry)
        GROUP BY skill
    )
    SELECT
        c.skill::VARCHAR(500),
        COALESCE(es.preferred_label, c.skill)::VARCHAR(500),
        c.cnt::INTEGER,
        COALESCE(p.cnt, 0)::INTEGER,
        CASE
            WHEN COALESCE(p.cnt, 0) = 0 THEN 100.0
            ELSE ((c.cnt - COALESCE(p.cnt, 0))::DECIMAL / p.cnt * 100)
        END::DECIMAL(5,2)
    FROM current_period c
    LEFT JOIN previous_period p ON c.skill = p.skill
    LEFT JOIN esco_skills es ON es.esco_uri = c.skill
    ORDER BY
        CASE
            WHEN COALESCE(p.cnt, 0) = 0 THEN 100.0
            ELSE ((c.cnt - COALESCE(p.cnt, 0))::DECIMAL / p.cnt * 100)
        END DESC
    LIMIT 20;
END;
$$;


--
-- Name: is_employee_in_scope(uuid, uuid, public.permission_scope); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_employee_in_scope(p_requesting_employee_id uuid, p_target_employee_id uuid, p_scope public.permission_scope) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_requester_dept_id UUID;
    v_target_dept_id UUID;
    v_requester_tenant_id UUID;
    v_target_tenant_id UUID;
    v_is_dept_head BOOLEAN;
BEGIN
    -- Own scope: only self
    IF p_scope = 'own' THEN
        RETURN p_requesting_employee_id = p_target_employee_id;
    END IF;

    -- Get requester and target info
    SELECT org_unit_id, tenant_id INTO v_requester_dept_id, v_requester_tenant_id
    FROM employees WHERE id = p_requesting_employee_id;

    SELECT org_unit_id, tenant_id INTO v_target_dept_id, v_target_tenant_id
    FROM employees WHERE id = p_target_employee_id;

    -- Platform scope: any employee (SYSADMIN only)
    IF p_scope = 'platform' THEN
        RETURN true;
    END IF;

    -- Tenant scope: same tenant only
    IF p_scope = 'tenant' THEN
        RETURN v_requester_tenant_id = v_target_tenant_id;
    END IF;

    -- Department scope: same department only
    IF p_scope = 'department' THEN
        RETURN v_requester_dept_id = v_target_dept_id
           AND v_requester_tenant_id = v_target_tenant_id;
    END IF;

    -- Team scope: direct reports only
    IF p_scope = 'team' THEN
        RETURN EXISTS (
            SELECT 1 FROM employees
            WHERE id = p_target_employee_id
            AND manager_id = p_requesting_employee_id
        ) OR p_requesting_employee_id = p_target_employee_id;
    END IF;

    RETURN false;
END;
$$;


