-- Name: log_ai_usage(character varying, character varying, character varying, integer, numeric, integer, boolean, text, uuid, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_ai_usage(p_provider character varying, p_model character varying, p_operation character varying, p_total_tokens integer, p_cost numeric, p_latency_ms integer, p_success boolean, p_error_message text DEFAULT NULL::text, p_tenant_id uuid DEFAULT NULL::uuid, p_user_id uuid DEFAULT NULL::uuid, p_metadata jsonb DEFAULT NULL::jsonb) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_id UUID;
BEGIN
    INSERT INTO ai_usage_log (
        provider, model, operation, total_tokens, cost, latency_ms,
        success, error_message, tenant_id, user_id, request_metadata
    ) VALUES (
        p_provider, p_model, p_operation, p_total_tokens, p_cost, p_latency_ms,
        p_success, p_error_message, p_tenant_id, p_user_id, p_metadata
    ) RETURNING id INTO v_id;

    RETURN v_id;
END;
$$;


--
-- Name: log_goal_update(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_goal_update() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF OLD.progress_percent IS DISTINCT FROM NEW.progress_percent OR OLD.status IS DISTINCT FROM NEW.status THEN
        INSERT INTO goal_updates (
            tenant_id, goal_id, update_type,
            previous_progress, new_progress,
            previous_status, new_status
        ) VALUES (
            NEW.tenant_id, NEW.id,
            CASE
                WHEN OLD.status IS DISTINCT FROM NEW.status THEN 'status_change'
                ELSE 'progress'
            END,
            OLD.progress_percent, NEW.progress_percent,
            OLD.status, NEW.status
        );
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: normalize_skill_pair(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.normalize_skill_pair(p_skill_id_1 uuid, p_skill_id_2 uuid) RETURNS TABLE(skill_1 uuid, skill_2 uuid)
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
    IF p_skill_id_1 < p_skill_id_2 THEN
        RETURN QUERY SELECT p_skill_id_1, p_skill_id_2;
    ELSE
        RETURN QUERY SELECT p_skill_id_2, p_skill_id_1;
    END IF;
END;
$$;


--
-- Name: publish_scheduled_articles(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.publish_scheduled_articles() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  updated_count INTEGER;
BEGIN
  UPDATE news_articles
  SET
    status = 'published',
    published_at = NOW(),
    updated_at = NOW()
  WHERE status = 'scheduled' AND publish_at <= NOW();

  GET DIAGNOSTICS updated_count = ROW_COUNT;
  RETURN updated_count;
END;
$$;


