--
-- Name: rbp_get_recursive_reports(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rbp_get_recursive_reports(manager_employee_id uuid) RETURNS TABLE(id uuid)
    LANGUAGE sql STABLE
    AS $$
    WITH RECURSIVE subordinates AS (
        SELECT e.id
        FROM employees e
        WHERE e.manager_id = manager_employee_id
          AND e.deleted_at IS NULL
        UNION ALL
        SELECT e.id
        FROM employees e
        INNER JOIN subordinates s ON e.manager_id = s.id
        WHERE e.deleted_at IS NULL
    )
    SELECT id FROM subordinates;
$$;


--
-- Name: rbp_get_user_effective_permissions(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rbp_get_user_effective_permissions(user_role_code text) RETURNS TABLE(functional_area_code text, can_view boolean, can_create boolean, can_edit boolean, can_delete boolean, can_approve boolean, can_export boolean, scope_type text)
    LANGUAGE sql STABLE
    AS $$
    WITH RECURSIVE role_chain AS (
        SELECT r.code, r.inherits_from, r.id
        FROM rbp_roles r
        WHERE r.code = user_role_code
        UNION ALL
        SELECT r.code, r.inherits_from, r.id
        FROM rbp_roles r
        INNER JOIN role_chain rc ON r.code = rc.inherits_from
    ),
    scope_order AS (
        SELECT fa.code AS fa_code,
               bool_or(rp.can_view) AS can_view,
               bool_or(rp.can_create) AS can_create,
               bool_or(rp.can_edit) AS can_edit,
               bool_or(rp.can_delete) AS can_delete,
               bool_or(rp.can_approve) AS can_approve,
               bool_or(rp.can_export) AS can_export,
               MIN(CASE rp.scope_type
                   WHEN 'PLATFORM' THEN 1
                   WHEN 'TENANT' THEN 2
                   WHEN 'DEPARTMENT' THEN 3
                   WHEN 'HIERARCHY' THEN 4
                   WHEN 'TEAM' THEN 5
                   WHEN 'SELF' THEN 6
                   ELSE 7
               END) AS scope_ord
        FROM role_chain rc
        JOIN rbp_role_permissions rp ON rp.role_id = rc.id
        JOIN rbp_functional_areas fa ON fa.id = rp.functional_area_id
        GROUP BY fa.code
    )
    SELECT fa_code,
           can_view, can_create, can_edit, can_delete, can_approve, can_export,
           CASE scope_ord
               WHEN 1 THEN 'PLATFORM'
               WHEN 2 THEN 'TENANT'
               WHEN 3 THEN 'DEPARTMENT'
               WHEN 4 THEN 'HIERARCHY'
               WHEN 5 THEN 'TEAM'
               WHEN 6 THEN 'SELF'
               ELSE 'SELF'
           END AS scope_type
    FROM scope_order
$$;


--
-- Name: rbp_get_user_effective_permissions(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rbp_get_user_effective_permissions(user_role_code character varying) RETURNS TABLE(functional_area_code character varying, can_view boolean, can_create boolean, can_edit boolean, can_delete boolean, can_approve boolean, can_export boolean, scope_type character varying)
    LANGUAGE sql STABLE
    AS $$
    WITH RECURSIVE role_chain AS (
        -- Base: direct role
        SELECT r.code, r.inherits_from, r.id
        FROM rbp_roles r
        WHERE r.code = user_role_code
        UNION ALL
        -- Recursive: inherited roles
        SELECT r.code, r.inherits_from, r.id
        FROM rbp_roles r
        INNER JOIN role_chain rc ON r.code = rc.inherits_from
    )
    SELECT
        fa.code AS functional_area_code,
        -- For each permission, take the most permissive across the chain (OR logic)
        bool_or(rp.can_view) AS can_view,
        bool_or(rp.can_create) AS can_create,
        bool_or(rp.can_edit) AS can_edit,
        bool_or(rp.can_delete) AS can_delete,
        bool_or(rp.can_approve) AS can_approve,
        bool_or(rp.can_export) AS can_export,
        -- For scope, take the widest (lowest ordinal: PLATFORM < TENANT < DEPARTMENT < HIERARCHY < SELF)
        MIN(rp.scope_type) AS scope_type
    FROM role_chain rc
    JOIN rbp_role_permissions rp ON rp.role_id = rc.id
    JOIN rbp_functional_areas fa ON fa.id = rp.functional_area_id
    GROUP BY fa.code;
$$;


