--
-- Name: record_skill_pair_usage(uuid, uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.record_skill_pair_usage(p_skill_id_1 uuid, p_skill_id_2 uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_context_type character varying DEFAULT 'employee_profile'::character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_skill_1 UUID;
    v_skill_2 UUID;
    v_pair_id UUID;
BEGIN
    -- Skip if same skill
    IF p_skill_id_1 = p_skill_id_2 THEN
        RETURN NULL;
    END IF;

    -- Normalize order
    SELECT * INTO v_skill_1, v_skill_2 FROM normalize_skill_pair(p_skill_id_1, p_skill_id_2);

    -- Upsert the pair
    INSERT INTO skill_pair_usage (skill_id_1, skill_id_2, tenant_id, context_type)
    VALUES (v_skill_1, v_skill_2, p_tenant_id, p_context_type)
    ON CONFLICT (skill_id_1, skill_id_2, tenant_id, context_type)
    DO UPDATE SET
        co_occurrence_count = skill_pair_usage.co_occurrence_count + 1,
        last_seen_at = NOW(),
        updated_at = NOW()
    RETURNING id INTO v_pair_id;

    RETURN v_pair_id;
END;
$$;


--
-- Name: refresh_all_mat_views(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_all_mat_views() RETURNS TABLE(view_name text, duration_ms integer, success boolean, error_msg text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  mv text;
  start_ts timestamptz;
  views text[] := ARRAY[
    'mv_cross_tenant_rollup',
    'mv_tenant_owner_rollup',
    'mv_occupation_similarity',
    'mv_talent_signals',
    'mv_employee_performance_context',
    'mv_rbac_matrix'
  ];
BEGIN
  FOREACH mv IN ARRAY views LOOP
    start_ts := clock_timestamp();
    BEGIN
      EXECUTE format('REFRESH MATERIALIZED VIEW CONCURRENTLY public.%I', mv);
      RETURN QUERY SELECT mv, extract(milliseconds from clock_timestamp() - start_ts)::int, true, NULL::text;
    EXCEPTION WHEN OTHERS THEN
      BEGIN
        EXECUTE format('REFRESH MATERIALIZED VIEW public.%I', mv);
        RETURN QUERY SELECT mv, extract(milliseconds from clock_timestamp() - start_ts)::int, true, ('non-concurrent fallback: ' || SQLERRM)::text;
      EXCEPTION WHEN OTHERS THEN
        RETURN QUERY SELECT mv, extract(milliseconds from clock_timestamp() - start_ts)::int, false, SQLERRM::text;
      END;
    END;
  END LOOP;
END;
$$;


--
-- Name: seed_role_requirements_from_esco(uuid, uuid, public.requirement_importance, smallint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.seed_role_requirements_from_esco(p_role_id uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_default_importance public.requirement_importance DEFAULT 'important'::public.requirement_importance, p_default_level smallint DEFAULT 3) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_occupation_uri VARCHAR;
    v_count INTEGER := 0;
BEGIN
    -- Get the ESCO occupation URI for this role
    SELECT esco_occupation_uri INTO v_occupation_uri
    FROM job_templates WHERE id = p_role_id;

    IF v_occupation_uri IS NULL THEN
        RETURN 0;
    END IF;

    -- Insert skills associated with this occupation
    INSERT INTO role_skill_requirements (
        tenant_id, role_id, skill_id,
        required_skill_level, importance, source
    )
    SELECT
        p_tenant_id, p_role_id, osm.skill_id,
        p_default_level, p_default_importance, 'esco_mapping'
    FROM esco_occupation_skill_map osm
    WHERE osm.occupation_uri = v_occupation_uri
    ON CONFLICT (tenant_id, role_id, skill_id) DO NOTHING;

    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$$;


--
-- Name: set_tenant_context(uuid); Type: FUNCTION; Schema: public; Owner: -
--

