--
-- Name: suggest_company_size(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.suggest_company_size(p_employee_count integer) RETURNS character varying
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
    IF p_employee_count IS NULL OR p_employee_count < 10 THEN
        RETURN 'MI';
    ELSIF p_employee_count < 50 THEN
        RETURN 'SM';
    ELSIF p_employee_count < 250 THEN
        RETURN 'MD';
    ELSE
        RETURN 'LG';
    END IF;
END;
$$;


--
-- Name: FUNCTION suggest_company_size(p_employee_count integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.suggest_company_size(p_employee_count integer) IS 'Suggerisce codice dimensione aziendale basato su numero dipendenti';


--
-- Name: sync_all_users_from_heuresys(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_all_users_from_heuresys() RETURNS TABLE(synced_count integer, error_count integer, duration_ms integer)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_start_time TIMESTAMP;
    v_synced INTEGER := 0;
    v_errors INTEGER := 0;
    v_user RECORD;
BEGIN
    v_start_time := clock_timestamp();

    -- Loop through all users from heuresys database via dblink
    FOR v_user IN
        SELECT * FROM dblink(
            'dbname=heuresys host=localhost user=heuresys password=h3ur3sys',
            'SELECT
                user_id,
                user_first_name,
                user_last_name,
                user_middle_name,
                user_email,
                user_birth_date,
                user_phone_number,
                user_mobile_phone,
                user_gender,
                user_marital_status,
                user_nationality,
                it_street_address,
                it_city,
                it_state_province_region,
                it_postal_code,
                it_country,
                user_salary,
                user_position,
                user_department,
                user_start_date,
                user_end_date,
                user_is_active,
                user_tenant_id
            FROM sys.sys_users
            WHERE user_tenant_id IS NOT NULL
            AND is_deleted = false'
        ) AS t(
            user_id UUID,
            user_first_name VARCHAR(255),
            user_last_name VARCHAR(255),
            user_middle_name VARCHAR(100),
            user_email VARCHAR(255),
            user_birth_date DATE,
            user_phone_number VARCHAR(20),
            user_mobile_phone VARCHAR(20),
            user_gender VARCHAR(50),
            user_marital_status VARCHAR(50),
            user_nationality VARCHAR(100),
            it_street_address TEXT,
            it_city VARCHAR(100),
            it_state_province_region VARCHAR(100),
            it_postal_code VARCHAR(20),
            it_country VARCHAR(100),
            user_salary NUMERIC,
            user_position VARCHAR(255),
            user_department VARCHAR(100),
            user_start_date DATE,
            user_end_date DATE,
            user_is_active BOOLEAN,
            user_tenant_id UUID
        )
    LOOP
        BEGIN
            PERFORM sync_single_user(
                v_user.user_id,
                v_user.user_first_name,
                v_user.user_last_name,
                v_user.user_middle_name,
                v_user.user_email,
                v_user.user_birth_date,
                v_user.user_phone_number,
                v_user.user_mobile_phone,
                v_user.user_gender,
                v_user.user_marital_status,
                v_user.user_nationality,
                v_user.it_street_address,
                v_user.it_city,
                v_user.it_state_province_region,
                v_user.it_postal_code,
                v_user.it_country,
                v_user.user_salary,
                v_user.user_position,
                v_user.user_department,
                v_user.user_start_date,
                v_user.user_end_date,
                v_user.user_is_active,
                v_user.user_tenant_id
            );
            v_synced := v_synced + 1;
        EXCEPTION WHEN OTHERS THEN
            v_errors := v_errors + 1;
            RAISE NOTICE 'Error syncing user %: %', v_user.user_id, SQLERRM;
        END;
    END LOOP;

    synced_count := v_synced;
    error_count := v_errors;
    duration_ms := EXTRACT(MILLISECONDS FROM (clock_timestamp() - v_start_time))::INTEGER;

    RETURN NEXT;
END;
$$;


--
-- Name: sync_single_user(uuid, character varying, character varying, character varying, character varying, date, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, numeric, character varying, character varying, date, date, boolean, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_single_user(p_user_uuid uuid, p_first_name character varying, p_last_name character varying, p_middle_name character varying, p_email character varying, p_birth_date date, p_phone character varying, p_mobile character varying, p_gender character varying, p_marital_status character varying, p_nationality character varying, p_street character varying, p_city character varying, p_region character varying, p_postal_code character varying, p_country character varying, p_salary numeric, p_position character varying, p_department character varying, p_start_date date, p_end_date date, p_is_active boolean, p_tenant_uuid uuid) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_pernr VARCHAR(8);
    v_bukrs VARCHAR(4);
BEGIN
    -- Get SAP company code from tenant mapping
    SELECT sap_bukrs INTO v_bukrs
    FROM tenant_sap_mapping
    WHERE tenant_uuid = p_tenant_uuid;

    IF v_bukrs IS NULL THEN
        RAISE EXCEPTION 'No SAP mapping found for tenant %', p_tenant_uuid;
    END IF;

    -- Check if user already has a PERNR
    SELECT pernr INTO v_pernr
    FROM user_pernr_mapping
    WHERE user_uuid = p_user_uuid;

    -- Generate new PERNR if not exists
    IF v_pernr IS NULL THEN
        v_pernr := generate_pernr(v_bukrs);

        INSERT INTO user_pernr_mapping (user_uuid, pernr, bukrs)
        VALUES (p_user_uuid, v_pernr, v_bukrs);
    END IF;

    -- Sync to all PA tables
    PERFORM sync_user_to_pa0000(v_pernr, p_user_uuid, p_start_date, p_end_date, p_is_active);
    PERFORM sync_user_to_pa0001(v_pernr, v_bukrs, p_start_date, p_end_date, p_position, p_department);
    PERFORM sync_user_to_pa0002(v_pernr, p_first_name, p_last_name, p_middle_name, p_birth_date, p_gender, p_marital_status, p_nationality, p_start_date);
    PERFORM sync_user_to_pa0006(v_pernr, p_street, p_city, p_region, p_postal_code, p_country, p_start_date);
    PERFORM sync_user_to_pa0008(v_pernr, v_bukrs, p_salary, p_start_date);
    PERFORM sync_user_to_pa0105(v_pernr, p_email, p_phone, p_mobile, p_start_date);

    -- Update sync timestamp
    UPDATE user_pernr_mapping
    SET last_sync_at = NOW(), sync_status = 'synced'
    WHERE user_uuid = p_user_uuid;

    RETURN v_pernr;
END;
$$;


--
-- Name: sync_skill_classification_to_esco(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_skill_classification_to_esco() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE esco_skills
    SET
        is_classified = true,
        primary_category = NEW.primary_category,
        cognitive_level = NEW.cognitive_level,
        updated_at = NOW()
    WHERE id = NEW.esco_skill_id;
    RETURN NEW;
END;
$$;


--
-- Name: sync_user_to_pa0000(character varying, uuid, date, date, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_user_to_pa0000(p_pernr character varying, p_user_id uuid, p_start_date date, p_end_date date, p_is_active boolean) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO pa0000 (pernr, subty, endda, begda, massn, massg, stat2)
    VALUES (
        p_pernr,
        '01',
        COALESCE(p_end_date, '9999-12-31'),
        COALESCE(p_start_date, CURRENT_DATE),
        CASE WHEN p_is_active THEN '01' ELSE '99' END,
        '01',
        CASE WHEN p_is_active THEN '3' ELSE '0' END
    )
    ON CONFLICT (pernr, subty, endda) DO UPDATE SET
        massn = EXCLUDED.massn,
        stat2 = EXCLUDED.stat2,
        begda = EXCLUDED.begda;
    RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'Error in PA0000: %', SQLERRM;
    RETURN FALSE;
END;
$$;


--
-- Name: sync_user_to_pa0001(character varying, character varying, date, date, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_user_to_pa0001(p_pernr character varying, p_bukrs character varying, p_start_date date, p_end_date date, p_position character varying, p_department character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO pa0001 (pernr, endda, begda, bukrs, werks, btrtl, persg, persk, plans, orgeh, stell, kostl)
    VALUES (
        p_pernr,
        COALESCE(p_end_date, '9999-12-31'),
        COALESCE(p_start_date, CURRENT_DATE),
        p_bukrs,
        p_bukrs,
        '0001',
        '1',
        '01',
        LPAD(CAST(ABS(HASHTEXT(COALESCE(p_position, 'EMPLOYEE'))) % 100000 AS TEXT), 8, '0'),
        LPAD(CAST(ABS(HASHTEXT(COALESCE(p_department, 'GENERAL'))) % 100000 AS TEXT), 8, '0'),
        LPAD(CAST(ABS(HASHTEXT(COALESCE(p_position, 'JOB'))) % 10000 AS TEXT), 8, '0'),
        LPAD(CAST(ABS(HASHTEXT(COALESCE(p_department, 'CC'))) % 10000 AS TEXT), 10, '0')
    )
    ON CONFLICT (pernr, endda) DO UPDATE SET
        bukrs = EXCLUDED.bukrs,
        plans = EXCLUDED.plans,
        orgeh = EXCLUDED.orgeh,
        stell = EXCLUDED.stell,
        kostl = EXCLUDED.kostl;
    RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'Error in PA0001: %', SQLERRM;
    RETURN FALSE;
END;
$$;


--
-- Name: sync_user_to_pa0002(character varying, character varying, character varying, character varying, date, character varying, character varying, character varying, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_user_to_pa0002(p_pernr character varying, p_first_name character varying, p_last_name character varying, p_middle_name character varying, p_birth_date date, p_gender character varying, p_marital_status character varying, p_nationality character varying, p_start_date date) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_gesch VARCHAR(1);
BEGIN
    v_gesch := CASE 
        WHEN LOWER(p_gender) IN ('male', 'm', 'maschio') THEN '1'
        WHEN LOWER(p_gender) IN ('female', 'f', 'femmina') THEN '2'
        ELSE '0'
    END;
    
    INSERT INTO pa0002 (pernr, endda, begda, nachn, vorna, midnm, gbdat, natio, gesch, famst)
    VALUES (
        p_pernr,
        '9999-12-31',
        COALESCE(p_start_date, CURRENT_DATE),
        UPPER(COALESCE(p_last_name, 'UNKNOWN')),
        COALESCE(p_first_name, 'Unknown'),
        COALESCE(p_middle_name, ''),
        COALESCE(p_birth_date, '1990-01-01'),
        COALESCE(SUBSTRING(p_nationality, 1, 3), 'IT'),
        v_gesch,
        COALESCE(SUBSTRING(p_marital_status, 1, 1), '0')
    )
    ON CONFLICT (pernr, endda) DO UPDATE SET
        nachn = EXCLUDED.nachn,
        vorna = EXCLUDED.vorna,
        midnm = EXCLUDED.midnm,
        gbdat = EXCLUDED.gbdat,
        natio = EXCLUDED.natio,
        gesch = EXCLUDED.gesch,
        famst = EXCLUDED.famst;
    RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'Error in PA0002: %', SQLERRM;
    RETURN FALSE;
END;
$$;


--
-- Name: sync_user_to_pa0006(character varying, character varying, character varying, character varying, character varying, character varying, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_user_to_pa0006(p_pernr character varying, p_street character varying, p_city character varying, p_region character varying, p_postal_code character varying, p_country character varying, p_start_date date) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO pa0006 (pernr, subty, endda, begda, stras, ort01, pstlz, land1, regio)
    VALUES (
        p_pernr,
        '1',
        '9999-12-31',
        COALESCE(p_start_date, CURRENT_DATE),
        COALESCE(SUBSTRING(p_street, 1, 60), 'Via Non Specificata'),
        COALESCE(p_city, 'Roma'),
        COALESCE(p_postal_code, '00100'),
        COALESCE(SUBSTRING(p_country, 1, 3), 'IT'),
        COALESCE(SUBSTRING(p_region, 1, 3), '00')
    )
    ON CONFLICT (pernr, subty, endda) DO UPDATE SET
        stras = EXCLUDED.stras,
        ort01 = EXCLUDED.ort01,
        pstlz = EXCLUDED.pstlz,
        land1 = EXCLUDED.land1,
        regio = EXCLUDED.regio;
    RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'Error in PA0006: %', SQLERRM;
    RETURN FALSE;
END;
$$;


--
-- Name: sync_user_to_pa0008(character varying, character varying, numeric, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_user_to_pa0008(p_pernr character varying, p_bukrs character varying, p_salary numeric, p_start_date date) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO pa0008 (pernr, subty, endda, begda, trfar, trfgb, trfgr, trfst, ansal, divgv, waession, bession)
    VALUES (
        p_pernr,
        '0',
        '9999-12-31',
        COALESCE(p_start_date, CURRENT_DATE),
        '01', '01', '01', '01',
        COALESCE(p_salary, 35000.00),
        12, 'EUR', 'M'
    )
    ON CONFLICT (pernr, subty, endda) DO UPDATE SET
        ansal = EXCLUDED.ansal;
    RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'Error in PA0008: %', SQLERRM;
    RETURN FALSE;
END;
$$;


--
-- Name: sync_user_to_pa0105(character varying, character varying, character varying, character varying, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_user_to_pa0105(p_pernr character varying, p_email character varying, p_phone character varying, p_mobile character varying, p_start_date date) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO pa0105 (pernr, subty, endda, begda, usrid, usrid_long)
    VALUES (
        p_pernr, '0010', '9999-12-31',
        COALESCE(p_start_date, CURRENT_DATE),
        SUBSTRING(COALESCE(p_email, 'noemail'), 1, 12),
        COALESCE(p_email, 'noemail@company.com')
    )
    ON CONFLICT (pernr, subty, endda) DO UPDATE SET
        usrid = EXCLUDED.usrid, usrid_long = EXCLUDED.usrid_long;
    
    IF p_phone IS NOT NULL AND p_phone != '' THEN
        INSERT INTO pa0105 (pernr, subty, endda, begda, usrid, usrid_long)
        VALUES (p_pernr, '0020', '9999-12-31', COALESCE(p_start_date, CURRENT_DATE), 
                SUBSTRING(p_phone, 1, 12), p_phone)
        ON CONFLICT (pernr, subty, endda) DO UPDATE SET 
            usrid = EXCLUDED.usrid, usrid_long = EXCLUDED.usrid_long;
    END IF;
    
    IF p_mobile IS NOT NULL AND p_mobile != '' THEN
        INSERT INTO pa0105 (pernr, subty, endda, begda, usrid, usrid_long)
        VALUES (p_pernr, '0030', '9999-12-31', COALESCE(p_start_date, CURRENT_DATE),
                SUBSTRING(p_mobile, 1, 12), p_mobile)
        ON CONFLICT (pernr, subty, endda) DO UPDATE SET 
            usrid = EXCLUDED.usrid, usrid_long = EXCLUDED.usrid_long;
    END IF;
    
    RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'Error in PA0105: %', SQLERRM;
    RETURN FALSE;
END;
$$;


--
-- Name: track_skill_history(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.track_skill_history() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Only track if any level changed
    IF OLD.knowledge_level IS DISTINCT FROM NEW.knowledge_level OR
       OLD.skill_level IS DISTINCT FROM NEW.skill_level OR
       OLD.ability_level IS DISTINCT FROM NEW.ability_level OR
       OLD.behavior_level IS DISTINCT FROM NEW.behavior_level OR
       OLD.attitude_level IS DISTINCT FROM NEW.attitude_level THEN

        INSERT INTO employee_skill_history (
            profile_id,
            previous_knowledge_level, previous_skill_level, previous_ability_level,
            previous_behavior_level, previous_attitude_level, previous_composite_score,
            new_knowledge_level, new_skill_level, new_ability_level,
            new_behavior_level, new_attitude_level, new_composite_score,
            change_type
        ) VALUES (
            NEW.id,
            OLD.knowledge_level, OLD.skill_level, OLD.ability_level,
            OLD.behavior_level, OLD.attitude_level, OLD.composite_score,
            NEW.knowledge_level, NEW.skill_level, NEW.ability_level,
            NEW.behavior_level, NEW.attitude_level, NEW.composite_score,
            CASE
                WHEN NEW.verification_status = 'verified' AND OLD.verification_status != 'verified' THEN 'verification'
                ELSE 'update'
            END
        );
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: trg_career_skill_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_career_skill_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_emp_id UUID;
BEGIN
  SELECT employee_id INTO v_emp_id FROM career_profiles WHERE id = NEW.profile_id;
  IF v_emp_id IS NULL THEN RETURN NEW; END IF;
  IF TG_OP='INSERT' OR (TG_OP='UPDATE' AND NEW.proficiency IS DISTINCT FROM OLD.proficiency) THEN
    PERFORM fn_add_employee_event(NEW.tenant_id, v_emp_id, 'skill_updated', now(),
      'career_skills', NEW.id,
      jsonb_build_object('skill_name', NEW.skill_name, 'previous_proficiency', CASE WHEN TG_OP='UPDATE' THEN OLD.proficiency ELSE NULL END, 'new_proficiency', NEW.proficiency),
      format('Skill %s: proficiency %s → %s', NEW.skill_name, COALESCE(OLD.proficiency::text,'new'), NEW.proficiency));
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: trg_cert_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_cert_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_cert_name TEXT;
  v_tenant UUID;
BEGIN
  SELECT c.name, e.tenant_id INTO v_cert_name, v_tenant
  FROM certifications c, employees e
  WHERE c.id = NEW.certification_id AND e.id = NEW.employee_id;
  IF TG_OP='INSERT' THEN
    PERFORM fn_add_employee_event(v_tenant, NEW.employee_id, 'certification_earned', NEW.issued_date::timestamptz,
      'employee_certifications', NEW.id,
      jsonb_build_object('cert_name', v_cert_name, 'expiry', NEW.expiry_date),
      format('Certification earned: %s', v_cert_name));
  ELSIF TG_OP='UPDATE' AND OLD.status='active' AND NEW.status='expired' THEN
    PERFORM fn_add_employee_event(v_tenant, NEW.employee_id, 'certification_expired', now(),
      'employee_certifications', NEW.id,
      jsonb_build_object('cert_name', v_cert_name),
      format('Certification expired: %s', v_cert_name));
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: trg_contract_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_contract_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_event_type VARCHAR(50);
  v_summary TEXT;
BEGIN
  IF NEW.level IS DISTINCT FROM OLD.level THEN
    v_event_type := 'level_change';
    v_summary := format('Level change: %s → %s (CCNL %s)', OLD.level, NEW.level, COALESCE(NEW.ccnl_code,''));
    PERFORM fn_add_employee_event(NEW.tenant_id, NEW.employee_id, v_event_type, now(),
      'employee_contracts', NEW.id,
      jsonb_build_object('previous_level', OLD.level, 'new_level', NEW.level, 'ccnl', NEW.ccnl_code),
      v_summary);
  END IF;
  IF NEW.annual_salary IS DISTINCT FROM OLD.annual_salary THEN
    v_event_type := 'salary_change';
    v_summary := format('Salary change: %s → %s %s', COALESCE(OLD.annual_salary::text,'?'), NEW.annual_salary, COALESCE(NEW.currency,'EUR'));
    PERFORM fn_add_employee_event(NEW.tenant_id, NEW.employee_id, v_event_type, now(),
      'employee_contracts', NEW.id,
      jsonb_build_object('previous_salary', OLD.annual_salary, 'new_salary', NEW.annual_salary, 'currency', NEW.currency),
      v_summary);
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: trg_course_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_course_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_title TEXT;
BEGIN
  IF NEW.status='completed' AND (TG_OP='INSERT' OR OLD.status<>'completed') THEN
    SELECT title INTO v_title FROM courses WHERE id = NEW.course_id;
    PERFORM fn_add_employee_event(NEW.tenant_id, NEW.employee_id, 'course_completed', COALESCE(NEW.completed_at::timestamptz, now()),
      'course_enrollments', NEW.id,
      jsonb_build_object('course_title', v_title, 'progress', NEW.progress_percent),
      format('Course completed: %s', v_title));
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: trg_profile_auto_populate(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_profile_auto_populate() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_section_name_it VARCHAR(255);
    v_section_name_en VARCHAR(255);
    v_division_name_it VARCHAR(255);
    v_division_name_en VARCHAR(255);
    v_group_name_it VARCHAR(255);
    v_group_name_en VARCHAR(255);
    v_size_name_it VARCHAR(50);
    v_size_name_en VARCHAR(50);
BEGIN
    -- Generate profile_code if not provided
    IF NEW.profile_code IS NULL THEN
        NEW.profile_code := generate_profile_code(
            NEW.section_code,
            NEW.division_code,
            NEW.group_code,
            NEW.size_code
        );
    END IF;

    -- Get names for full_name generation
    SELECT name_it, name_en INTO v_section_name_it, v_section_name_en
    FROM nace_sections WHERE code = NEW.section_code;

    SELECT name_it, name_en INTO v_division_name_it, v_division_name_en
    FROM nace_divisions WHERE code = NEW.division_code;

    SELECT name_it, name_en INTO v_group_name_it, v_group_name_en
    FROM nace_groups WHERE code = NEW.group_code;

    SELECT name_it, name_en INTO v_size_name_it, v_size_name_en
    FROM company_sizes WHERE code = NEW.size_code;

    -- Generate full names
    NEW.full_name_it := generate_profile_full_name(
        v_section_name_it, v_division_name_it, v_group_name_it, v_size_name_it
    );
    NEW.full_name_en := generate_profile_full_name(
        v_section_name_en, v_division_name_en, v_group_name_en, v_size_name_en
    );

    -- Update timestamp
    NEW.updated_at := NOW();

    RETURN NEW;
END;
$$;


--
-- Name: trg_review_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_review_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.status='completed' AND (TG_OP='INSERT' OR OLD.status<>'completed') THEN
    PERFORM fn_add_employee_event(NEW.tenant_id, NEW.employee_id, 'review_completed', COALESCE(NEW.submitted_at, now()),
      'performance_reviews', NEW.id,
      jsonb_build_object('rating', NEW.overall_rating, 'review_type', NEW.review_type, 'period_end', NEW.review_period_end),
      format('Review %s completed: rating %s/5', NEW.review_type, NEW.overall_rating));
  END IF;
  RETURN NEW;
END;
$$;


