--
-- Name: update_goal_progress(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_goal_progress() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  total_milestones INTEGER;
  completed_milestones INTEGER;
  new_progress INTEGER;
BEGIN
  SELECT COUNT(*), COUNT(*) FILTER (WHERE completed_at IS NOT NULL)
  INTO total_milestones, completed_milestones
  FROM career_goal_milestones
  WHERE goal_id = COALESCE(NEW.goal_id, OLD.goal_id);

  IF total_milestones > 0 THEN
    new_progress := ROUND((completed_milestones::NUMERIC / total_milestones::NUMERIC) * 100);
  ELSE
    new_progress := 0;
  END IF;

  UPDATE career_goals
  SET
    progress = new_progress,
    updated_at = NOW(),
    status = CASE WHEN new_progress = 100 THEN 'completed' ELSE status END,
    completed_at = CASE WHEN new_progress = 100 THEN NOW() ELSE completed_at END
  WHERE id = COALESCE(NEW.goal_id, OLD.goal_id);

  RETURN NEW;
END;
$$;


--
-- Name: update_okr_progress(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_okr_progress() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE okrs
    SET
        overall_progress = calculate_okr_progress(NEW.okr_id),
        updated_at = NOW()
    WHERE id = NEW.okr_id;

    RETURN NEW;
END;
$$;


