-- Name: update_skill_composite_score(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_skill_composite_score() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.composite_score := calculate_composite_score(
        NEW.knowledge_level,
        NEW.skill_level,
        NEW.ability_level,
        NEW.behavior_level,
        NEW.attitude_level
    );
    NEW.updated_at := NOW();
    RETURN NEW;
END;
$$;


--
-- Name: update_skill_pair_strengths(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_skill_pair_strengths() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_max_count INTEGER;
    v_updated INTEGER;
BEGIN
    -- Get max co-occurrence count for normalization
    SELECT MAX(co_occurrence_count) INTO v_max_count FROM skill_pair_usage;

    IF v_max_count IS NULL OR v_max_count = 0 THEN
        RETURN 0;
    END IF;

    -- Update strengths normalized to 0-1 range
    WITH updated AS (
        UPDATE skill_pair_usage
        SET usage_strength = LEAST(1.0, (co_occurrence_count::NUMERIC / v_max_count)),
            updated_at = NOW()
        WHERE co_occurrence_count > 0
        RETURNING id
    )
    SELECT COUNT(*) INTO v_updated FROM updated;

    RETURN v_updated;
END;
$$;


--
-- Name: update_template_org_paths(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_template_org_paths(p_template_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    r_unit RECORD;
    v_parent_path LTREE;
BEGIN
    FOR r_unit IN
        SELECT id, parent_id, code
        FROM org_unit_templates
        WHERE template_id = p_template_id
        ORDER BY depth, sort_order
    LOOP
        IF r_unit.parent_id IS NULL THEN
            UPDATE org_unit_templates
            SET path = text2ltree(replace(r_unit.code, '.', '_'))
            WHERE id = r_unit.id;
        ELSE
            SELECT path INTO v_parent_path
            FROM org_unit_templates
            WHERE id = r_unit.parent_id;

            UPDATE org_unit_templates
            SET path = v_parent_path || text2ltree(replace(r_unit.code, '.', '_'))
            WHERE id = r_unit.id;
        END IF;
    END LOOP;
END;
$$;


--
-- Name: update_tenant_org_paths(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_tenant_org_paths(p_chart_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    r_unit RECORD;
    v_parent_path LTREE;
BEGIN
    -- Process in depth order
    FOR r_unit IN
        SELECT id, parent_id, code
        FROM tenant_org_units
        WHERE chart_id = p_chart_id
        ORDER BY depth, sort_order
    LOOP
        IF r_unit.parent_id IS NULL THEN
            -- Root unit
            UPDATE tenant_org_units
            SET path = text2ltree(r_unit.code)
            WHERE id = r_unit.id;
        ELSE
            -- Child unit - get parent path
            SELECT path INTO v_parent_path
            FROM tenant_org_units
            WHERE id = r_unit.parent_id;

            UPDATE tenant_org_units
            SET path = v_parent_path || text2ltree(r_unit.code)
            WHERE id = r_unit.id;
        END IF;
    END LOOP;
END;
$$;


