--

CREATE VIEW public.employees AS
 SELECT e.id,
    e.tenant_id,
    p.first_name,
    p.last_name,
    p.email,
    h.job_title,
    h.department,
    h.location,
    h.manager_id,
    h.hire_date,
    e.skills,
    h.performance_rating,
    h.potential,
    e.is_active,
    e.created_at,
    e.updated_at,
    e.pernr,
    p.birth_date,
    p.gender,
    p.nationality,
    pa.salary,
    pa.currency,
    h.cost_center,
    h.employee_group,
    h.employee_subgroup,
    h.position_id,
    h.legacy_org_unit_code,
    h.cost_center_id,
    h.org_unit_id,
    p.middle_name,
    p.birth_place,
    p.marital_status,
    p.address_street,
    p.address_city,
    p.address_postal_code,
    p.address_country,
    p.address_region,
    p.temp_address_street,
    p.temp_address_city,
    p.temp_address_postal_code,
    p.temp_address_country,
    pa.pay_scale_area,
    pa.pay_scale_type,
    pa.pay_scale_group,
    pa.pay_scale_level,
    pa.pay_periods_per_year,
    h.work_schedule_percentage,
    pa.iban,
    pa.swift_bic,
    pa.bank_name,
    pa.bank_account_number,
    p.phone_mobile,
    p.phone_work,
    p.phone_home,
    p.personal_email,
    p.tax_id,
    p.national_id,
    p.national_id_expiry,
    p.passport_number,
    p.passport_expiry,
    p.driver_license,
    p.driver_license_expiry,
    h.probation_end_date,
    h.seniority_date,
    h.contract_end_date,
    p.emergency_contact_name,
    p.emergency_contact_phone,
    p.emergency_contact_relationship,
    p.family_members,
    p.education_history,
    p.highest_education_level,
    p.highest_education_institution,
    p.highest_education_field,
    p.highest_education_year,
    h.company_code,
    h.personnel_area,
    h.personnel_subarea,
    e.employment_status,
    e.termination_date,
    e.termination_reason,
    h.auth_username,
    h.auth_password_hash,
    h.auth_role,
    h.auth_permissions,
    h.auth_last_login,
    h.auth_username_candidate,
    h.location_id,
    e.profile_embedding,
    e.embedding_text_hash,
    e.embedding_model,
    e.embedding_generated_at,
    e.deleted_at,
    e.enrichment_consent,
    e.enrichment_consent_at,
    e.enrichment_consent_scope
   FROM (((public.employees_core e
     LEFT JOIN public.employees_pii p ON ((p.employee_id = e.id)))
     LEFT JOIN public.employees_hr h ON ((h.employee_id = e.id)))
     LEFT JOIN public.employees_payroll pa ON ((pa.employee_id = e.id)));


