    tenant_job_skill_id uuid,
    esco_skill_uri character varying(255),
    skill_name character varying(255) NOT NULL,
    assessed_level integer NOT NULL,
    required_level integer,
    gap integer GENERATED ALWAYS AS ((COALESCE(required_level, assessed_level) - assessed_level)) STORED,
    assessment_date date NOT NULL,
    assessed_by uuid,
    assessment_method character varying(50),
    evidence_notes text,
    certification_url character varying(255),
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    tenant_id uuid NOT NULL,
    CONSTRAINT ck_assessed_level CHECK (((assessed_level >= 1) AND (assessed_level <= 5))),
    CONSTRAINT ck_assessment_method CHECK (((assessment_method IS NULL) OR ((assessment_method)::text = ANY (ARRAY[('self'::character varying)::text, ('manager'::character varying)::text, ('peer'::character varying)::text, ('test'::character varying)::text, ('certification'::character varying)::text, ('360'::character varying)::text, ('interview'::character varying)::text])))),
    CONSTRAINT ck_required_level CHECK (((required_level IS NULL) OR ((required_level >= 1) AND (required_level <= 5)))),
    CONSTRAINT employee_skill_assessments_updated_after_created CHECK ((updated_at >= created_at))
);

