COMMENT ON COLUMN public.dashboard_elements.tenant_id IS 'NULL = platform default seeded; non-NULL = tenant-specific override. RLS enforces P1 isolation on non-NULL rows.';


--
-- Name: COLUMN dashboard_elements.parent_element_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.dashboard_elements.parent_element_id IS 'Self-FK per gerarchia slot. NULL = top-level (figlio diretto del preset). Non-NULL = slot figlio (es. left/right di .double-split). Cascade delete: rimuovendo un parent, rimuove tutti i figli.';


--
-- Name: COLUMN dashboard_elements.variant; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.dashboard_elements.variant IS 'Catalog livello 2 modifier (BEM-like). Es. ''pill-warn'', ''tenant-card-platform'', ''fill-info'', ''heat-6''. NULL = default base senza variant. Validazione lato app contro brand-dashboard-catalog.md.';


