--

CREATE TABLE public.employee_kpi_targets (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    employee_id uuid NOT NULL,
    tenant_job_kpi_id uuid,
    kpi_code character varying(20) NOT NULL,
    kpi_name character varying(255) NOT NULL,
    period_start date NOT NULL,
    period_end date NOT NULL,
    target_value numeric(12,2) NOT NULL,
    min_acceptable numeric(12,2),
    stretch_target numeric(12,2),
    actual_value numeric(12,2),
    achievement_percent numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (target_value <> (0)::numeric) THEN ((actual_value / target_value) * (100)::numeric)
    ELSE NULL::numeric
END) STORED,
    status character varying(20) DEFAULT 'active'::character varying,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    tenant_id uuid NOT NULL,
    CONSTRAINT ck_kpi_period CHECK ((period_end >= period_start)),
    CONSTRAINT ck_kpi_status CHECK (((status)::text = ANY (ARRAY[('active'::character varying)::text, ('completed'::character varying)::text, ('cancelled'::character varying)::text, ('on_hold'::character varying)::text]))),
    CONSTRAINT employee_kpi_targets_updated_after_created CHECK ((updated_at >= created_at))
);

