    is_primary boolean DEFAULT false,
    is_target boolean DEFAULT false,
    target_level smallint,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT employee_skill_profiles_ability_level_check CHECK (((ability_level >= 0) AND (ability_level <= 5))),
    CONSTRAINT employee_skill_profiles_attitude_level_check CHECK (((attitude_level >= 0) AND (attitude_level <= 5))),
    CONSTRAINT employee_skill_profiles_behavior_level_check CHECK (((behavior_level >= 0) AND (behavior_level <= 5))),
    CONSTRAINT employee_skill_profiles_composite_score_check CHECK (((composite_score >= (0)::numeric) AND (composite_score <= (5)::numeric))),
    CONSTRAINT employee_skill_profiles_confidence_score_check CHECK (((confidence_score >= (0)::numeric) AND (confidence_score <= (1)::numeric))),
    CONSTRAINT employee_skill_profiles_knowledge_level_check CHECK (((knowledge_level >= 0) AND (knowledge_level <= 5))),
    CONSTRAINT employee_skill_profiles_skill_level_check CHECK (((skill_level >= 0) AND (skill_level <= 5))),
    CONSTRAINT employee_skill_profiles_target_level_check CHECK (((target_level IS NULL) OR ((target_level >= 0) AND (target_level <= 5)))),
    CONSTRAINT employee_skill_profiles_updated_after_created CHECK ((updated_at >= created_at)),
    CONSTRAINT valid_target CHECK (((target_level IS NULL) OR ((target_level)::numeric > composite_score)))
);

