--
-- Name: employees_full; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.employees_full AS
 SELECT e.id,
    e.tenant_id,
    e.first_name,
    e.last_name,
    e.email,
    e.job_title,
    e.department,
    e.location,
    e.manager_id,
    e.hire_date,
    e.skills,
    e.performance_rating,
    e.potential,
    e.is_active,
    e.created_at,
    e.updated_at,
    e.pernr,
    e.birth_date,
    e.gender,
    e.nationality,
    e.salary,
    e.currency,
    e.cost_center,
    e.employee_group,
    e.employee_subgroup,
    e.position_id,
    e.legacy_org_unit_code,
    e.cost_center_id,
    e.org_unit_id,
    e.middle_name,
    e.birth_place,
    e.marital_status,
    e.address_street,
    e.address_city,
    e.address_postal_code,
    e.address_country,
    e.address_region,
    e.temp_address_street,
    e.temp_address_city,
    e.temp_address_postal_code,
    e.temp_address_country,
    e.pay_scale_area,
    e.pay_scale_type,
    e.pay_scale_group,
    e.pay_scale_level,
    e.pay_periods_per_year,
    e.work_schedule_percentage,
    e.iban,
    e.swift_bic,
    e.bank_name,
    e.bank_account_number,
    e.phone_mobile,
    e.phone_work,
    e.phone_home,
    e.personal_email,
    e.tax_id,
    e.national_id,
    e.national_id_expiry,
    e.passport_number,
    e.passport_expiry,
    e.driver_license,
    e.driver_license_expiry,
    e.probation_end_date,
    e.seniority_date,
    e.contract_end_date,
    e.emergency_contact_name,
    e.emergency_contact_phone,
    e.emergency_contact_relationship,
    e.family_members,
    e.education_history,
    e.highest_education_level,
    e.highest_education_institution,
    e.highest_education_field,
    e.highest_education_year,
    e.company_code,
    e.personnel_area,
    e.personnel_subarea,
    e.employment_status,
    e.termination_date,
    e.termination_reason,
    e.auth_username,
    e.auth_password_hash,
    e.auth_role,
    e.auth_permissions,
    e.auth_last_login,
    e.auth_username_candidate,
    e.location_id,
    e.profile_embedding,
    e.embedding_text_hash,
    e.embedding_model,
    e.embedding_generated_at,
    e.deleted_at,
    e.enrichment_consent,
    e.enrichment_consent_at,
    e.enrichment_consent_scope,
    pii.first_name AS pii_first_name,
    pii.last_name AS pii_last_name,
    hr.job_title AS hr_job_title,
    hr.department AS hr_department,
    pay.salary AS pay_salary,
    pay.currency AS pay_currency
   FROM (((public.employees e
     LEFT JOIN public.employees_pii pii ON ((pii.employee_id = e.id)))
     LEFT JOIN public.employees_hr hr ON ((hr.employee_id = e.id)))
     LEFT JOIN public.employees_payroll pay ON ((pay.employee_id = e.id)));


--
-- Name: employees_staging; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.employees_staging (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    session_id uuid NOT NULL,
    original_employee_id uuid,
    tenant_id uuid NOT NULL,
    first_name character varying(100) NOT NULL,
    last_name character varying(100) NOT NULL,
    middle_name character varying(100),
    email character varying(255) NOT NULL,
    personal_email character varying(255),
    phone_mobile character varying(30),
    phone_work character varying(30),
    phone_home character varying(30),
    job_title character varying(255),
    department character varying(100),
    location character varying(255),
    hire_date date,
    is_active boolean DEFAULT true,
    manager_id uuid,
    org_unit_id uuid,
    cost_center_id uuid,
    position_id character varying(50),
    cost_center character varying(50),
    hierarchy_level integer,
    reports_to_staging_id uuid,
    position_code character varying(50),
    unit_code character varying(50),
    birth_date date,
    birth_place character varying(100),
    gender character varying(10),
    nationality character varying(50),
    marital_status character varying(20),
    address_street character varying(255),
    address_city character varying(100),
    address_postal_code character varying(20),
    address_country character varying(3),
    address_region character varying(50),
    salary numeric(15,2),
    currency character varying(3) DEFAULT 'EUR'::character varying,
    pay_scale_area character varying(10),
    pay_scale_type character varying(10),
    pay_scale_group character varying(10),
    pay_scale_level character varying(10),
    pay_periods_per_year integer DEFAULT 12,
    iban character varying(34),
    swift_bic character varying(11),
    bank_name character varying(100),
    bank_account_number character varying(50),
    skills text[] DEFAULT '{}'::text[],
    performance_rating numeric(3,2),
    potential character varying(20),
    employee_group character varying(50),
    employee_subgroup character varying(50),
    work_schedule_percentage numeric(5,2) DEFAULT 100.00,
    pernr character varying(8),
    legacy_org_unit_code character varying(50),
    tax_id character varying(20),
    original_values jsonb DEFAULT '{}'::jsonb NOT NULL,
    diff_fields text[] DEFAULT '{}'::text[],
    change_type character varying(30) DEFAULT 'unchanged'::character varying NOT NULL,
    assignment_confidence numeric(5,4),
    assignment_method character varying(50),
    assignment_notes text,
    is_approved boolean DEFAULT false,
    approved_by uuid,
    approved_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    deleted_at timestamp with time zone,
    CONSTRAINT ck_staging_assignment_method CHECK (((assignment_method IS NULL) OR ((assignment_method)::text = ANY (ARRAY[('job_title_match'::character varying)::text, ('department_match'::character varying)::text, ('manager_chain'::character varying)::text, ('manual'::character varying)::text, ('ai_suggested'::character varying)::text, ('esco_match'::character varying)::text])))),
    CONSTRAINT ck_staging_change_type CHECK (((change_type)::text = ANY (ARRAY[('unchanged'::character varying)::text, ('new_position'::character varying)::text, ('reassignment'::character varying)::text, ('promotion'::character varying)::text, ('demotion'::character varying)::text, ('transfer'::character varying)::text, ('new_hire_slot'::character varying)::text]))),
    CONSTRAINT employees_staging_hierarchy_level_check CHECK (((hierarchy_level >= 1) AND (hierarchy_level <= 7))),
    CONSTRAINT employees_staging_updated_after_created CHECK ((updated_at >= created_at))
);

ALTER TABLE ONLY public.employees_staging FORCE ROW LEVEL SECURITY;


