--
-- Name: error_logs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.error_logs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    error_id character varying(50) NOT NULL,
    code character varying(50) NOT NULL,
    category character varying(30) NOT NULL,
    severity character varying(20) NOT NULL,
    message text NOT NULL,
    http_status integer NOT NULL,
    tenant_id uuid NOT NULL,
    user_id uuid,
    request_method character varying(10),
    request_path text,
    request_ip character varying(45),
    request_id character varying(100),
    user_agent text,
    details jsonb,
    database_context jsonb,
    stack_trace text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT error_logs_category_check CHECK (((category)::text = ANY (ARRAY[('API'::character varying)::text, ('AUTH'::character varying)::text, ('DB'::character varying)::text, ('VALIDATION'::character varying)::text, ('BUSINESS'::character varying)::text, ('INTEGRATION'::character varying)::text, ('SYSTEM'::character varying)::text, ('PERMISSION'::character varying)::text, ('TENANT'::character varying)::text, ('AI'::character varying)::text]))),
    CONSTRAINT error_logs_severity_check CHECK (((severity)::text = ANY (ARRAY[('CRITICAL'::character varying)::text, ('ERROR'::character varying)::text, ('WARNING'::character varying)::text, ('INFO'::character varying)::text])))
);

ALTER TABLE ONLY public.error_logs FORCE ROW LEVEL SECURITY;


--
-- Name: TABLE error_logs; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.error_logs IS 'Centralized error logging for all application errors';


--
-- Name: error_patterns; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.error_patterns (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    pattern_type character varying(50) NOT NULL,
    description text NOT NULL,
    error_code character varying(50),
    category character varying(30),
    first_seen timestamp with time zone NOT NULL,
    last_seen timestamp with time zone NOT NULL,
    occurrence_count integer DEFAULT 1 NOT NULL,
    affected_tenants uuid[],
    is_resolved boolean DEFAULT false,
    resolution_notes text,
    resolved_at timestamp with time zone,
    resolved_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT error_patterns_type_check CHECK (((pattern_type)::text = ANY (ARRAY[('SPIKE'::character varying)::text, ('RECURRING'::character varying)::text, ('NEW_ERROR'::character varying)::text, ('REGRESSION'::character varying)::text, ('CLUSTER'::character varying)::text]))),
    CONSTRAINT error_patterns_updated_after_created CHECK ((updated_at >= created_at))
);


--
-- Name: TABLE error_patterns; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.error_patterns IS 'Detected error patterns and anomalies';


--
-- Name: error_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.error_stats AS
 SELECT date_trunc('day'::text, created_at) AS date,
    tenant_id,
    category,
    severity,
    count(*) AS error_count,
    count(DISTINCT code) AS unique_codes,
    count(DISTINCT user_id) AS affected_users
   FROM public.error_logs
  WHERE (created_at >= (now() - '30 days'::interval))
  GROUP BY (date_trunc('day'::text, created_at)), tenant_id, category, severity;


