--
-- Name: goal_hierarchy; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.goal_hierarchy AS
 WITH RECURSIVE goal_tree AS (
         SELECT g.id,
            g.tenant_id,
            g.title,
            g.status,
            g.progress_percent,
            g.parent_goal_id,
            g.employee_id,
            1 AS depth,
            ARRAY[g.id] AS path,
            g.title AS root_title
           FROM public.goals g
          WHERE (g.parent_goal_id IS NULL)
        UNION ALL
         SELECT g.id,
            g.tenant_id,
            g.title,
            g.status,
            g.progress_percent,
            g.parent_goal_id,
            g.employee_id,
            (gt.depth + 1),
            (gt.path || g.id),
            gt.root_title
           FROM (public.goals g
             JOIN goal_tree gt ON ((g.parent_goal_id = gt.id)))
        )
 SELECT id,
    tenant_id,
    title,
    status,
    progress_percent,
    parent_goal_id,
    employee_id,
    depth,
    path,
    root_title
   FROM goal_tree;


