CREATE TABLE public.industry_classifications (
    code character varying(10) NOT NULL,
    parent_code character varying(10),
    level smallint NOT NULL,
    classification_system character varying(10) DEFAULT 'NACE'::character varying NOT NULL,
    name_it character varying(500) NOT NULL,
    name_en character varying(500),
    description_it text,
    description_en text,
    icon character varying(50),
    color character varying(7),
    is_active boolean DEFAULT true NOT NULL,
    embedding_it public.vector(1536),
    embedding_en public.vector(1536),
