    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    deleted_at timestamp with time zone,
    CONSTRAINT chk_level_system CHECK ((((level <= 4) AND ((classification_system)::text = 'NACE'::text)) OR ((level >= 5) AND ((classification_system)::text = 'ATECO'::text)))),
    CONSTRAINT chk_parent_consistency CHECK ((((level = 1) AND (parent_code IS NULL)) OR ((level > 1) AND (parent_code IS NOT NULL)))),
    CONSTRAINT industry_classifications_classification_system_check CHECK (((classification_system)::text = ANY (ARRAY[('NACE'::character varying)::text, ('ATECO'::character varying)::text]))),
    CONSTRAINT industry_classifications_level_check CHECK (((level >= 1) AND (level <= 6))),
    CONSTRAINT industry_classifications_updated_after_created CHECK ((updated_at >= created_at))
);


