--
-- Name: mv_rbac_matrix; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.mv_rbac_matrix AS
 SELECT r.id AS role_id,
    r.code AS role_code,
    r.name AS role_name,
    r.hierarchy_level AS role_level,
    fa.id AS area_id,
    fa.code AS area_code,
    fa.name AS area_name,
    rp.can_view,
    rp.can_create,
    rp.can_edit,
    rp.can_delete,
    rp.can_approve,
    rp.can_export,
    rp.scope_type,
    ((((((((rp.can_view)::integer + (rp.can_create)::integer) + (rp.can_edit)::integer) + (rp.can_delete)::integer) + (rp.can_approve)::integer) + (rp.can_export)::integer) * 100) / 6) AS grant_pct
   FROM ((public.rbp_roles r
     CROSS JOIN public.rbp_functional_areas fa)
     LEFT JOIN public.rbp_role_permissions rp ON (((rp.role_id = r.id) AND (rp.functional_area_id = fa.id))))
  ORDER BY r.hierarchy_level, fa.id
  WITH NO DATA;


