-- Name: users; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.users (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    username character varying(100) NOT NULL,
    password_hash character varying(255),
    role character varying(50) DEFAULT 'USER'::character varying,
    permissions text[] DEFAULT '{}'::text[],
    is_active boolean DEFAULT true,
    last_login timestamp without time zone,
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now(),
    employee_id uuid,
    deleted_at timestamp with time zone,
    totp_enabled boolean DEFAULT false,
    totp_recovery_codes text[],
    totp_failed_attempts integer DEFAULT 0,
    totp_lockout_until timestamp with time zone,
    totp_secret_encrypted text,
    palette_preference_id character varying(32),
    theme_preference character varying(8),
    CONSTRAINT users_business_must_have_employee CHECK ((((role)::text = ANY (ARRAY[('SUPERUSER'::character varying)::text, ('SYSADMIN'::character varying)::text, ('DEMO'::character varying)::text])) OR (employee_id IS NOT NULL))),
    CONSTRAINT users_palette_preference_id_check CHECK (((palette_preference_id IS NULL) OR ((palette_preference_id)::text = ANY ((ARRAY['legacy'::character varying, 'alpha'::character varying, 'beta'::character varying, 'gamma'::character varying, 'delta'::character varying, 'epsilon'::character varying, 'zeta'::character varying, 'eta'::character varying, 'theta'::character varying, 'iota'::character varying, 'kappa'::character varying, 'lambda'::character varying, 'mu-architect'::character varying, 'mu-art-director'::character varying, 'mu-pragmatic'::character varying, 'mu-synthesis'::character varying, 'mu-data-dense'::character varying])::text[])))),
    CONSTRAINT users_theme_preference_check CHECK (((theme_preference IS NULL) OR ((theme_preference)::text = ANY ((ARRAY['dark'::character varying, 'light'::character varying])::text[])))),
    CONSTRAINT users_updated_after_created CHECK ((updated_at >= created_at))
);

ALTER TABLE ONLY public.users FORCE ROW LEVEL SECURITY;


--
-- Name: COLUMN users.totp_secret_encrypted; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.users.totp_secret_encrypted IS 'Envelope-encrypted TOTP secret (AES-256-GCM via services/totpCrypto.ts). Base64: iv[12]||tag[16]||ciphertext. Replaces users.totp_secret plaintext storage (HIGH-09).';


--
-- Name: COLUMN users.palette_preference_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.users.palette_preference_id IS 'User dashboard palette override (PaletteId enum). NULL = inherit project default. Applies to /dashboard/* routes only via DashboardPaletteApplier.';


--
-- Name: COLUMN users.theme_preference; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.users.theme_preference IS 'User dashboard theme override (dark | light). NULL = inherit project default. Coupled with palette_preference_id.';


--
-- Name: recent_errors; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.recent_errors AS
 SELECT el.id,
    el.error_id,
    el.code,
    el.category,
    el.severity,
    el.message,
    el.http_status,
    el.request_method,
    el.request_path,
    el.tenant_id,
    t.name AS tenant_name,
    el.user_id,
    u.username,
    el.created_at
   FROM ((public.error_logs el
     LEFT JOIN public.tenants t ON ((el.tenant_id = t.id)))
     LEFT JOIN public.users u ON ((el.user_id = u.id)))
  WHERE (el.created_at >= (now() - '24:00:00'::interval))
  ORDER BY el.created_at DESC;


