    CONSTRAINT recruiting_interview_participants_rsvp_status_check CHECK (((rsvp_status)::text = ANY (ARRAY[('pending'::character varying)::text, ('accepted'::character varying)::text, ('declined'::character varying)::text, ('tentative'::character varying)::text])))
