CREATE TABLE public.skill_relationships (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    source_skill_id uuid NOT NULL,
    target_skill_id uuid NOT NULL,
    relationship_type character varying(30) NOT NULL,
    relationship_strength numeric(3,2) DEFAULT 0.50,
    is_bidirectional boolean DEFAULT false,
    substitution_context text,
    prerequisite_level integer,
    relationship_source character varying(50) DEFAULT 'ai_inferred'::character varying,
    validated_by uuid,
    validated_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT ck_no_self_relationship CHECK ((source_skill_id <> target_skill_id)),
    CONSTRAINT skill_relationships_prerequisite_level_check CHECK (((prerequisite_level >= 1) AND (prerequisite_level <= 5))),
    CONSTRAINT skill_relationships_relationship_source_check CHECK (((relationship_source)::text = ANY (ARRAY[('esco_hierarchy'::character varying)::text, ('ai_inferred'::character varying)::text, ('manual'::character varying)::text, ('cooccurrence'::character varying)::text]))),
    CONSTRAINT skill_relationships_relationship_strength_check CHECK (((relationship_strength >= (0)::numeric) AND (relationship_strength <= (1)::numeric))),
    CONSTRAINT skill_relationships_relationship_type_check CHECK (((relationship_type)::text = ANY (ARRAY[('prerequisite'::character varying)::text, ('complementary'::character varying)::text, ('substitution'::character varying)::text, ('builds_on'::character varying)::text, ('enables'::character varying)::text])))
);


