--
-- Name: v_360_feedback_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_360_feedback_summary AS
 SELECT f.tenant_id,
    f.target_employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    f.review_cycle_id,
    rc.name AS cycle_name,
    f.relationship_type,
    count(*) AS response_count,
    round(avg(f.overall_rating), 2) AS avg_rating,
    round(stddev(f.overall_rating), 2) AS rating_stddev,
    round(avg(f.sentiment_score), 2) AS avg_sentiment,
        CASE
            WHEN (count(*) >= COALESCE(rc.feedback_360_min_responses, 3)) THEN jsonb_build_object('min_rating', min(f.overall_rating), 'max_rating', max(f.overall_rating), 'median_rating', percentile_cont((0.5)::double precision) WITHIN GROUP (ORDER BY ((f.overall_rating)::double precision)))
            ELSE NULL::jsonb
        END AS rating_distribution
   FROM ((public.feedback_360 f
     JOIN public.employees e ON ((f.target_employee_id = e.id)))
     LEFT JOIN public.review_cycles rc ON ((f.review_cycle_id = rc.id)))
  WHERE ((f.status)::text = 'completed'::text)
  GROUP BY f.tenant_id, f.target_employee_id, e.first_name, e.last_name, f.review_cycle_id, rc.name, f.relationship_type, rc.feedback_360_min_responses;


--
-- Name: v_360_response_rates; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_360_response_rates AS
 SELECT rc.id AS review_cycle_id,
    rc.tenant_id,
    rc.name AS cycle_name,
    count(DISTINCT fr.id) AS total_requests,
    count(DISTINCT
        CASE
            WHEN ((fr.status)::text = 'completed'::text) THEN fr.id
            ELSE NULL::uuid
        END) AS completed_requests,
    round((((count(DISTINCT
        CASE
            WHEN ((fr.status)::text = 'completed'::text) THEN fr.id
            ELSE NULL::uuid
        END))::numeric / (NULLIF(count(DISTINCT fr.id), 0))::numeric) * (100)::numeric), 2) AS response_rate,
    count(DISTINCT fr.requestee_id) AS total_employees,
    count(DISTINCT
        CASE
            WHEN ((fr.status)::text = 'pending'::text) THEN fr.reviewer_id
            ELSE NULL::uuid
        END) AS pending_reviewers,
    avg(
        CASE
            WHEN (f.id IS NOT NULL) THEN f.overall_rating
            ELSE NULL::numeric
        END) AS avg_rating
   FROM ((public.review_cycles rc
     LEFT JOIN public.feedback_requests fr ON ((rc.id = fr.review_cycle_id)))
     LEFT JOIN public.feedback_360 f ON ((fr.feedback_360_id = f.id)))
  WHERE (rc.include_360_feedback = true)
  GROUP BY rc.id, rc.tenant_id, rc.name;


--
-- Name: VIEW v_360_response_rates; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_360_response_rates IS 'Response rates for 360 feedback by review cycle';


--
-- Name: v_active_job_postings; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_active_job_postings AS
 SELECT j.id,
    j.tenant_id,
    j.title,
    j.department,
    j.team,
    j.location,
    j.work_type,
    j.summary,
    j.responsibilities,
    j.requirements,
    j.nice_to_have,
    j.job_level,
    j.job_family,
    j.salary_min,
    j.salary_max,
    j.currency,
    j.show_salary,
    j.status,
    j.visibility,
    j.min_tenure_months,
    j.min_rating,
    j.required_skills,
    j.posted_at,
    j.expires_at,
    j.target_start_date,
    j.hiring_manager_id,
    j.hr_contact_id,
    j.views_count,
    j.applications_count,
    j.created_by,
    j.created_at,
    j.updated_at,
    COALESCE(a.app_count, (0)::bigint) AS application_count,
    COALESCE(v.view_count, (0)::bigint) AS view_count,
    (((hm.first_name)::text || ' '::text) || (hm.last_name)::text) AS hiring_manager_name,
    (((hr.first_name)::text || ' '::text) || (hr.last_name)::text) AS hr_contact_name
   FROM ((((public.internal_job_postings j
     LEFT JOIN ( SELECT internal_applications.job_posting_id,
            count(*) AS app_count
           FROM public.internal_applications
          WHERE ((internal_applications.status)::text <> ALL (ARRAY[('draft'::character varying)::text, ('withdrawn'::character varying)::text]))
          GROUP BY internal_applications.job_posting_id) a ON ((j.id = a.job_posting_id)))
     LEFT JOIN ( SELECT internal_job_views.job_posting_id,
            count(*) AS view_count
           FROM public.internal_job_views
          GROUP BY internal_job_views.job_posting_id) v ON ((j.id = v.job_posting_id)))
     LEFT JOIN public.employees hm ON ((j.hiring_manager_id = hm.id)))
     LEFT JOIN public.employees hr ON ((j.hr_contact_id = hr.id)))
  WHERE (((j.status)::text = 'open'::text) AND ((j.expires_at IS NULL) OR (j.expires_at > now())));


--
-- Name: v_ai_daily_costs; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_ai_daily_costs AS
 SELECT date(created_at) AS date,
    provider,
    model,
    operation,
    count(*) AS request_count,
    sum(total_tokens) AS total_tokens,
    sum(cost) AS total_cost,
    avg(latency_ms) AS avg_latency_ms,
    sum(
        CASE
            WHEN success THEN 1
            ELSE 0
        END) AS success_count,
    sum(
        CASE
            WHEN (NOT success) THEN 1
            ELSE 0
        END) AS error_count
   FROM public.ai_usage_log
  GROUP BY (date(created_at)), provider, model, operation
  ORDER BY (date(created_at)) DESC, provider, model;


--
-- Name: VIEW v_ai_daily_costs; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_ai_daily_costs IS 'Daily aggregation of AI usage costs';


--
-- Name: v_ai_monthly_costs; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_ai_monthly_costs AS
 SELECT date_trunc('month'::text, created_at) AS month,
    provider,
    count(*) AS request_count,
    sum(total_tokens) AS total_tokens,
    sum(cost) AS total_cost,
    avg(latency_ms) AS avg_latency_ms,
    round((((sum(
        CASE
            WHEN success THEN 1
            ELSE 0
        END))::numeric / (count(*))::numeric) * (100)::numeric), 2) AS success_rate
   FROM public.ai_usage_log
  GROUP BY (date_trunc('month'::text, created_at)), provider
  ORDER BY (date_trunc('month'::text, created_at)) DESC, provider;


--
-- Name: VIEW v_ai_monthly_costs; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_ai_monthly_costs IS 'Monthly summary of AI usage costs';


--
-- Name: v_ai_tenant_costs; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_ai_tenant_costs AS
 SELECT t.code AS tenant_code,
    t.name AS tenant_name,
    aul.provider,
    count(*) AS request_count,
    sum(aul.total_tokens) AS total_tokens,
    sum(aul.cost) AS total_cost
   FROM (public.ai_usage_log aul
     JOIN public.tenants t ON ((t.id = aul.tenant_id)))
  GROUP BY t.id, t.code, t.name, aul.provider
  ORDER BY (sum(aul.cost)) DESC;


--
-- Name: VIEW v_ai_tenant_costs; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_ai_tenant_costs IS 'AI costs broken down by tenant';


--
-- Name: v_applicant_pipeline; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_applicant_pipeline AS
 SELECT pb.aplnr,
    (((pb.nachn)::text || ', '::text) || (pb.vorna)::text) AS applicant_name,
    pb.email,
    pb.source_channel,
    pa.stat2 AS status,
    va.vacancy_id,
    va.assignment_status,
    va.position_id,
    count(DISTINCT act.activity_id) AS activities_count,
    max(act.activity_date) AS last_activity_date,
    ev.overall_score AS latest_score,
    ev.recommendation
   FROM ((((public.pb0002 pb
     LEFT JOIN public.pb0001 pa ON ((((pb.aplnr)::text = (pa.aplnr)::text) AND (pa.endda = '9999-12-31'::date))))
     LEFT JOIN public.pb4001 va ON ((((pb.aplnr)::text = (va.aplnr)::text) AND (va.endda = '9999-12-31'::date))))
     LEFT JOIN public.pb4000 act ON (((pb.aplnr)::text = (act.aplnr)::text)))
     LEFT JOIN ( SELECT DISTINCT ON (pb4005.aplnr) pb4005.id,
            pb4005.aplnr,
            pb4005.vacancy_id,
            pb4005.evaluation_id,
            pb4005.evaluation_date,
            pb4005.evaluator_pernr,
            pb4005.evaluation_type,
            pb4005.technical_score,
            pb4005.communication_score,
            pb4005.cultural_fit_score,
            pb4005.experience_score,
            pb4005.overall_score,
            pb4005.recommendation,
            pb4005.comments,
            pb4005.created_at
           FROM public.pb4005
          ORDER BY pb4005.aplnr, pb4005.evaluation_date DESC) ev ON (((pb.aplnr)::text = (ev.aplnr)::text)))
  WHERE (pb.endda = '9999-12-31'::date)
  GROUP BY pb.aplnr, pb.nachn, pb.vorna, pb.email, pb.source_channel, pa.stat2, va.vacancy_id, va.assignment_status, va.position_id, ev.overall_score, ev.recommendation
  ORDER BY pb.aplnr;


--
-- Name: VIEW v_applicant_pipeline; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_applicant_pipeline IS 'Recruitment pipeline with applicant status and activities';


--
-- Name: v_employee_master; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_employee_master AS
 SELECT p0002.pernr,
    p0002.vorna AS first_name,
    p0002.nachn AS last_name,
    p0002.midnm AS middle_name,
    p0002.gbdat AS birth_date,
    p0002.natio AS nationality,
        CASE p0002.gesch
            WHEN '1'::text THEN 'Male'::text
            WHEN '2'::text THEN 'Female'::text
            ELSE 'Other'::text
        END AS gender,
    p0000.stat2 AS status,
    p0000.begda AS hire_date,
    p0001.bukrs AS company_code,
    p0001.werks AS personnel_area,
    p0001.orgeh AS org_unit,
    p0001.plans AS "position",
    p0001.stell AS job,
    p0001.kostl AS cost_center,
    p0008.ansal AS annual_salary,
    p0008.waession AS currency,
    p0008.bession AS employment_pct,
    p0007.wession AS weekly_hours,
    p0016.cttyp AS contract_type,
    p0016.probation_end,
    p0016.termination_date,
    email.usrid_long AS email,
    phone.usrid_long AS phone
   FROM (((((((public.pa0002 p0002
     LEFT JOIN public.pa0000 p0000 ON ((((p0002.pernr)::text = (p0000.pernr)::text) AND (p0000.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0001 p0001 ON ((((p0002.pernr)::text = (p0001.pernr)::text) AND (p0001.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0008 p0008 ON ((((p0002.pernr)::text = (p0008.pernr)::text) AND (p0008.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0007 p0007 ON ((((p0002.pernr)::text = (p0007.pernr)::text) AND (p0007.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0016 p0016 ON ((((p0002.pernr)::text = (p0016.pernr)::text) AND (p0016.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0105 email ON ((((p0002.pernr)::text = (email.pernr)::text) AND ((email.subty)::text = '0010'::text) AND (email.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0105 phone ON ((((p0002.pernr)::text = (phone.pernr)::text) AND ((phone.subty)::text = '0020'::text) AND (phone.endda = '9999-12-31'::date))))
  WHERE (p0002.endda = '9999-12-31'::date);


--
-- Name: v_appraisal_status; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_appraisal_status AS
 SELECT e.pernr,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e.company_code,
    a.subty AS appraisal_type,
    a.appraisal_id,
    a.bession AS overall_rating,
    a.potential_rating,
    a.appraisal_date,
    a.status,
        CASE a.status
            WHEN '01'::text THEN 'Draft'::text
            WHEN '02'::text THEN 'Submitted'::text
            WHEN '03'::text THEN 'Approved'::text
            ELSE 'Unknown'::text
        END AS status_text
   FROM (public.v_employee_master e
     LEFT JOIN public.pa0025 a ON ((((e.pernr)::text = (a.pernr)::text) AND (a.begda >= date_trunc('year'::text, (CURRENT_DATE)::timestamp with time zone)) AND (a.endda = '9999-12-31'::date))))
  ORDER BY e.company_code, e.pernr;


--
-- Name: VIEW v_appraisal_status; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_appraisal_status IS 'Performance appraisal completion status';


--
-- Name: v_attendance_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_attendance_summary AS
 SELECT e.pernr,
    e.company_code,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS full_name,
    date_trunc('month'::text, (a.begda)::timestamp with time zone) AS month,
    sum(
        CASE
            WHEN ((a.subty)::text ~~ '01%'::text) THEN a.abwtg
            ELSE (0)::numeric
        END) AS vacation_days,
    sum(
        CASE
            WHEN ((a.subty)::text ~~ '02%'::text) THEN a.abwtg
            ELSE (0)::numeric
        END) AS sick_days,
    sum(
        CASE
            WHEN ((a.subty)::text ~~ '03%'::text) THEN a.abwtg
            ELSE (0)::numeric
        END) AS personal_days,
    sum(a.abwtg) AS total_absence_days,
    sum(a.stdaz) AS total_absence_hours
   FROM (public.v_employee_master e
     LEFT JOIN public.pa2001 a ON (((e.pernr)::text = (a.pernr)::text)))
  WHERE (a.begda >= date_trunc('year'::text, (CURRENT_DATE)::timestamp with time zone))
  GROUP BY e.pernr, e.company_code, e.first_name, e.last_name, (date_trunc('month'::text, (a.begda)::timestamp with time zone))
  ORDER BY e.pernr, (date_trunc('month'::text, (a.begda)::timestamp with time zone));


--
-- Name: v_benefits_enrollment; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_benefits_enrollment AS
 SELECT e.pernr,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e.company_code,
    'Health'::text AS benefit_category,
    h.bession AS plan_id,
    bp.plan_name,
    h.bession_option AS coverage,
    h.ee_contribution,
    h.er_contribution,
    h.begda AS effective_date
   FROM ((public.v_employee_master e
     JOIN public.pa0167 h ON ((((e.pernr)::text = (h.pernr)::text) AND (h.endda = '9999-12-31'::date))))
     LEFT JOIN public.t5ubp bp ON ((((h.bession)::text = (bp.bession)::text) AND (bp.endda = '9999-12-31'::date))))
UNION ALL
 SELECT e.pernr,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e.company_code,
    'Savings'::text AS benefit_category,
    s.bession AS plan_id,
    bp.plan_name,
    (((s.ee_contribution_pct)::character varying)::text || '%'::text) AS coverage,
    s.ee_contribution_amt AS ee_contribution,
    s.er_match_pct AS er_contribution,
    s.begda AS effective_date
   FROM ((public.v_employee_master e
     JOIN public.pa0169 s ON ((((e.pernr)::text = (s.pernr)::text) AND (s.endda = '9999-12-31'::date))))
     LEFT JOIN public.t5ubp bp ON ((((s.bession)::text = (bp.bession)::text) AND (bp.endda = '9999-12-31'::date))))
  ORDER BY 1, 4;


--
-- Name: VIEW v_benefits_enrollment; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_benefits_enrollment IS 'Employee benefits enrollment summary';


--
-- Name: v_calibration_9box; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_calibration_9box AS
 SELECT ca.tenant_id,
    ca.calibration_session_id,
    ca.employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    d.name AS department_name,
    ca.original_rating,
    ca.adjusted_rating,
    COALESCE(ca.adjusted_rating, ca.original_rating) AS final_rating,
        CASE
            WHEN (COALESCE(ca.adjusted_rating, ca.original_rating) >= (4)::numeric) THEN 'high'::text
            WHEN (COALESCE(ca.adjusted_rating, ca.original_rating) >= (3)::numeric) THEN 'medium'::text
            ELSE 'low'::text
        END AS performance_bucket,
        CASE
            WHEN (COALESCE((pp.predicted_rating / 5.0), 0.5) >= 0.7) THEN 'high'::text
            WHEN (COALESCE((pp.predicted_rating / 5.0), 0.5) >= 0.4) THEN 'medium'::text
            ELSE 'low'::text
        END AS potential_bucket,
        CASE
            WHEN ((COALESCE(ca.adjusted_rating, ca.original_rating) >= (4)::numeric) AND (COALESCE((pp.predicted_rating / 5.0), 0.5) >= 0.7)) THEN 9
            WHEN ((COALESCE(ca.adjusted_rating, ca.original_rating) >= (4)::numeric) AND (COALESCE((pp.predicted_rating / 5.0), 0.5) >= 0.4)) THEN 6
            WHEN (COALESCE(ca.adjusted_rating, ca.original_rating) >= (4)::numeric) THEN 3
            WHEN ((COALESCE(ca.adjusted_rating, ca.original_rating) >= (3)::numeric) AND (COALESCE((pp.predicted_rating / 5.0), 0.5) >= 0.7)) THEN 8
            WHEN ((COALESCE(ca.adjusted_rating, ca.original_rating) >= (3)::numeric) AND (COALESCE((pp.predicted_rating / 5.0), 0.5) >= 0.4)) THEN 5
            WHEN (COALESCE(ca.adjusted_rating, ca.original_rating) >= (3)::numeric) THEN 2
            WHEN (COALESCE((pp.predicted_rating / 5.0), 0.5) >= 0.7) THEN 7
            WHEN (COALESCE((pp.predicted_rating / 5.0), 0.5) >= 0.4) THEN 4
            ELSE 1
        END AS box_position,
    ca.outlier_flag,
    ca.outlier_reason
   FROM (((public.calibration_adjustments ca
     JOIN public.employees e ON ((ca.employee_id = e.id)))
     LEFT JOIN public.org_units d ON ((e.org_unit_id = d.id)))
     LEFT JOIN public.performance_predictions pp ON (((ca.employee_id = pp.employee_id) AND (pp.is_current = true))));


--
-- Name: v_calibration_bell_curve; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_calibration_bell_curve AS
 SELECT tenant_id,
    calibration_session_id,
    COALESCE(adjusted_rating, original_rating) AS rating,
    count(*) AS count,
    (((count(*))::numeric / NULLIF(sum(count(*)) OVER (PARTITION BY calibration_session_id), (0)::numeric)) * (100)::numeric) AS percentage,
        CASE
            WHEN (COALESCE(adjusted_rating, original_rating) <= (1)::numeric) THEN 5
            WHEN (COALESCE(adjusted_rating, original_rating) <= (2)::numeric) THEN 10
            WHEN (COALESCE(adjusted_rating, original_rating) <= (3)::numeric) THEN 35
            WHEN (COALESCE(adjusted_rating, original_rating) <= (4)::numeric) THEN 35
            ELSE 15
        END AS expected_percentage
   FROM public.calibration_adjustments ca
  WHERE (COALESCE(adjusted_rating, original_rating) IS NOT NULL)
  GROUP BY tenant_id, calibration_session_id, COALESCE(adjusted_rating, original_rating);


--
-- Name: VIEW v_calibration_bell_curve; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_calibration_bell_curve IS 'Bell curve distribution analysis for calibration';


