--
-- Name: v_employee_sap_master; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_employee_sap_master AS
 SELECT m.pernr,
    m.bukrs,
    p2.vorna AS first_name,
    p2.nachn AS last_name,
    p2.gbdat AS birth_date,
    p1.orgeh AS org_unit,
    p1.plans AS "position",
    p1.kostl AS cost_center,
    p8.ansal AS annual_salary,
    p5.usrid_long AS email,
    m.last_sync_at
   FROM ((((public.user_pernr_mapping m
     JOIN public.pa0001 p1 ON ((((m.pernr)::text = (p1.pernr)::text) AND (p1.endda = '9999-12-31'::date))))
     JOIN public.pa0002 p2 ON ((((m.pernr)::text = (p2.pernr)::text) AND (p2.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0008 p8 ON ((((m.pernr)::text = (p8.pernr)::text) AND (p8.endda = '9999-12-31'::date) AND ((p8.subty)::text = '0'::text))))
     LEFT JOIN public.pa0105 p5 ON ((((m.pernr)::text = (p5.pernr)::text) AND ((p5.subty)::text = '0010'::text) AND (p5.endda = '9999-12-31'::date))));


--
-- Name: v_employee_skill_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_employee_skill_summary AS
 SELECT esp.tenant_id,
    esp.employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    count(*) AS total_skills,
    count(*) FILTER (WHERE (esp.verification_status = 'verified'::public.skill_verification_status)) AS verified_skills,
    count(*) FILTER (WHERE (esp.verification_status = 'pending'::public.skill_verification_status)) AS pending_skills,
    round(avg(esp.composite_score), 2) AS avg_composite_score,
    max(esp.composite_score) AS max_composite_score,
    count(*) FILTER (WHERE esp.is_primary) AS primary_skills,
    count(*) FILTER (WHERE esp.is_target) AS target_skills
   FROM (public.employee_skill_profiles esp
     JOIN public.employees e ON ((esp.employee_id = e.id)))
  GROUP BY esp.tenant_id, esp.employee_id, e.first_name, e.last_name;


