--
-- Name: v_employee_skills_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_employee_skills_summary AS
 SELECT es.tenant_id,
    es.employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    count(*) AS total_skills,
    count(
        CASE
            WHEN (es.proficiency_level >= 4) THEN 1
            ELSE NULL::integer
        END) AS expert_skills,
    count(
        CASE
            WHEN es.is_verified THEN 1
            ELSE NULL::integer
        END) AS verified_skills,
    (avg(es.proficiency_level))::numeric(3,2) AS avg_proficiency,
    array_agg(DISTINCT COALESCE(esco.skill_type, 'custom'::character varying)) AS skill_types
   FROM ((public.employee_skills es
     JOIN public.employees e ON ((es.employee_id = e.id)))
     LEFT JOIN public.esco_skills esco ON ((es.esco_skill_id = esco.id)))
  GROUP BY es.tenant_id, es.employee_id, e.first_name, e.last_name;


--
-- Name: v_engagement_analytics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_engagement_analytics AS
 WITH survey_metrics AS (
         SELECT s.tenant_id,
            date_trunc('month'::text, s.created_at) AS period,
            count(DISTINCT s.id) AS total_surveys,
            sum(s.total_invitations) AS total_invitations,
            sum(s.total_responses) AS total_responses,
                CASE
                    WHEN (sum(s.total_invitations) > 0) THEN round((((sum(s.total_responses))::numeric / (sum(s.total_invitations))::numeric) * (100)::numeric), 1)
                    ELSE (0)::numeric
                END AS response_rate
           FROM public.engagement_surveys s
          WHERE ((s.status)::text = ANY (ARRAY[('active'::character varying)::text, ('closed'::character varying)::text]))
          GROUP BY s.tenant_id, (date_trunc('month'::text, s.created_at))
        ), nps_metrics AS (
         SELECT s.tenant_id,
            date_trunc('month'::text, s.created_at) AS period,
            count(*) FILTER (WHERE (((a.value ->> 'value'::text))::integer >= 9)) AS promoters,
            count(*) FILTER (WHERE ((((a.value ->> 'value'::text))::integer >= 7) AND (((a.value ->> 'value'::text))::integer <= 8))) AS passives,
            count(*) FILTER (WHERE (((a.value ->> 'value'::text))::integer <= 6)) AS detractors,
            count(*) AS total_nps_responses
           FROM (((public.engagement_surveys s
             JOIN public.engagement_survey_responses r ON (((r.survey_id = s.id) AND (r.is_complete = true))))
             CROSS JOIN LATERAL jsonb_array_elements(r.answers) a(value))
             JOIN LATERAL jsonb_array_elements(s.questions) q(value) ON (((q.value ->> 'id'::text) = (a.value ->> 'question_id'::text))))
          WHERE ((q.value ->> 'type'::text) = 'nps'::text)
          GROUP BY s.tenant_id, (date_trunc('month'::text, s.created_at))
        )
 SELECT sm.tenant_id,
    sm.period,
    sm.total_surveys,
    sm.total_invitations,
    sm.total_responses,
    sm.response_rate,
        CASE
            WHEN (COALESCE(nm.total_nps_responses, (0)::bigint) > 0) THEN round(((((nm.promoters)::numeric / (nm.total_nps_responses)::numeric) - ((nm.detractors)::numeric / (nm.total_nps_responses)::numeric)) * (100)::numeric), 0)
            ELSE NULL::numeric
        END AS enps_score,
    nm.promoters,
    nm.passives,
    nm.detractors
   FROM (survey_metrics sm
     LEFT JOIN nps_metrics nm ON (((sm.tenant_id = nm.tenant_id) AND (sm.period = nm.period))));


--
-- Name: VIEW v_engagement_analytics; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_engagement_analytics IS 'Aggregated engagement analytics by tenant and month';


--
-- Name: v_engagement_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_engagement_summary AS
 SELECT s.tenant_id,
    s.id AS survey_id,
    s.title AS survey_title,
    s.survey_type,
    count(DISTINCT sr.employee_id) AS respondents,
    round(avg(
        CASE
            WHEN ((sq.question_type)::text = 'nps'::text) THEN sr.rating_value
            ELSE NULL::integer
        END), 1) AS avg_nps_score,
    round(avg(sr.rating_value), 2) AS avg_rating,
    round(avg(
        CASE
            WHEN ((sq.category)::text = 'engagement'::text) THEN sr.rating_value
            ELSE NULL::integer
        END), 2) AS engagement_score,
    round(avg(
        CASE
            WHEN ((sq.category)::text = 'manager'::text) THEN sr.rating_value
            ELSE NULL::integer
        END), 2) AS manager_score,
    round(avg(
        CASE
            WHEN ((sq.category)::text = 'growth'::text) THEN sr.rating_value
            ELSE NULL::integer
        END), 2) AS growth_score,
    round(avg(
        CASE
            WHEN ((sq.category)::text = 'culture'::text) THEN sr.rating_value
            ELSE NULL::integer
        END), 2) AS culture_score
   FROM ((public.surveys s
     JOIN public.survey_questions sq ON ((sq.survey_id = s.id)))
     LEFT JOIN public.survey_responses sr ON ((sr.question_id = sq.id)))
  GROUP BY s.tenant_id, s.id, s.title, s.survey_type;


--
-- Name: v_feature_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_feature_summary AS
 SELECT category,
    count(*) AS total_features,
    sum(
        CASE
            WHEN ((implementation_status)::text = 'implemented'::text) THEN 1
            ELSE 0
        END) AS implemented,
    sum(
        CASE
            WHEN ((implementation_status)::text = 'in_progress'::text) THEN 1
            ELSE 0
        END) AS in_progress,
    sum(
        CASE
            WHEN ((implementation_status)::text = 'not_started'::text) THEN 1
            ELSE 0
        END) AS not_started,
    round(avg(current_coverage_pct), 1) AS avg_coverage_pct,
    sum(COALESCE(estimated_effort_days, 0)) AS total_effort_days
   FROM public.platform_features
  GROUP BY category
  ORDER BY (round(avg(current_coverage_pct), 1)) DESC;


--
-- Name: v_feedback_given_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_feedback_given_summary AS
 SELECT cf.tenant_id,
    cf.from_employee_id AS employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    count(*) AS total_given,
    count(*) FILTER (WHERE ((cf.feedback_type)::text = 'praise'::text)) AS praise_given,
    count(*) FILTER (WHERE ((cf.feedback_type)::text = 'suggestion'::text)) AS suggestion_given,
    count(*) FILTER (WHERE ((cf.feedback_type)::text = 'concern'::text)) AS concern_given,
    count(DISTINCT cf.to_employee_id) AS unique_recipients,
    max(cf.created_at) AS last_feedback_given
   FROM (public.continuous_feedback cf
     JOIN public.employees e ON ((cf.from_employee_id = e.id)))
  GROUP BY cf.tenant_id, cf.from_employee_id, e.first_name, e.last_name;


--
-- Name: v_feedback_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_feedback_summary AS
 SELECT cf.tenant_id,
    cf.to_employee_id AS employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    count(*) AS total_received,
    count(*) FILTER (WHERE ((cf.feedback_type)::text = 'praise'::text)) AS praise_count,
    count(*) FILTER (WHERE ((cf.feedback_type)::text = 'suggestion'::text)) AS suggestion_count,
    count(*) FILTER (WHERE ((cf.feedback_type)::text = 'concern'::text)) AS concern_count,
    count(*) FILTER (WHERE ((cf.visibility)::text = 'public'::text)) AS public_count,
    round(avg(cf.sentiment_score), 2) AS avg_sentiment,
    max(cf.created_at) AS last_feedback_at,
    count(DISTINCT cf.from_employee_id) AS unique_givers
   FROM (public.continuous_feedback cf
     JOIN public.employees e ON ((cf.to_employee_id = e.id)))
  GROUP BY cf.tenant_id, cf.to_employee_id, e.first_name, e.last_name;


--
-- Name: v_feedback_wall; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_feedback_wall AS
 SELECT cf.id,
    cf.tenant_id,
    cf.from_employee_id,
    (((f.first_name)::text || ' '::text) || (f.last_name)::text) AS from_name,
    f.job_title AS from_job_title,
    cf.to_employee_id,
    (((t.first_name)::text || ' '::text) || (t.last_name)::text) AS to_name,
    t.job_title AS to_job_title,
    d.name AS to_department,
    cf.feedback_type,
    cf.message,
    cf.category,
    cf.tags,
    cf.created_at,
    cf.acknowledged,
    g.title AS related_goal_title
   FROM ((((public.continuous_feedback cf
     JOIN public.employees f ON ((cf.from_employee_id = f.id)))
     JOIN public.employees t ON ((cf.to_employee_id = t.id)))
     LEFT JOIN public.org_units d ON ((t.org_unit_id = d.id)))
     LEFT JOIN public.goals g ON ((cf.related_goal_id = g.id)))
  WHERE (((cf.visibility)::text = 'public'::text) AND ((cf.feedback_type)::text = 'praise'::text))
  ORDER BY cf.created_at DESC;


--
-- Name: v_goal_cascade; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_goal_cascade AS
 WITH RECURSIVE goal_tree AS (
         SELECT g.id,
            g.tenant_id,
            g.title,
            g.description,
            g.employee_id,
            g.parent_goal_id,
            g.status,
            g.progress_percent,
            g.weight,
            g.due_date,
            0 AS level,
            ARRAY[g.id] AS path,
            g.id AS root_id
           FROM public.goals g
          WHERE (g.parent_goal_id IS NULL)
        UNION ALL
         SELECT g.id,
            g.tenant_id,
            g.title,
            g.description,
            g.employee_id,
            g.parent_goal_id,
            g.status,
            g.progress_percent,
            g.weight,
            g.due_date,
            (gt_1.level + 1),
            (gt_1.path || g.id),
            gt_1.root_id
           FROM (public.goals g
             JOIN goal_tree gt_1 ON ((g.parent_goal_id = gt_1.id)))
          WHERE (NOT (g.id = ANY (gt_1.path)))
        )
 SELECT gt.id,
    gt.tenant_id,
    gt.title,
    gt.description,
    gt.employee_id,
    gt.parent_goal_id,
    gt.status,
    gt.progress_percent,
    gt.weight,
    gt.due_date,
    gt.level,
    gt.path,
    gt.root_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS owner_name,
    e.job_title AS owner_job_title,
    d.name AS owner_department,
    pg.title AS parent_goal_title
   FROM (((goal_tree gt
     JOIN public.employees e ON ((gt.employee_id = e.id)))
     LEFT JOIN public.org_units d ON ((e.org_unit_id = d.id)))
     LEFT JOIN public.goals pg ON ((gt.parent_goal_id = pg.id)));


--
-- Name: v_goals_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_goals_summary AS
 SELECT g.tenant_id,
    t.name AS tenant_name,
    count(*) AS total_goals,
    count(*) FILTER (WHERE ((g.status)::text = 'completed'::text)) AS completed_goals,
    count(*) FILTER (WHERE ((g.status)::text = 'in_progress'::text)) AS in_progress_goals,
    count(*) FILTER (WHERE ((g.status)::text = 'not_started'::text)) AS not_started_goals,
    round(avg(g.progress_percent), 1) AS avg_progress,
    count(*) FILTER (WHERE ((g.due_date < CURRENT_DATE) AND ((g.status)::text <> 'completed'::text))) AS overdue_goals
   FROM (public.goals g
     JOIN public.tenants t ON ((t.id = g.tenant_id)))
  GROUP BY g.tenant_id, t.name;


--
-- Name: v_headcount_trend; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_headcount_trend AS
 SELECT p1.bukrs AS company_code,
    t.butxt AS company_name,
    p1.orgeh AS org_unit,
    org.stext AS org_unit_name,
    count(DISTINCT p1.pernr) AS headcount,
    count(DISTINCT
        CASE
            WHEN ((p0.stat2)::text = '1'::text) THEN p1.pernr
            ELSE NULL::character varying
        END) AS active_count,
    count(DISTINCT
        CASE
            WHEN ((p0.stat2)::text = '3'::text) THEN p1.pernr
            ELSE NULL::character varying
        END) AS terminated_count,
    avg(p8.ansal) AS avg_salary
   FROM ((((public.pa0001 p1
     LEFT JOIN public.pa0000 p0 ON ((((p1.pernr)::text = (p0.pernr)::text) AND (p0.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0008 p8 ON ((((p1.pernr)::text = (p8.pernr)::text) AND (p8.endda = '9999-12-31'::date))))
     LEFT JOIN public.t500c t ON (((p1.bukrs)::text = (t.bukrs)::text)))
     LEFT JOIN public.hrp1000 org ON ((((p1.orgeh)::text = (org.objid)::text) AND ((org.otype)::text = 'O'::text) AND (org.endda = '9999-12-31'::date))))
  WHERE (p1.endda = '9999-12-31'::date)
  GROUP BY p1.bukrs, t.butxt, p1.orgeh, org.stext
  ORDER BY p1.bukrs, p1.orgeh;


--
-- Name: VIEW v_headcount_trend; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_headcount_trend IS 'Headcount summary by company and org unit';


--
-- Name: v_hr_essentials; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_hr_essentials AS
 SELECT p0002.pernr,
    p0002.vorna AS first_name,
    p0002.nachn AS last_name,
    p0002.gbdat AS birth_date,
    p0000.stat2 AS status,
    p0001.bukrs AS company_code,
    p0001.orgeh AS org_unit,
    p0001.plans AS "position",
    email.usrid_long AS email
   FROM (((public.pa0002 p0002
     LEFT JOIN public.pa0000 p0000 ON ((((p0002.pernr)::text = (p0000.pernr)::text) AND (p0000.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0001 p0001 ON ((((p0002.pernr)::text = (p0001.pernr)::text) AND (p0001.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0105 email ON ((((p0002.pernr)::text = (email.pernr)::text) AND ((email.subty)::text = '0010'::text) AND (email.endda = '9999-12-31'::date))))
  WHERE (p0002.endda = '9999-12-31'::date);


--
-- Name: v_job_profile; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_job_profile AS
 SELECT j.objid AS job_id,
    j.stext AS job_title,
    j.short AS job_code,
    c.min_salary,
    c.mid_salary,
    c.max_salary,
    c.currency,
    string_agg(DISTINCT (cat.qual_name)::text, ', '::text) AS required_skills,
    count(DISTINCT req.quali) AS skill_count
   FROM (((public.hrp1000 j
     LEFT JOIN public.hrp1005 c ON ((((j.objid)::text = (c.objid)::text) AND ((c.otype)::text = 'C'::text) AND (c.endda = '9999-12-31'::date))))
     LEFT JOIN public.hrp1035 req ON ((((j.objid)::text = (req.objid)::text) AND ((req.otype)::text = 'C'::text) AND (req.endda = '9999-12-31'::date))))
     LEFT JOIN public.hrp1036 cat ON ((((req.quali)::text = (cat.objid)::text) AND (cat.endda = '9999-12-31'::date))))
  WHERE (((j.otype)::text = 'C'::text) AND (j.endda = '9999-12-31'::date))
  GROUP BY j.objid, j.stext, j.short, c.min_salary, c.mid_salary, c.max_salary, c.currency
  ORDER BY j.stext;


--
-- Name: VIEW v_job_profile; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_job_profile IS 'Job profiles with compensation and skill requirements';


--
-- Name: v_job_template_courses; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_job_template_courses AS
 SELECT DISTINCT jt.id AS job_template_id,
    jt.tenant_id,
    jtc.course_id,
    jtc.requirement_type,
    jtc.priority,
    jtc.rationale,
    jt.title_it AS job_template_title
   FROM (public.job_templates jt
     JOIN public.job_title_courses jtc ON (((((jtc.job_title)::text = (jt.title_it)::text) OR ((jtc.job_title)::text = (jt.title_en)::text)) AND (jtc.tenant_id = jt.tenant_id))));


--
-- Name: VIEW v_job_template_courses; Type: COMMENT; Schema: public; Owner: -
