COMMENT ON VIEW public.v_job_template_courses IS 'Riconcilia job_title_courses (mapping su stringa) con job_templates.id (FK robusta).';


--
-- Name: v_learning_dashboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_learning_dashboard AS
 SELECT t.id AS tenant_id,
    t.code AS tenant_code,
    t.name AS tenant_name,
    count(DISTINCT c.id) AS total_courses,
    count(DISTINCT c.id) FILTER (WHERE ((c.status)::text = 'published'::text)) AS published_courses,
    count(DISTINCT lp.id) AS total_learning_paths,
    count(DISTINCT ce.id) AS total_enrollments,
    count(DISTINCT ce.id) FILTER (WHERE ((ce.status)::text = 'completed'::text)) AS completed_enrollments,
    count(DISTINCT ce.id) FILTER (WHERE ((ce.status)::text = 'in_progress'::text)) AS in_progress_enrollments,
    round(avg(ce.progress_percent), 1) AS avg_progress,
    count(DISTINCT ec.id) AS total_certifications_earned,
    count(DISTINCT lr.id) FILTER (WHERE ((lr.status)::text = 'pending'::text)) AS pending_recommendations
   FROM (((((public.tenants t
     LEFT JOIN public.courses c ON ((c.tenant_id = t.id)))
     LEFT JOIN public.learning_paths lp ON ((lp.tenant_id = t.id)))
     LEFT JOIN public.course_enrollments ce ON ((ce.course_id = c.id)))
     LEFT JOIN public.employee_certifications ec ON ((ec.employee_id IN ( SELECT employees.id
           FROM public.employees
          WHERE (employees.tenant_id = t.id)))))
     LEFT JOIN public.learning_recommendations lr ON ((lr.employee_id IN ( SELECT employees.id
           FROM public.employees
          WHERE (employees.tenant_id = t.id)))))
  GROUP BY t.id, t.code, t.name;


--
-- Name: v_learning_path_progress; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_learning_path_progress AS
 SELECT lpe.id AS enrollment_id,
    lpe.employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    lpe.learning_path_id,
    lp.title AS path_title,
    lp.target_role,
    lp.estimated_duration_hours,
    lpe.status,
    lpe.progress_percent,
    lpe.enrolled_at,
    lpe.completed_at,
    count(lpc.id) AS total_courses_in_path,
    count(ce.id) FILTER (WHERE ((ce.status)::text = 'completed'::text)) AS courses_completed,
    count(ce.id) FILTER (WHERE ((ce.status)::text = 'in_progress'::text)) AS courses_in_progress
   FROM ((((public.learning_path_enrollments lpe
     JOIN public.employees e ON ((e.id = lpe.employee_id)))
     JOIN public.learning_paths lp ON ((lp.id = lpe.learning_path_id)))
     LEFT JOIN public.learning_path_courses lpc ON ((lpc.learning_path_id = lp.id)))
     LEFT JOIN public.course_enrollments ce ON (((ce.course_id = lpc.course_id) AND (ce.employee_id = lpe.employee_id))))
  GROUP BY lpe.id, lpe.employee_id, e.first_name, e.last_name, lpe.learning_path_id, lp.title, lp.target_role, lp.estimated_duration_hours, lpe.status, lpe.progress_percent, lpe.enrolled_at, lpe.completed_at;


--
-- Name: v_learning_skills_development; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_learning_skills_development AS
 SELECT e.id AS employee_id,
    e.tenant_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    ces.esco_skill_uri,
    ces.skill_name,
    ces.skill_type,
    max(ces.proficiency_level_gained) AS max_level_from_courses,
    count(DISTINCT ce.course_id) AS courses_completed_for_skill,
    array_agg(DISTINCT c.title) AS completed_courses
   FROM (((public.employees e
     JOIN public.course_enrollments ce ON (((ce.employee_id = e.id) AND ((ce.status)::text = 'completed'::text))))
     JOIN public.course_esco_skills ces ON ((ces.course_id = ce.course_id)))
     JOIN public.courses c ON ((c.id = ce.course_id)))
  GROUP BY e.id, e.tenant_id, e.first_name, e.last_name, ces.esco_skill_uri, ces.skill_name, ces.skill_type;


--
-- Name: v_manager_chain_issues; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_manager_chain_issues AS
 WITH RECURSIVE manager_chain AS (
         SELECT employees.id AS employee_id,
            employees.manager_id,
            employees.tenant_id,
            1 AS depth,
            ARRAY[employees.id] AS chain
           FROM public.employees
          WHERE (employees.manager_id IS NOT NULL)
        UNION ALL
         SELECT mc.employee_id,
            e_1.manager_id,
            mc.tenant_id,
            (mc.depth + 1),
            (mc.chain || e_1.id)
           FROM (manager_chain mc
             JOIN public.employees e_1 ON ((mc.manager_id = e_1.id)))
          WHERE ((mc.depth < 20) AND (e_1.id <> ALL (mc.chain)))
        )
 SELECT e.id AS employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e.job_title,
    e.tenant_id,
    t.name AS tenant_name,
        CASE
            WHEN ((e.manager_id IS NOT NULL) AND (NOT (EXISTS ( SELECT 1
               FROM public.employees
              WHERE (employees.id = e.manager_id))))) THEN 'invalid_manager'::text
            WHEN (e.manager_id = e.id) THEN 'self_reference'::text
            WHEN (EXISTS ( SELECT 1
               FROM manager_chain mc
              WHERE ((mc.employee_id = e.id) AND (e.id = ANY (mc.chain[2:]))))) THEN 'circular_reference'::text
            WHEN ((e.manager_id IS NULL) AND ((e.auth_role)::text <> ALL (ARRAY[('TENANT_ADMIN'::character varying)::text, ('SYSADMIN'::character varying)::text])) AND (e.is_active = true)) THEN 'no_manager'::text
            ELSE 'ok'::text
        END AS issue_type
   FROM (public.employees e
     JOIN public.tenants t ON ((e.tenant_id = t.id)))
  WHERE ((t.code)::text <> 'heuresys'::text);


--
-- Name: v_marketplace_plugins; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_marketplace_plugins AS
 SELECT p.id,
    p.name,
    p.slug,
    p.short_description,
    p.icon_url,
    pc.name AS category_name,
    pc.slug AS category_slug,
    pc.icon AS category_icon,
    p.publisher_name,
    p.status,
    p.visibility,
    p.pricing_model,
    p.price_cents,
    p.currency,
    p.tags,
    p.avg_rating,
    p.total_ratings,
    p.total_installations,
    p.featured,
    pv.version AS latest_version,
    pv.published_at AS latest_version_date,
    p.created_at,
    p.updated_at
   FROM ((public.plugins p
     LEFT JOIN public.plugin_categories pc ON ((pc.id = p.category_id)))
     LEFT JOIN public.plugin_versions pv ON (((pv.plugin_id = p.id) AND (pv.is_latest = true))))
  WHERE (((p.status)::text = 'published'::text) AND ((p.visibility)::text = 'public'::text));


--
-- Name: v_my_applications; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_my_applications AS
 SELECT a.id,
