--
-- Name: v_onboarding_dashboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_onboarding_dashboard AS
 SELECT oi.tenant_id,
    oi.id AS instance_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e.job_title,
    e.department,
    ot.name AS template_name,
    oi.status,
    oi.start_date,
    oi.target_completion_date,
    oi.progress_percent,
    ( SELECT count(*) AS count
           FROM public.onboarding_tasks t
          WHERE (t.instance_id = oi.id)) AS total_tasks,
    ( SELECT count(*) AS count
           FROM public.onboarding_tasks t
          WHERE ((t.instance_id = oi.id) AND ((t.status)::text = 'completed'::text))) AS completed_tasks,
    ( SELECT count(*) AS count
           FROM public.onboarding_tasks t
          WHERE ((t.instance_id = oi.id) AND ((t.status)::text = 'pending'::text) AND (t.due_date < CURRENT_DATE))) AS overdue_tasks,
    (((buddy.first_name)::text || ' '::text) || (buddy.last_name)::text) AS buddy_name
   FROM (((public.onboarding_instances oi
     JOIN public.employees e ON ((oi.employee_id = e.id)))
     LEFT JOIN public.onboarding_templates ot ON ((oi.template_id = ot.id)))
     LEFT JOIN public.employees buddy ON ((oi.assigned_buddy_id = buddy.id)));


--
-- Name: v_org_hierarchy; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_org_hierarchy AS
 WITH RECURSIVE org_tree AS (
         SELECT org_units.id,
            org_units.tenant_id,
            org_units.code,
            org_units.name,
            org_units.parent_id,
            org_units.org_level,
            org_units.org_type,
            org_units.legacy_department_id,
            org_units.default_location_id,
            org_units.manager_id,
            (org_units.name)::text AS path_name,
            (org_units.code)::text AS path_code,
            1 AS depth
           FROM public.org_units
          WHERE ((org_units.parent_id IS NULL) AND (org_units.is_active = true))
        UNION ALL
         SELECT ou.id,
            ou.tenant_id,
            ou.code,
            ou.name,
            ou.parent_id,
            ou.org_level,
            ou.org_type,
            ou.legacy_department_id,
            ou.default_location_id,
            ou.manager_id,
            ((ot_1.path_name || ' > '::text) || (ou.name)::text),
            ((ot_1.path_code || '.'::text) || (ou.code)::text),
            (ot_1.depth + 1)
           FROM (public.org_units ou
             JOIN org_tree ot_1 ON ((ou.parent_id = ot_1.id)))
          WHERE (ou.is_active = true)
        )
 SELECT ot.id,
    ot.tenant_id,
    ot.code,
    ot.name,
    ot.parent_id,
    ot.org_level,
    ot.org_type,
    ot.legacy_department_id,
    ot.default_location_id,
    ot.manager_id,
    ot.path_name,
    ot.path_code,
    ot.depth,
    d.name AS department_name,
    d.color AS department_color,
    l.name AS location_name,
    l.city AS location_city,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS manager_name
   FROM (((org_tree ot
     LEFT JOIN public.org_units d ON ((ot.legacy_department_id = d.id)))
     LEFT JOIN public.locations l ON ((ot.default_location_id = l.id)))
     LEFT JOIN public.employees e ON ((ot.manager_id = e.id)));


--
-- Name: v_org_structure; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_org_structure AS
 SELECT o.objid AS org_unit_id,
    o.stext AS org_name,
    o.short AS org_code,
    r.sobid AS parent_org_id,
    p.stext AS parent_name
   FROM ((public.hrp1000 o
     LEFT JOIN public.hrp1001 r ON ((((o.objid)::text = (r.objid)::text) AND ((r.rsign)::text = 'A'::text) AND ((r.relat)::text = '002'::text) AND (r.endda = '9999-12-31'::date))))
     LEFT JOIN public.hrp1000 p ON ((((r.sobid)::text = (p.objid)::text) AND ((p.otype)::text = 'O'::text) AND (p.endda = '9999-12-31'::date))))
  WHERE (((o.otype)::text = 'O'::text) AND (o.endda = '9999-12-31'::date));


--
-- Name: v_org_structure_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_org_structure_stats AS
 SELECT id AS tenant_id,
    name AS tenant_name,
    ( SELECT count(*) AS count
           FROM public.locations
          WHERE ((locations.tenant_id = t.id) AND (locations.is_active = true))) AS total_locations,
    ( SELECT count(*) AS count
           FROM public.org_units
          WHERE ((org_units.tenant_id = t.id) AND (org_units.is_active = true))) AS total_departments,
    ( SELECT count(*) AS count
           FROM public.org_units
          WHERE ((org_units.tenant_id = t.id) AND (org_units.is_active = true))) AS total_org_units,
    ( SELECT count(*) AS count
           FROM public.cost_centers
          WHERE ((cost_centers.tenant_id = t.id) AND (cost_centers.is_active = true))) AS total_cost_centers,
    ( SELECT count(*) AS count
           FROM public.employees
          WHERE ((employees.tenant_id = t.id) AND ((t.status)::text = 'active'::text))) AS total_employees
   FROM public.tenants t
  WHERE ((status)::text = 'active'::text);


--
-- Name: v_org_structure_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_org_structure_summary AS
 SELECT t.code AS tenant_code,
    t.name AS tenant_name,
    count(DISTINCT e.id) AS total_employees,
    count(DISTINCT
        CASE
            WHEN ((e.auth_role)::text = 'TENANT_ADMIN'::text) THEN e.id
            ELSE NULL::uuid
        END) AS tenant_admins,
    count(DISTINCT
        CASE
            WHEN ((e.auth_role)::text = 'IT_ADMIN'::text) THEN e.id
            ELSE NULL::uuid
        END) AS it_admins,
    count(DISTINCT
        CASE
            WHEN ((e.auth_role)::text = 'HR_DIRECTOR'::text) THEN e.id
            ELSE NULL::uuid
        END) AS hr_directors,
    count(DISTINCT
        CASE
            WHEN ((e.auth_role)::text = 'HR_MANAGER'::text) THEN e.id
            ELSE NULL::uuid
        END) AS hr_managers,
    count(DISTINCT
        CASE
            WHEN ((e.auth_role)::text = 'DEPT_HEAD'::text) THEN e.id
            ELSE NULL::uuid
        END) AS dept_heads,
    count(DISTINCT
        CASE
            WHEN ((e.auth_role)::text = 'LINE_MANAGER'::text) THEN e.id
            ELSE NULL::uuid
        END) AS line_managers,
    count(DISTINCT
        CASE
            WHEN ((e.auth_role)::text = 'EMPLOYEE'::text) THEN e.id
            ELSE NULL::uuid
        END) AS employees,
    count(DISTINCT
        CASE
            WHEN ((e.manager_id IS NULL) AND ((e.auth_role)::text <> ALL (ARRAY[('TENANT_ADMIN'::character varying)::text, ('SYSADMIN'::character varying)::text]))) THEN e.id
            ELSE NULL::uuid
        END) AS orphans,
    count(DISTINCT d.id) AS departments,
    count(DISTINCT
        CASE
            WHEN (d.manager_id IS NOT NULL) THEN d.id
            ELSE NULL::uuid
        END) AS depts_with_head
   FROM ((public.tenants t
     LEFT JOIN public.employees e ON (((e.tenant_id = t.id) AND (e.is_active = true))))
     LEFT JOIN public.org_units d ON ((d.tenant_id = t.id)))
  WHERE ((t.code)::text <> 'heuresys'::text)
  GROUP BY t.id, t.code, t.name
  ORDER BY t.name;


--
-- Name: v_org_unit_headcount; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_org_unit_headcount AS
 SELECT tou.id AS org_unit_id,
    tou.chart_id,
    toc.tenant_id,
    tou.code,
    tou.name_it,
    tou.cost_center,
    oa.code AS area_code,
    oa.name_it AS area_name,
    ol.level,
    ol.name_it AS level_name,
    tou.headcount_budget,
    count(DISTINCT e.id) AS headcount_actual,
    (tou.headcount_budget - count(DISTINCT e.id)) AS headcount_variance,
    count(DISTINCT tj.id) AS job_count,
    COALESCE(sum(tj.budgeted_positions), (0)::bigint) AS total_budgeted_positions,
    COALESCE(sum(tj.filled_positions), (0)::bigint) AS total_filled_positions
   FROM ((((((public.tenant_org_units tou
     JOIN public.tenant_org_charts toc ON ((tou.chart_id = toc.id)))
     LEFT JOIN public.org_areas oa ON (((tou.area_code)::text = (oa.code)::text)))
     LEFT JOIN public.org_levels ol ON ((tou.level = ol.level)))
     LEFT JOIN public.tenant_jobs tj ON (((tou.id = tj.tenant_org_unit_id) AND (tj.is_active = true))))
     LEFT JOIN public.employee_job_assignments eja ON (((tj.id = eja.tenant_job_id) AND (eja.is_current = true))))
     LEFT JOIN public.employees e ON (((eja.employee_id = e.id) AND (e.is_active = true))))
  WHERE (tou.is_active = true)
  GROUP BY tou.id, tou.chart_id, toc.tenant_id, tou.code, tou.name_it, tou.cost_center, oa.code, oa.name_it, ol.level, ol.name_it, tou.headcount_budget;


--
-- Name: v_overtime_analysis; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_overtime_analysis AS
 SELECT e.pernr,
    e.company_code,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS full_name,
    e."position" AS position_text,
    date_trunc('month'::text, (o.begda)::timestamp with time zone) AS month,
    count(*) AS ot_occurrences,
    sum(o.stdaz) AS total_ot_hours,
    avg(o.stdaz) AS avg_ot_per_occurrence,
    sum(
        CASE
            WHEN o.approved THEN o.stdaz
            ELSE (0)::numeric
        END) AS approved_hours,
    sum(
        CASE
            WHEN (NOT o.approved) THEN o.stdaz
            ELSE (0)::numeric
        END) AS pending_hours
   FROM (public.v_employee_master e
     LEFT JOIN public.pa2005 o ON (((e.pernr)::text = (o.pernr)::text)))
  WHERE (o.begda >= date_trunc('year'::text, (CURRENT_DATE)::timestamp with time zone))
  GROUP BY e.pernr, e.company_code, e.first_name, e.last_name, e."position", (date_trunc('month'::text, (o.begda)::timestamp with time zone))
  ORDER BY (sum(o.stdaz)) DESC NULLS LAST;


--
-- Name: v_payroll_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_payroll_summary AS
 SELECT e.pernr,
    e.company_code,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS full_name,
    p.abkrs AS payroll_area,
    p.paession AS year,
    p.pession_no AS period,
    p.gross_pay,
    p.net_pay,
    (p.gross_pay - p.net_pay) AS total_deductions,
    p.status,
    p.rgdate AS process_date
   FROM (public.v_employee_master e
     JOIN public.pcl2 p ON (((e.pernr)::text = (p.pernr)::text)))
  WHERE ((p.relession)::text = 'RG'::text)
  ORDER BY p.paession DESC, p.pession_no DESC, e.pernr;


--
-- Name: v_people_inspector; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_people_inspector AS
 SELECT e.id,
    e.tenant_id,
    e.pernr,
    e.first_name,
    e.last_name,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS full_name,
    e.email,
    e.job_title,
    e.department,
    e.location,
    e.location_id,
    l.name AS location_name,
    l.city AS location_city,
    l.country AS location_country,
    e.manager_id,
    (((mgr.first_name)::text || ' '::text) || (mgr.last_name)::text) AS manager_name,
    e.hire_date,
    e.termination_date,
    e.employment_status,
    e.is_active,
    t.name AS tenant_name
   FROM (((public.employees e
     LEFT JOIN public.locations l ON ((l.id = e.location_id)))
     LEFT JOIN public.employees mgr ON ((mgr.id = e.manager_id)))
     LEFT JOIN public.tenants t ON ((t.id = e.tenant_id)));


--
-- Name: v_performance_skill_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_performance_skill_summary AS
 SELECT psl.tenant_id,
    psl.employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e.job_title,
    d.name AS department_name,
    count(*) AS total_competencies,
    count(*) FILTER (WHERE ((psl.rating_level)::text = 'low'::text)) AS low_rated,
    count(*) FILTER (WHERE ((psl.rating_level)::text = 'medium'::text)) AS medium_rated,
    count(*) FILTER (WHERE ((psl.rating_level)::text = 'high'::text)) AS high_rated,
    count(*) FILTER (WHERE (psl.linked_skill_id IS NOT NULL)) AS skills_linked,
    count(*) FILTER (WHERE (psl.linked_gap_analysis_id IS NOT NULL)) AS gap_analyses,
    count(*) FILTER (WHERE (psl.is_addressed = true)) AS addressed,
    max(psl.created_at) AS last_updated
   FROM ((public.performance_skill_links psl
     JOIN public.employees e ON ((psl.employee_id = e.id)))
     LEFT JOIN public.org_units d ON ((e.org_unit_id = d.id)))
  GROUP BY psl.tenant_id, psl.employee_id, e.first_name, e.last_name, e.job_title, d.name;


--
-- Name: v_platform_tables; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_platform_tables AS
 SELECT table_name,
    schema_name,
    description,
    example_use
   FROM public.table_usage_rules
  WHERE (((usage_allowed)::text = ANY (ARRAY[('PLATFORM'::character varying)::text, ('BOTH'::character varying)::text])) AND ((table_category)::text = ANY (ARRAY[('HEURESYS_CORE'::character varying)::text, ('HEURESYS_MODULE'::character varying)::text])))
  ORDER BY table_category, table_name;


--
-- Name: VIEW v_platform_tables; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_platform_tables IS 'Tables that should be used for platform features';


--
-- Name: v_recruiting_pipeline; Type: VIEW; Schema: public; Owner: -
