--
-- Name: v_risk_distribution; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_risk_distribution AS
 SELECT pp.tenant_id,
    d.id AS department_id,
    d.name AS department_name,
    count(*) AS total_employees,
    count(*) FILTER (WHERE ((pp.risk_level)::text = 'low'::text)) AS low_risk,
    count(*) FILTER (WHERE ((pp.risk_level)::text = 'medium'::text)) AS medium_risk,
    count(*) FILTER (WHERE ((pp.risk_level)::text = 'high'::text)) AS high_risk,
    count(*) FILTER (WHERE ((pp.risk_level)::text = 'critical'::text)) AS critical_risk,
    count(*) FILTER (WHERE pp.is_high_potential) AS high_potentials,
    round(avg(pp.risk_score), 1) AS avg_risk_score,
    round(avg(pp.predicted_rating), 2) AS avg_predicted_rating
   FROM ((public.performance_predictions pp
     JOIN public.employees e ON ((pp.employee_id = e.id)))
     LEFT JOIN public.org_units d ON ((e.org_unit_id = d.id)))
  WHERE (pp.is_current = true)
  GROUP BY pp.tenant_id, d.id, d.name;


--
-- Name: v_sap_esco_skills; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sap_esco_skills AS
 SELECT q.qualifi AS sap_qualification_id,
    q.qualifitext AS sap_name,
    q.esco_skill_uri,
    q.esco_concept_type,
    cat.qual_type AS skill_type,
    cat.qual_group AS skill_group,
    count(DISTINCT e.pernr) AS employees_with_skill
   FROM ((public.t771q q
     LEFT JOIN public.hrp1036 cat ON ((((q.qualifi)::text = (cat.objid)::text) AND (cat.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0024 e ON ((((q.qualifi)::text = (e.quali)::text) AND (e.endda = '9999-12-31'::date))))
  WHERE (q.endda = '9999-12-31'::date)
  GROUP BY q.qualifi, q.qualifitext, q.esco_skill_uri, q.esco_concept_type, cat.qual_type, cat.qual_group
  ORDER BY (count(DISTINCT e.pernr)) DESC NULLS LAST;


--
-- Name: VIEW v_sap_esco_skills; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_sap_esco_skills IS 'SAP Qualification to ESCO skill mapping';


--
-- Name: v_sap_only_tables; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sap_only_tables AS
 SELECT table_name,
    description,
    forbidden_use
   FROM public.table_usage_rules
  WHERE ((table_category)::text = 'SAP_ONLY'::text)
  ORDER BY table_name;


--
-- Name: VIEW v_sap_only_tables; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_sap_only_tables IS 'Tables that should NEVER be used for platform features - SAP sync only';


--
-- Name: v_skill_classification_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_skill_classification_stats AS
 SELECT count(*) AS total_skills,
    count(sc.id) AS classified_skills,
    (count(*) - count(sc.id)) AS unclassified_skills,
    round(((100.0 * (count(sc.id))::numeric) / (NULLIF(count(*), 0))::numeric), 2) AS classification_percentage,
    count(sc.id) FILTER (WHERE ((sc.primary_category)::text = 'hard'::text)) AS hard_skills,
    count(sc.id) FILTER (WHERE ((sc.primary_category)::text = 'soft'::text)) AS soft_skills,
    count(sc.id) FILTER (WHERE ((sc.primary_category)::text = 'hybrid'::text)) AS hybrid_skills,
    count(sc.id) FILTER (WHERE (sc.cognitive_level = 1)) AS cognitive_level_1,
    count(sc.id) FILTER (WHERE (sc.cognitive_level = 2)) AS cognitive_level_2,
    count(sc.id) FILTER (WHERE (sc.cognitive_level = 3)) AS cognitive_level_3,
    count(sc.id) FILTER (WHERE (sc.cognitive_level = 4)) AS cognitive_level_4,
    count(sc.id) FILTER (WHERE ((sc.social_dimension)::text = 'intrapersonal'::text)) AS intrapersonal,
    count(sc.id) FILTER (WHERE ((sc.social_dimension)::text = 'interpersonal'::text)) AS interpersonal,
    count(sc.id) FILTER (WHERE ((sc.social_dimension)::text = 'task_oriented'::text)) AS task_oriented,
    count(sc.id) FILTER (WHERE ((sc.transferability)::text = 'specialized'::text)) AS specialized,
    count(sc.id) FILTER (WHERE ((sc.transferability)::text = 'adjacent'::text)) AS adjacent,
    count(sc.id) FILTER (WHERE ((sc.transferability)::text = 'transferable'::text)) AS transferable,
    count(sc.id) FILTER (WHERE (sc.needs_review = true)) AS needs_review
   FROM (public.esco_skills es
     LEFT JOIN public.skill_classifications sc ON ((es.id = sc.esco_skill_id)));


--
-- Name: v_skill_clusters_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_skill_clusters_summary AS
 SELECT skc.id,
    skc.code,
    skc.name_en,
    skc.name_it,
    skc.cluster_level,
    skc.parent_cluster_id,
    parent.code AS parent_code,
    parent.name_en AS parent_name,
    count(sc.id) AS skill_count,
    count(sc.id) FILTER (WHERE ((sc.primary_category)::text = 'hard'::text)) AS hard_skill_count,
    count(sc.id) FILTER (WHERE ((sc.primary_category)::text = 'soft'::text)) AS soft_skill_count,
    count(sc.id) FILTER (WHERE ((sc.primary_category)::text = 'hybrid'::text)) AS hybrid_skill_count
   FROM ((public.skill_clusters skc
     LEFT JOIN public.skill_clusters parent ON ((skc.parent_cluster_id = parent.id)))
     LEFT JOIN public.skill_classifications sc ON ((skc.id = sc.skill_cluster_id)))
  GROUP BY skc.id, skc.code, skc.name_en, skc.name_it, skc.cluster_level, skc.parent_cluster_id, parent.code, parent.name_en;


--
-- Name: v_skill_gaps; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_skill_gaps AS
 SELECT esa.id AS assessment_id,
    esa.employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e.tenant_id,
    esa.skill_name,
    esa.esco_skill_uri,
    esa.required_level,
    esa.assessed_level,
    esa.gap,
        CASE
            WHEN ((esa.gap IS NULL) OR (esa.gap <= 0)) THEN 'met'::text
            WHEN (esa.gap = 1) THEN 'minor_gap'::text
            WHEN (esa.gap = 2) THEN 'moderate_gap'::text
            ELSE 'critical_gap'::text
        END AS gap_severity,
    esa.assessment_date,
    esa.assessment_method,
    tjs.importance AS skill_importance,
    tjs.skill_category
   FROM ((public.employee_skill_assessments esa
     JOIN public.employees e ON ((esa.employee_id = e.id)))
     LEFT JOIN public.tenant_job_skills tjs ON ((esa.tenant_job_skill_id = tjs.id)))
  WHERE (e.is_active = true);


--
-- Name: v_skills_classified; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_skills_classified AS
 SELECT es.id,
    es.uri,
    es.preferred_label,
    es.description,
    es.skill_type AS esco_skill_type,
    es.reuse_level,
    es.is_digital,
    es.is_green,
    sc.primary_category,
    sc.primary_category_confidence,
    sc.cognitive_level,
    sc.cognitive_level_label,
    sc.social_dimension,
    sc.transferability,
    sc.transferability_score,
    sc.classification_source,
    sc.needs_review,
    skc.id AS cluster_id,
    skc.code AS cluster_code,
    skc.name_en AS cluster_name,
    skc.cluster_level
   FROM ((public.esco_skills es
     LEFT JOIN public.skill_classifications sc ON ((es.id = sc.esco_skill_id)))
     LEFT JOIN public.skill_clusters skc ON ((sc.skill_cluster_id = skc.id)));


--
-- Name: v_skills_gap; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_skills_gap AS
 SELECT e.pernr,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e."position",
    req.quali AS required_skill_id,
    cat.qual_name AS skill_name,
    req.proficiency_required,
    COALESCE(emp.proficiency, '00'::character varying) AS current_proficiency,
        CASE
            WHEN (emp.proficiency IS NULL) THEN 'Missing'::text
            WHEN ((emp.proficiency)::text < (req.proficiency_required)::text) THEN 'Gap'::text
            ELSE 'Met'::text
        END AS gap_status,
    req.esco_skill_uri
   FROM ((((public.v_employee_master e
     JOIN public.pa0001 p1 ON ((((e.pernr)::text = (p1.pernr)::text) AND (p1.endda = '9999-12-31'::date))))
     JOIN public.hrp1035 req ON ((((p1.plans)::text = (req.objid)::text) AND ((req.otype)::text = 'S'::text) AND (req.endda = '9999-12-31'::date))))
     LEFT JOIN public.hrp1036 cat ON ((((req.quali)::text = (cat.objid)::text) AND (cat.endda = '9999-12-31'::date))))
     LEFT JOIN public.pa0024 emp ON ((((e.pernr)::text = (emp.pernr)::text) AND ((req.quali)::text = (emp.quali)::text) AND (emp.endda = '9999-12-31'::date))))
  ORDER BY e.pernr,
        CASE
            WHEN (emp.proficiency IS NULL) THEN 'Missing'::text
            WHEN ((emp.proficiency)::text < (req.proficiency_required)::text) THEN 'Gap'::text
            ELSE 'Met'::text
        END DESC, req.quali;


--
-- Name: VIEW v_skills_gap; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_skills_gap IS 'Skills gap analysis - required vs actual';


--
-- Name: v_skills_matrix; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_skills_matrix AS
 SELECT t.id AS tenant_id,
    t.code AS tenant_code,
    skill.skill,
    count(*) AS employee_count,
    round(avg(e.performance_rating), 2) AS avg_performance
   FROM ((public.employees e
     JOIN public.tenants t ON ((t.id = e.tenant_id)))
     CROSS JOIN LATERAL unnest(COALESCE(e.skills, ARRAY[]::text[])) skill(skill))
  WHERE (e.is_active = true)
  GROUP BY t.id, t.code, skill.skill
  ORDER BY t.id, (count(*)) DESC;


--
-- Name: v_succession_pipeline; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_succession_pipeline AS
 SELECT cr.tenant_id,
    cr.id AS role_id,
    cr.role_name,
    cr.department,
    cr.criticality_level,
    cr.succession_status,
    (((e_inc.first_name)::text || ' '::text) || (e_inc.last_name)::text) AS incumbent_name,
    count(sc.id) AS total_successors,
    sum(
        CASE
            WHEN ((sc.readiness_level)::text = 'ready_now'::text) THEN 1
            ELSE 0
        END) AS ready_now_count,
    sum(
        CASE
            WHEN ((sc.readiness_level)::text = 'ready_1_year'::text) THEN 1
            ELSE 0
        END) AS ready_1_year_count,
        CASE
            WHEN (count(sc.id) = 0) THEN 'Critical'::text
            WHEN (sum(
            CASE
                WHEN ((sc.readiness_level)::text = 'ready_now'::text) THEN 1
                ELSE 0
            END) = 0) THEN 'High'::text
            WHEN (count(sc.id) < 2) THEN 'Medium'::text
            ELSE 'Low'::text
        END AS succession_risk
   FROM ((public.critical_roles cr
     LEFT JOIN public.employees e_inc ON ((e_inc.id = cr.current_incumbent_id)))
     LEFT JOIN public.succession_candidates sc ON ((sc.critical_role_id = cr.id)))
  GROUP BY cr.tenant_id, cr.id, cr.role_name, cr.department, cr.criticality_level, cr.succession_status, e_inc.first_name, e_inc.last_name;


--
-- Name: v_succession_readiness; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_succession_readiness AS
 SELECT s.position_id,
    pos.stext AS position_name,
    s.successor_pernr,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS successor_name,
    s.readiness,
    c.config_value AS readiness_text,
    s.readiness_pct,
    s.ranking,
    s.potential_rating,
    s.performance_rating,
    s.gap_analysis,
    s.status,
    s.reviewed_date
   FROM (((public.hrpdev1 s
     LEFT JOIN public.hrp1000 pos ON ((((s.position_id)::text = (pos.objid)::text) AND ((pos.otype)::text = 'S'::text) AND (pos.endda = '9999-12-31'::date))))
     LEFT JOIN public.v_employee_master e ON (((s.successor_pernr)::text = (e.pernr)::text)))
     LEFT JOIN public.sap_config c ON (((c.config_key)::text = ('SUCC_READY_'::text || (s.readiness)::text))))
  WHERE (s.endda = '9999-12-31'::date)
  ORDER BY s.position_id, s.ranking;


--
-- Name: VIEW v_succession_readiness; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_succession_readiness IS 'Succession planning with readiness levels';


--
-- Name: v_sync_dashboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sync_dashboard AS
 SELECT t.name AS tenant_name,
    t.code AS tenant_code,
    count(DISTINCT e.id) AS total_employees,
    count(DISTINCT e.id) FILTER (WHERE (e.pernr IS NOT NULL)) AS synced_to_sap,
    count(DISTINCT e.id) FILTER (WHERE (e.pernr IS NULL)) AS not_synced,
    ( SELECT count(*) AS count
           FROM public.sync_queue sq
          WHERE ((sq.tenant_id = t.id) AND ((sq.status)::text = 'pending'::text))) AS pending_syncs,
    ( SELECT max(sl.completed_at) AS max
           FROM public.sync_log sl
          WHERE ((sl.tenant_id = t.id) AND ((sl.status)::text = 'completed'::text))) AS last_sync
   FROM (public.tenants t
     LEFT JOIN public.employees e ON ((e.tenant_id = t.id)))
  GROUP BY t.id, t.name, t.code
  ORDER BY t.name;


--
-- Name: v_sync_status; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sync_status AS
 SELECT m.bukrs,
    t.butxt AS company_name,
    count(m.pernr) AS synced_users,
    max(m.last_sync_at) AS last_sync,
    count(
        CASE
            WHEN ((m.sync_status)::text = 'synced'::text) THEN 1
            ELSE NULL::integer
        END) AS ok_count,
    count(
        CASE
            WHEN ((m.sync_status)::text = 'error'::text) THEN 1
            ELSE NULL::integer
        END) AS error_count
   FROM (public.user_pernr_mapping m
     JOIN public.t500c t ON (((m.bukrs)::text = (t.bukrs)::text)))
  GROUP BY m.bukrs, t.butxt
  ORDER BY (count(m.pernr)) DESC;


--
-- Name: v_sync_status_by_tenant; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sync_status_by_tenant AS
 SELECT t.tenant_name,
    t.sap_bukrs,
    count(m.user_uuid) AS synced_users,
    max(m.last_sync_at) AS last_sync
   FROM (public.tenant_sap_mapping t
     LEFT JOIN public.user_pernr_mapping m ON (((t.sap_bukrs)::text = (m.bukrs)::text)))
  GROUP BY t.tenant_name, t.sap_bukrs
  ORDER BY (count(m.user_uuid)) DESC;


--
-- Name: v_team_goals; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_team_goals AS
 SELECT g.id,
    g.tenant_id,
    g.employee_id,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS employee_name,
    e.manager_id,
    (((m.first_name)::text || ' '::text) || (m.last_name)::text) AS manager_name,
    d.id AS department_id,
    d.name AS department_name,
    g.title,
    g.description,
    g.goal_type,
    g.status,
    g.progress_percent,
    g.weight,
    g.priority,
    g.start_date,
    g.due_date,
    g.completed_at,
    g.parent_goal_id,
    pg.title AS parent_goal_title,
    g.is_smart_validated,
    g.smart_score,
        CASE
            WHEN ((g.status)::text = 'completed'::text) THEN 'completed'::text
            WHEN ((g.due_date < CURRENT_DATE) AND ((g.status)::text <> 'completed'::text)) THEN 'overdue'::text
            WHEN (g.due_date < (CURRENT_DATE + '7 days'::interval)) THEN 'due_soon'::text
            ELSE 'on_track'::text
        END AS timeline_status,
    ( SELECT count(*) AS count
           FROM public.goal_check_ins gc
          WHERE (gc.goal_id = g.id)) AS check_in_count,
    ( SELECT max(gc.check_in_date) AS max
           FROM public.goal_check_ins gc
          WHERE (gc.goal_id = g.id)) AS last_check_in
   FROM ((((public.goals g
     JOIN public.employees e ON ((g.employee_id = e.id)))
     LEFT JOIN public.employees m ON ((e.manager_id = m.id)))
     LEFT JOIN public.org_units d ON ((e.org_unit_id = d.id)))
     LEFT JOIN public.goals pg ON ((g.parent_goal_id = pg.id)));


--
-- Name: v_tenant_absence_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tenant_absence_stats AS
 SELECT ue.bukrs AS sap_company_code,
    p21.awart AS absence_type,
    count(*) AS record_count,
    count(DISTINCT ue.pernr) AS employees_affected,
    round(sum(p21.abwtg), 1) AS total_days,
    round(avg(p21.abwtg), 1) AS avg_days_per_record
   FROM (public.v_unique_sap_employee ue
     JOIN public.pa2001 p21 ON (((p21.pernr)::text = (ue.pernr)::text)))
  GROUP BY ue.bukrs, p21.awart;


--
-- Name: v_tenant_demographics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tenant_demographics AS
 SELECT t.sap_company_code,
    t.id AS tenant_id,
    t.name AS tenant_name,
    e.department,
    e.gender,
    count(*) AS employee_count,
    round(avg(EXTRACT(year FROM age((e.birth_date)::timestamp with time zone))), 1) AS avg_age,
    round(avg(EXTRACT(year FROM age((e.hire_date)::timestamp with time zone))), 1) AS avg_tenure
   FROM (public.tenants t
     JOIN public.employees e ON ((e.tenant_id = t.id)))
  WHERE (e.is_active = true)
  GROUP BY t.sap_company_code, t.id, t.name, e.department, e.gender;


--
-- Name: v_tenant_employee_profile; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tenant_employee_profile AS
 SELECT t.sap_company_code,
    t.id AS tenant_id,
    e.id AS employee_id,
    e.pernr,
    e.first_name,
    e.last_name,
    e.email,
    e.job_title,
    e.department,
    e.location,
    e.hire_date,
    e.birth_date,
    e.gender,
    e.salary,
    e.performance_rating,
    e.potential,
    e.skills,
    e.is_active
   FROM (public.tenants t
     JOIN public.employees e ON ((e.tenant_id = t.id)));


--
-- Name: v_tenant_inspector; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tenant_inspector AS
 SELECT id,
    code,
    name,
    industry_type,
    region,
    employee_count,
    status,
    ( SELECT count(*) AS count
           FROM public.locations l
          WHERE (l.tenant_id = t.id)) AS location_count,
    ( SELECT count(*) AS count
           FROM public.org_units d
          WHERE (d.tenant_id = t.id)) AS department_count,
    ( SELECT count(*) AS count
           FROM public.employees e
          WHERE ((e.tenant_id = t.id) AND (e.is_active = true))) AS active_employee_count,
    created_at,
    updated_at
   FROM public.tenants t;


--
-- Name: v_tenant_job_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tenant_job_stats AS
 SELECT t.id AS tenant_id,
    t.name AS tenant_name,
    count(DISTINCT tj.id) AS total_jobs,
    count(DISTINCT
        CASE
            WHEN tj.is_management THEN tj.id
            ELSE NULL::uuid
        END) AS management_jobs,
    sum(tj.budgeted_positions) AS total_budgeted,
    sum(tj.filled_positions) AS total_filled,
    (sum(tj.budgeted_positions) - sum(tj.filled_positions)) AS total_open,
    count(DISTINCT tou.id) AS org_units_with_jobs,
    count(DISTINCT tjs.esco_skill_uri) AS unique_skills_required
   FROM (((public.tenants t
     LEFT JOIN public.tenant_jobs tj ON (((t.id = tj.tenant_id) AND (tj.is_active = true))))
     LEFT JOIN public.tenant_org_units tou ON ((tj.tenant_org_unit_id = tou.id)))
     LEFT JOIN public.tenant_job_skills tjs ON ((tj.id = tjs.tenant_job_id)))
  WHERE ((t.status)::text = 'active'::text)
  GROUP BY t.id, t.name;


--
-- Name: VIEW v_tenant_job_stats; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_tenant_job_stats IS 'Job statistics summary by tenant';


--
-- Name: v_tenant_plugin_installations; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tenant_plugin_installations AS
 SELECT pi.id AS installation_id,
    pi.tenant_id,
    pi.status AS installation_status,
    pi.auto_update,
    pi.installed_at,
    p.id AS plugin_id,
    p.name AS plugin_name,
    p.slug AS plugin_slug,
    p.short_description,
    p.icon_url,
    pc.name AS category_name,
    pc.slug AS category_slug,
    pv.version AS installed_version,
    pv.published_at AS version_date,
    latest_pv.version AS latest_available_version,
        CASE
            WHEN (pv.id <> latest_pv.id) THEN true
            ELSE false
        END AS update_available
   FROM ((((public.plugin_installations pi
     JOIN public.plugins p ON ((p.id = pi.plugin_id)))
     LEFT JOIN public.plugin_categories pc ON ((pc.id = p.category_id)))
     JOIN public.plugin_versions pv ON ((pv.id = pi.plugin_version_id)))
     LEFT JOIN public.plugin_versions latest_pv ON (((latest_pv.plugin_id = p.id) AND (latest_pv.is_latest = true))));


--
-- Name: v_tenant_salary_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tenant_salary_stats AS
 SELECT t.sap_company_code,
    t.id AS tenant_id,
    e.department,
    e.job_title,
    count(*) AS employee_count,
    round(avg(e.salary), 0) AS avg_salary,
    round(min(e.salary), 0) AS min_salary,
    round(max(e.salary), 0) AS max_salary,
    round(sum(e.salary), 0) AS total_payroll
   FROM (public.tenants t
     JOIN public.employees e ON ((e.tenant_id = t.id)))
  WHERE ((e.is_active = true) AND (e.salary IS NOT NULL))
  GROUP BY t.sap_company_code, t.id, e.department, e.job_title;


--
-- Name: v_time_balance; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_time_balance AS
 SELECT e.pernr,
    e.company_code,
    e.first_name,
    e.last_name,
    (((e.first_name)::text || ' '::text) || (e.last_name)::text) AS full_name,
    q.ktart AS quota_type,
    c.config_value AS quota_description,
    q.anzhl AS entitlement,
    q.kession AS used,
    q.remainder AS balance,
    q.unit,
    q.begda AS period_start,
    q.endda AS period_end
   FROM ((public.v_employee_master e
     JOIN public.pa2006 q ON ((((e.pernr)::text = (q.pernr)::text) AND ((CURRENT_DATE >= q.begda) AND (CURRENT_DATE <= q.endda)))))
     LEFT JOIN public.sap_config c ON (((c.config_key)::text = ('QUOTA_TYPE_'::text || (q.ktart)::text))))
  ORDER BY e.pernr, q.ktart;


--
-- Name: v_turnover_analysis; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_turnover_analysis AS
 SELECT t.id AS tenant_id,
    t.code AS tenant_code,
    t.name AS tenant_name,
    count(
        CASE
            WHEN (e.is_active = true) THEN 1
            ELSE NULL::integer
        END) AS active_count,
    count(
        CASE
            WHEN (e.is_active = false) THEN 1
            ELSE NULL::integer
        END) AS inactive_count,
    round(((100.0 * (count(
        CASE
            WHEN (e.is_active = false) THEN 1
            ELSE NULL::integer
        END))::numeric) / (NULLIF(count(*), 0))::numeric), 2) AS turnover_rate,
    round(avg(
        CASE
            WHEN (e.is_active = false) THEN EXTRACT(year FROM age((e.hire_date)::timestamp with time zone))
            ELSE NULL::numeric
        END), 1) AS avg_tenure_leavers,
    e.department,
    count(*) AS dept_total
   FROM (public.employees e
     JOIN public.tenants t ON ((t.id = e.tenant_id)))
  GROUP BY t.id, t.code, t.name, e.department;


--
-- Name: v_unified_employee; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_unified_employee AS
 SELECT e.id AS employee_id,
    e.pernr AS sap_pernr,
    COALESCE(ext.tenant_id, e.tenant_id) AS tenant_id,
    t.code AS tenant_code,
    t.name AS tenant_name,
    t.sap_company_code,
    COALESCE(p2.vorna, e.first_name) AS first_name,
    COALESCE(p2.nachn, e.last_name) AS last_name,
    e.email,
    p2.gbdat AS birth_date,
        CASE p2.gesch
            WHEN '1'::text THEN 'Male'::text
            WHEN '2'::text THEN 'Female'::text
            ELSE 'Other'::text
        END AS gender,
    p2.natio AS nationality,
    e.job_title,
    e.department,
    e.location,
    p1.orgeh AS sap_org_unit,
    p1.plans AS sap_position,
    p1.kostl AS sap_cost_center,
    p8.ansal AS annual_salary,
    p8.waession AS currency,
    p105_phone.usrid_long AS phone,
    COALESCE(ext.is_active, e.is_active) AS is_active,
    e.hire_date,
    COALESCE(ext.skills, e.skills) AS skills,
    COALESCE(ext.performance_rating, e.performance_rating) AS performance_rating,
    COALESCE(ext.potential, e.potential) AS potential,
    COALESCE(( SELECT m.id
           FROM public.employees m
          WHERE ((m.pernr)::text = (ext.manager_pernr)::text)), e.manager_id) AS manager_id,
    u.id AS user_id,
    u.username,
    u.role AS user_role,
    e.created_at,
    COALESCE(ext.updated_at, e.updated_at) AS updated_at
   FROM (((((((public.employees e
     JOIN public.tenants t ON ((e.tenant_id = t.id)))
     LEFT JOIN public.ext_pa0002 ext ON (((e.pernr)::text = (ext.pernr)::text)))
     LEFT JOIN public.pa0001 p1 ON ((((e.pernr)::text = (p1.pernr)::text) AND (p1.endda >= CURRENT_DATE))))
     LEFT JOIN public.pa0002 p2 ON ((((e.pernr)::text = (p2.pernr)::text) AND (p2.endda >= CURRENT_DATE))))
     LEFT JOIN public.pa0008 p8 ON ((((e.pernr)::text = (p8.pernr)::text) AND (p8.endda >= CURRENT_DATE))))
     LEFT JOIN public.pa0105 p105_phone ON ((((e.pernr)::text = (p105_phone.pernr)::text) AND ((p105_phone.subty)::text = '0020'::text) AND (p105_phone.endda >= CURRENT_DATE))))
     LEFT JOIN public.users u ON ((u.employee_id = e.id)));


--
-- Name: v_unified_skills; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_unified_skills AS
 SELECT 'esco'::text AS source,
    (esco_skills.id)::text AS id,
    esco_skills.uri AS external_id,
    esco_skills.preferred_label_en AS name,
    COALESCE(esco_skills.description_en, ''::text) AS description,
    COALESCE(esco_skills.skill_type, 'skill'::character varying) AS category
   FROM public.esco_skills
UNION ALL
 SELECT 'onet'::text AS source,
    (onet_skills.id)::text AS id,
    onet_skills.element_id AS external_id,
    onet_skills.element_name AS name,
    COALESCE(onet_skills.description, ''::text) AS description,
    COALESCE(onet_skills.category, 'skill'::character varying) AS category
   FROM public.onet_skills;


--
-- Name: v_upcoming_interviews; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_upcoming_interviews AS
SELECT
    NULL::uuid AS id,
    NULL::uuid AS tenant_id,
    NULL::uuid AS candidate_id,
    NULL::uuid AS job_posting_id,
    NULL::character varying(50) AS interview_type,
    NULL::character varying(255) AS title,
    NULL::timestamp without time zone AS scheduled_at,
    NULL::integer AS duration_minutes,
    NULL::character varying(30) AS location_type,
    NULL::character varying(500) AS meeting_link,
    NULL::character varying(30) AS status,
    NULL::timestamp without time zone AS created_at,
    NULL::character varying[] AS interviewers;


--
-- Name: v_whistleblowing_dashboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_whistleblowing_dashboard AS
 SELECT tenant_id,
    count(*) AS total_reports,
    count(*) FILTER (WHERE ((status)::text = 'submitted'::text)) AS new_reports,
    count(*) FILTER (WHERE ((status)::text = ANY (ARRAY[('under_review'::character varying)::text, ('investigating'::character varying)::text]))) AS active_investigations,
    count(*) FILTER (WHERE ((status)::text = 'resolved'::text)) AS resolved_reports,
    count(*) FILTER (WHERE ((status)::text = 'escalated'::text)) AS escalated_reports,
    count(*) FILTER (WHERE ((severity)::text = 'critical'::text)) AS critical_reports,
    count(*) FILTER (WHERE ((acknowledgement_sent = false) AND (created_at < (now() - '7 days'::interval)))) AS overdue_acknowledgements,
    (avg((EXTRACT(epoch FROM (COALESCE((updated_at)::timestamp with time zone, now()) - (created_at)::timestamp with time zone)) / (86400)::numeric)))::integer AS avg_resolution_days
   FROM public.whistleblowing_reports wr
  GROUP BY tenant_id;


--
-- Name: v_workforce_overview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_workforce_overview AS
 SELECT t.id AS tenant_id,
    t.name AS tenant_name,
    count(DISTINCT e.id) AS total_employees,
    count(DISTINCT e.id) FILTER (WHERE (e.is_active = true)) AS active_employees,
    count(DISTINCT e.location_id) AS location_count,
    count(DISTINCT e.department) AS department_count,
    avg(EXTRACT(year FROM age((CURRENT_DATE)::timestamp without time zone, (e.hire_date)::timestamp without time zone))) AS avg_tenure_years
   FROM (public.tenants t
     LEFT JOIN public.employees e ON ((e.tenant_id = t.id)))
  GROUP BY t.id, t.name;


