);

ALTER TABLE ONLY public.wellbeing_goals FORCE ROW LEVEL SECURITY;


--
-- Name: wellbeing_program_enrollments; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.wellbeing_program_enrollments (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    tenant_id uuid NOT NULL,
    employee_id uuid NOT NULL,
    resource_id uuid NOT NULL,
    enrolled_at timestamp with time zone DEFAULT now(),
