--
-- Name: process_kpis process_kpis_tenant_isolation; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY process_kpis_tenant_isolation ON public.process_kpis USING ((EXISTS ( SELECT 1
   FROM (public.business_processes bp
     JOIN public.tenants t ON ((t.industry_profile_id = bp.profile_id)))
  WHERE ((bp.id = process_kpis.process_id) AND (t.id = public.current_tenant_id()))))) WITH CHECK ((EXISTS ( SELECT 1
   FROM (public.business_processes bp
     JOIN public.tenants t ON ((t.industry_profile_id = bp.profile_id)))
  WHERE ((bp.id = process_kpis.process_id) AND (t.id = public.current_tenant_id())))));


