-- Name: process_skill_requirements process_skill_requirements_tenant_isolation; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY process_skill_requirements_tenant_isolation ON public.process_skill_requirements USING ((EXISTS ( SELECT 1
   FROM (public.business_processes bp
     JOIN public.tenants t ON ((t.industry_profile_id = bp.profile_id)))
  WHERE ((bp.id = process_skill_requirements.process_id) AND (t.id = public.current_tenant_id()))))) WITH CHECK ((EXISTS ( SELECT 1
   FROM (public.business_processes bp
     JOIN public.tenants t ON ((t.industry_profile_id = bp.profile_id)))
  WHERE ((bp.id = process_skill_requirements.process_id) AND (t.id = public.current_tenant_id())))));


